SET FOREIGN_KEY_CHECKS = 0;
SET NAMES utf8mb4;
-- chat_session DDL
DROP TABLE IF EXISTS `chat_session`;
CREATE TABLE `chat_session` (`id` BIGINT NOT NULL AUTO_INCREMENT Comment "会话主键",
`session_code` CHAR(26) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "会话编码（ULID）",
`session_type` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "会话类型：SKILL_CHAT/KNOWLEDGE_QA",
`scope_id` BIGINT NULL Comment "会话作用域ID（知识问答场景可存 kb_id）",
`name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "会话名称",
`status` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'normal' Comment "会话状态",
`last_message` VARCHAR(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "最近一条消息摘要",
`create_user_id` BIGINT NOT NULL Comment "创建用户ID",
`created_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP Comment "创建时间",
`updated_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) Comment "更新时间",
INDEX `idx_chat_session_scope`(`scope_id` ASC) USING BTREE,
INDEX `idx_chat_session_user_type_updated`(`create_user_id` ASC,`session_type` ASC,`updated_at` ASC,`id` ASC) USING BTREE,
UNIQUE INDEX `uk_chat_session_code`(`session_code` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 10 ROW_FORMAT = Dynamic COMMENT = "用户会话主表";
-- document_chunk DDL
DROP TABLE IF EXISTS `document_chunk`;
CREATE TABLE `document_chunk` (`chunk_id` BIGINT NOT NULL AUTO_INCREMENT Comment "分块唯一ID，自增主键",
`doc_id` BIGINT NOT NULL Comment "关联文档ID，逻辑关联knowledge_document.doc_id",
`chunk_content` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "分块文本内容",
`chunk_order` INT NOT NULL Comment "分块顺序，从1开始，用于排序",
`index_id` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "外部索引文档ID，用于关联Elasticsearch中的chunk文档",
`char_count` BIGINT NULL Comment "分块字符总数，基于chunk_content计算",
`keywords` JSON NULL Comment "关键字，JSON数组格式，如[\"tech\", \"AI\"]",
`headings` JSON NULL Comment "分块所属标题路径，JSON数组格式，如[\"第一章\",\"1.1概述\"]",
`chunk_type` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "分块类型，如TEXT、TABLE、WINDOW",
`metadata_values` JSON NULL Comment "分块元数据，JSON格式，存放条号、章号等结构化信息",
`embedding` JSON NULL Comment "可选的向量缓存字段；当前语义检索以Elasticsearch向量索引为主",
`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP Comment "创建时间，自动记录",
PRIMARY KEY (`chunk_id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 27541 ROW_FORMAT = Dynamic COMMENT = "存储文档分块内容及向量索引";
-- document_metadata DDL
DROP TABLE IF EXISTS `document_metadata`;
CREATE TABLE `document_metadata` (`metadata_id` BIGINT NOT NULL AUTO_INCREMENT Comment "元数据配置唯一ID，自增主键",
`kb_id` BIGINT NOT NULL Comment "关联知识库ID，逻辑关联knowledge_base.kb_id",
`meta_key` VARCHAR(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "元数据键，如author、tag",
`meta_type` ENUM("STRING","NUMBER","DATE","BOOLEAN") CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "元数据类型：字符串、数字、日期、布尔",
`is_required` TINYINT NULL DEFAULT 0 Comment "是否必填，1=必填，0=非必填",
`description` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "元数据描述，说明用途，可为空",
PRIMARY KEY (`metadata_id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 202 ROW_FORMAT = Dynamic COMMENT = "存储元数据配置定义";
-- imessages DDL
DROP TABLE IF EXISTS `imessages`;
CREATE TABLE `imessages` (`id` BIGINT NOT NULL AUTO_INCREMENT Comment "消息主键",
`session_id` BIGINT NOT NULL Comment "关联会话ID",
`query` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "提问",
`question_type` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "问题类型",
`params_json` JSON NULL Comment "参数",
`answer` LONGTEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "回答",
`ordinal` INT NULL Comment "序号",
`document_list` JSON NULL Comment "文档信息",
`file_list` JSON NULL Comment "文件信息",
`consumes_time` VARCHAR(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "问答耗时",
`error` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "错误信息",
`status` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'pending' Comment "状态",
`final_query` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "最终提问",
`create_user_id` BIGINT NULL Comment "创建人ID",
`updated_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) Comment "更新时间",
`created_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP Comment "创建时间",
INDEX `idx_imessages_session_created`(`session_id` ASC,`created_at` ASC,`id` ASC) USING BTREE,
INDEX `idx_imessages_user_created`(`create_user_id` ASC,`created_at` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 41 ROW_FORMAT = Dynamic COMMENT = "会话消息表";
-- knowledge_base DDL
DROP TABLE IF EXISTS `knowledge_base`;
CREATE TABLE `knowledge_base` (`kb_id` BIGINT NOT NULL AUTO_INCREMENT Comment "知识库唯一ID，自增主键",
`kb_name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "知识库名称，唯一",
`description` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "知识库描述，可为空",
`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP Comment "创建时间，自动记录",
`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP Comment "更新时间，自动更新",
PRIMARY KEY (`kb_id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 52 ROW_FORMAT = Dynamic COMMENT = "存储知识库基本信息";
DROP TABLE IF EXISTS `knowledge_base_publish_binding`;
CREATE TABLE `knowledge_base_publish_binding` (`id` BIGINT NOT NULL AUTO_INCREMENT Comment "主键",
`kb_id` BIGINT NOT NULL Comment "知识库 ID",
`publish_status` VARCHAR(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'DRAFT' Comment "发布状态",
`published_tool_codes` VARCHAR(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "已发布工具编码列表",
`published_version` INT NOT NULL DEFAULT 0 Comment "发布版本",
`published_at` DATETIME NULL Comment "发布时间",
`last_compiled_at` DATETIME NULL Comment "最近编译时间",
`last_publish_message` VARCHAR(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "最近发布摘要",
`created_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP Comment "创建时间",
`updated_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) Comment "更新时间",
UNIQUE INDEX `uk_knowledge_base_publish_kb`(`kb_id` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic COMMENT = "知识库发布态";
-- knowledge_document DDL
DROP TABLE IF EXISTS `knowledge_document`;
CREATE TABLE `knowledge_document` (`doc_id` BIGINT NOT NULL AUTO_INCREMENT Comment "文档或文件夹唯一ID，自增主键",
`kb_id` BIGINT NOT NULL Comment "关联知识库ID，逻辑关联knowledge_base.kb_id",
`parent_id` BIGINT NULL Comment "父节点ID，NULL表示根目录，逻辑自关联doc_id",
`is_folder` TINYINT NULL DEFAULT 0 Comment "是否为文件夹，1=文件夹，0=文档",
`name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "文档或文件夹名称",
`file_type` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "文档类型，如pdf、docx，仅对文档(is_folder=0)有效",
`file_size` BIGINT NULL Comment "文档大小（字节），仅对文档(is_folder=0)有效",
`total_tokens` BIGINT NULL Comment "文档总token数，仅对文档(is_folder=0)有效",
`metadata_values` JSON NULL Comment "元数据值，JSON格式，如{\"author\": \"John\", \"tag\": \"tech\"}",
`path` VARCHAR(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "层级路径，如/parent_folder/sub_folder，仅用于查询和展示",
`upload_time` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP Comment "上传或创建时间，自动记录",
`status` TINYINT NULL DEFAULT 0 Comment "文档处理状态，仅对文档(is_folder=0)有效：0待处理、1处理中、2完成、3失败",
`error_message` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "异步处理失败时的错误摘要",
`file_id` VARCHAR(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "MinIO对象ID，仅对文档(is_folder=0)有效",
`chunk_strategy` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "切片策略，如AUTO、DELIMITER_WINDOW、HEADING_DIRECTORY",
`chunk_config` JSON NULL Comment "切片参数配置，JSON格式",
`document_json` JSON NULL Comment "文档解析JSON",
PRIMARY KEY (`doc_id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 513 ROW_FORMAT = Dynamic COMMENT = "存储文档和文件夹信息，支持目录层级和元数据";
-- skill_catalog DDL
DROP TABLE IF EXISTS `skill_catalog`;
CREATE TABLE `skill_catalog` (`id` BIGINT NOT NULL AUTO_INCREMENT Comment "技能目录主键",
`runtime_skill_name` VARCHAR(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "运行时技能唯一名称",
`display_name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "展示名称",
`description` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "展示描述",
`category` VARCHAR(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "技能分类",
`source` VARCHAR(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL Comment "技能来源",
`visible` TINYINT NULL DEFAULT 1 Comment "是否在前台技能市场可见，1=可见，0=隐藏",
`sort_order` INT NULL DEFAULT 0 Comment "排序值，越小越靠前",
`created_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP Comment "创建时间",
`updated_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) Comment "更新时间",
INDEX `idx_skill_catalog_visible_sort`(`visible` ASC,`sort_order` ASC,`id` ASC) USING BTREE,
UNIQUE INDEX `uk_skill_catalog_runtime_skill`(`runtime_skill_name` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 17 ROW_FORMAT = Dynamic COMMENT = "技能业务目录表";
-- skill_tool_binding DDL
DROP TABLE IF EXISTS `skill_tool_binding`;
CREATE TABLE `skill_tool_binding` (`id` BIGINT NOT NULL AUTO_INCREMENT Comment "绑定主键",
`skill_id` BIGINT NOT NULL Comment "技能目录ID",
`tool_name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL Comment "追加绑定的公共工具名称",
`binding_type` VARCHAR(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'MANUAL' Comment "绑定类型：NATIVE/MANUAL",
`created_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP Comment "创建时间",
INDEX `idx_skill_tool_binding_skill`(`skill_id` ASC) USING BTREE,
UNIQUE INDEX `uk_skill_tool_binding_unique`(`skill_id` ASC,`tool_name` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci AUTO_INCREMENT = 37 ROW_FORMAT = Dynamic COMMENT = "技能追加公共工具绑定表";
-- sys_job DDL
DROP TABLE IF EXISTS `sys_job`;
CREATE TABLE `sys_job` (`job_id` BIGINT NOT NULL AUTO_INCREMENT Comment "任务ID",
`job_name` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' Comment "任务名称",
`job_group` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'DEFAULT' Comment "任务组名",
`invoke_target` VARCHAR(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL Comment "调用目标字符串",
`cron_expression` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' Comment "cron执行表达式",
`misfire_policy` VARCHAR(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '3' Comment "计划执行错误策略（1立即执行 2执行一次 3放弃执行）",
`concurrent` CHAR(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '1' Comment "是否并发执行（0允许 1禁止）",
`status` CHAR(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '0' Comment "状态（0正常 1暂停）",
`create_by` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' Comment "创建者",
`create_time` DATETIME NULL Comment "创建时间",
`update_by` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' Comment "更新者",
`update_time` DATETIME NULL Comment "更新时间",
`remark` VARCHAR(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' Comment "备注信息",
PRIMARY KEY (`job_id`,
`job_name`,
`job_group`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci AUTO_INCREMENT = 100 ROW_FORMAT = Dynamic COMMENT = "定时任务调度表";
-- sys_job_log DDL
DROP TABLE IF EXISTS `sys_job_log`;
CREATE TABLE `sys_job_log` (`job_log_id` BIGINT NOT NULL AUTO_INCREMENT Comment "任务日志ID",
`job_name` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL Comment "任务名称",
`job_group` VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL Comment "任务组名",
`invoke_target` VARCHAR(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL Comment "调用目标字符串",
`job_message` VARCHAR(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL Comment "日志信息",
`status` CHAR(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '0' Comment "执行状态（0正常 1失败）",
`exception_info` VARCHAR(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' Comment "异常信息",
`start_time` DATETIME NULL Comment "开始时间",
`stop_time` DATETIME NULL Comment "结束时间",
`create_time` DATETIME NULL Comment "创建时间",
PRIMARY KEY (`job_log_id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci AUTO_INCREMENT = 3 ROW_FORMAT = Dynamic COMMENT = "定时任务调度日志表";
-- t_user DDL
DROP TABLE IF EXISTS `t_user`;
CREATE TABLE `t_user` (`id` BIGINT NOT NULL AUTO_INCREMENT,
`name` VARCHAR(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
