-- chat_session DML
INSERT INTO `chat_session` (`id`,`session_code`,`session_type`,`scope_id`,`name`,`status`,`last_message`,`create_user_id`,`created_at`,`updated_at`) VALUES (2,'01KKB8WGPZG4B9T2PCA8WV6XFP','KNOWLEDGE_QA',50,'你好','normal','你好！\n\n根据当前提供的知识库内容，未包含与“你好”这一问候语直接相关的信息或上下文。如果你有关于知识库功能、RAG系统、前端交互、ES向量存储等方面的问题，我可以基于已有证据为你解答。\n\n例如，当前知识库中提到了以下几点可能相关的内容：\n',1,'2026-03-10 15:02:53','2026-03-10 15:02:59'),(3,'01KKB9XFKZKPWG711V6AVRF2DJ','KNOWLEDGE_QA',50,'你是谁？','normal','我是知识库问答助手，根据提供的知识库内容回答问题。当前知识库中没有关于“我是谁”的直接说明，但根据系统设定和上下文可知：我是一个基于给定证据进行回答的问答助手，仅依据用户提供的知识库内容作答，不编造信息。\n\n在当前提供的证据中，并无明确描述',1,'2026-03-10 15:20:53','2026-03-10 15:20:59'),(4,'01KKBC6933NMPHB9G8KYKVK2YA','KNOWLEDGE_QA',51,'你好','normal','以下回答基于通用模型能力，非知识库依据。\n\n西红柿炒鸡蛋的做法如下：\n\n1. **准备食材**：鸡蛋2-3个，西红柿1-2个，盐、糖、油适量。\n2. **打蛋**：将鸡蛋打入碗中，加少许盐，搅打均匀。\n3. **切西红柿**：西红柿洗净切块',1,'2026-03-10 16:00:39','2026-03-10 16:01:39'),(5,'01KKDEVZWDZBM3WW9D3FYM2F3P','KNOWLEDGE_QA',51,'击穿电压测量的试验目的是什么？','normal','根据提供的证据，绝缘试验顺序如下：\n\n在进行绝缘试验前，应至少完成以下项目：\n- 绝缘油试验  \n- 绕组电阻测量  \n- 电压比测量和联结组标号检定  \n- 绕组对地及绕组间直流绝缘电阻测量  \n- 铁心和夹件绝缘检查  \n\n对于设备最高',1,'2026-03-11 11:25:56','2026-03-13 20:32:35'),(6,'01KKE0ABASF3X3PMWBKF6DDNN1','SKILL_CHAT',2,'新会话','normal','帮我审查这个合同',1,'2026-03-11 16:30:52','2026-03-12 09:52:25'),(8,'01KKFZS6CQ0FX9DJGRJKN8HFQA','SKILL_CHAT',2,'你好','normal','你好',1,'2026-03-12 10:59:59','2026-03-12 11:00:03'),(9,'01KKG00AVSZ1GSSP3G23YEVHJ8','SKILL_CHAT',2,'你好','normal','抱歉，当前Python运行环境正在安装中，暂时无法直接执行合同审核脚本。\n\n不过，我可以为您提供合同审核的指导。首先，让我了解一下您上传的合同类型和基本信息。\n\n# 软件/服务采购合同审核意见书\n\n## 一、合同基本信息\n- **合同类型*',1,'2026-03-12 11:03:53','2026-03-13 15:33:50');
-- document_chunk DML
INSERT INTO `document_chunk` (`chunk_id`,`doc_id`,`chunk_content`,`chunk_order`,`index_id`,`char_count`,`keywords`,`headings`,`chunk_type`,`embedding`,`created_at`) VALUES (27160,508,'## 前    言\n\n本标准按照GB/T 1.1—2009给出的规则起草。\n本标准代替JB/T 501—2006《电力变压器试验导则》， 与JB/T501—2006相比主要技术变化如下： ——对规范性引用文件进行了调整；\n——对标准的整体结构进行了调整，将油浸式电力变压器与干式电力变压器的相关内容分别作为独 立的章节；\n——取消了主要符号的章节，改为在相应公式下面进行说明；\n——增加了油浸式电力变压器的绝缘试验顺序； ——对试验项目的排列顺序进行了调整；\n——对绝缘试验中的试验项目进行了修改，增加了带有局部放电测量的感应电压试验（IVPD)、线\n端交流耐压试验（LTAC)，取消了 2006 版的短时感应耐压试验（ACSD）、长时感应耐压试验 （ACLD）；\n——新增了液浸式变压器真空变形试验、液浸式变压器压力变形试验，取消了 2006 版的油箱机械 强度试验；\n——将绝缘特性测量调整为绕组对地及绕组间直流绝缘电阻测量、铁心和夹件绝缘检查、绕组对地 和绕组间电容测量和绝缘系统电容的介质损耗因数（tanδ) 测量。\n——增加了压力密封试验、内装电流互感器变比和极性试验、短时过负载能力试验、强迫油循环变 压器冷却油流系统的负压测试、暂态电压传输特性测定、频率响应测量、外部涂层检查、运输 质量测定、油箱开裂试验、运输颠簸试验、所有分接位置的负载损耗测量、长时间空载试验、 油流静电试验、转动油泵时的局部放电测量、环境试验、气候试验和燃烧性能试验。\n本标准由中国机械工业联合会提出。\n本标准由全国变压器标准化技术委员会（SAC/TC 44）归口。\n本标准起草单位：沈阳变压器研究院股份有限公司、国家变压器质量监督检验中心、中国电力科学 研究院有限公司、特变电工沈阳变压器集团有限公司、西安西电变压器有限责任公司、特变电工衡阳变 压器有限公司、山东输变电设备有限公司、顺特电气设备有限公司、特变电工股份有限公司新疆变压器 厂、明珠电气股份有限公司、江苏华鹏变压器有限公司、江苏华晨变压器股份有限公司、海鸿电气有限 公司、浙江江山变压器股份有限公司、鲁特电工股份有限公司。\n本标准主要起草人： 吕祥鹏、李世成、刘锡忠、张显忠、任晓红、刘丰、吕建玉、邹宇星、刘永、 肖明、虞金华、蔡定国、周国伟、徐健、梁庆宁、姜振军、张令健。\n本标准所代替标准的历次版本发布情况为：\n——JB/T 501—1964 、JB/T 501—1991 、JB/T 501—2006。\nJB/T 501—2021\n电力变压器试验导则',1,'be08d434-fc96-47e4-8975-85f03e06f1b8',1048,NULL,'["前    言"]','TEXT',NULL,'2026-03-11 11:17:42'),(27161,508,'## 1  范围\n\n本标准规定了油浸式电力变压器和干式电力变压器的例行试验、型式试验和特殊试验的程序及方 法。\n本标准适用于油浸式电力变压器和干式电力变压器的试验。 特种变压器的试验可参照本标准。',2,'38954feb-0417-4a5c-9c28-9602f573d51f',93,NULL,'["1  范围"]','TEXT',NULL,'2026-03-11 11:17:42'),(27162,508,'## 2  规范性引用文件\n\n下列文件对于本文件的应用是必不可少的。凡是注日期的引用文件，仅注日期的版本适用于本文件。 凡是不注日期的引用文件，其最新版本（包括所有的修改单）适用于本文件。\nGB/T 507  绝缘油  击穿电压测定法\nGB/T 1094.1—2013  电力变压器  第 1 部分：总则\nGB/T 1094.2—2013  电力变压器  第 2 部分：液浸式变压器的温升\nGB/T 1094.3—2017  电力变压器  第 3 部分：绝缘水平、绝缘试验和外绝缘空气间隙',3,'64e68c51-496c-4176-9ff4-a1b230f4e27d',231,NULL,'["2  规范性引用文件"]','TEXT',NULL,'2026-03-11 11:17:42'),(27163,508,'## 2  规范性引用文件\n<table><tr><td>GB/T</td><td>1094.4</td><td>电力变压器</td><td>第4部分：电力变压器和电抗器的雷电冲击和操作冲击试验导则</td></tr><tr><td>GB/T</td><td>1094.5</td><td>电力变压器</td><td>第 5部分：承受短路的能力</td></tr><tr><td>GB/T</td><td>1094.10</td><td>电力变压器</td><td>第10部分：声级测定</td></tr><tr><td>GB/T</td><td>1094.11</td><td>电力变压器</td><td>第11部分：干式变压器</td></tr><tr><td>GB/T</td><td>1094.18</td><td>电力变压器</td><td>第18部分：频率响应测量</td></tr></table>',4,'1541c0f6-1620-4412-8d9e-ca297978f026',221,NULL,'["2  规范性引用文件"]','TABLE',NULL,'2026-03-11 11:17:42'),(27164,508,'## 2  规范性引用文件\n\nGB/T 3785.1—2010  电声学  声级计  第1部分：规范\nGB/T 3785.2—2010  电声学  声级计  第2部分：型式评价试验\nGB/T 4983.4  家具表面漆膜理化性能试验  第4部分：附着力交叉切割测定法 GB/T 4956  磁性基体上非磁性覆盖层   覆盖层厚度测量   磁性法\nGB/T 5654  液体绝缘材料  相对电容率、介质损耗因数和直流电阻率的测量\nGB/T 6451—2015  油浸式电力变压器技术参数和要求 GB/T 7354  局部放电测量\nGB/T 7597  电力用油（变压器油、汽轮机油）取样方法）\nGB/T 7600  运行中变压器油和汽轮机油水分含量测定法(库仑法)  GB/T 7601  运行中变压器油、汽轮机油水分测定法 (气相色谱法)\nGB/T 10228  干式电力变压器技术参数和要求 GB/T 13499  电力变压器应用导则\nGB/T 17623  绝缘油中溶解气体组分含量的气相色谱测定法 GB/T 22072  干式非晶合金铁心配电变压器技术参数和要求 DL/T 423  绝缘油中含气量测定方法  真空压差法\nDL/T 703  绝缘油中含气量的气相色谱测定法\nDL/T 911  电力变压器绕组变形的频率响应分析法\nJB/T 501—2021\nJB/T 10088  6kV～1000kV级电力变压器声级',5,'db99a11a-7ce0-4fa0-bac9-ddf1c315ac89',577,NULL,'["2  规范性引用文件"]','TEXT',NULL,'2026-03-11 11:17:42'),(27165,508,'## 3  油浸式电力变压器试验\n### 3.1  试验项目\n\n例行试验、型式试验及特殊试验的项目按照GB/T 1094.1和GB/T 6451的规定，详见表1。',6,'3e6b5eb3-0e85-4eb5-ba1f-b846159a9961',71,NULL,'["3  油浸式电力变压器试验", "3.1  试验项目"]','TEXT',NULL,'2026-03-11 11:17:42'),(27166,508,'## 3  油浸式电力变压器试验\n### 3.1  试验项目\n表 1  油浸式电力变压器试验项目\n<table><tr><td>序号</td><td>试验</td><td>条款</td></tr><tr><td colspan=\'3\'>例行试验</td></tr><tr><td>1</td><td>绝缘油试验</td><td>3.4</td></tr><tr><td>2</td><td>绕组电阻测量</td><td>3.5</td></tr><tr><td>3</td><td>电压比测量和联结组标号检定</td><td>3.6</td></tr><tr><td>4</td><td>短路阻抗和负载损耗测量</td><td>3.7</td></tr><tr><td>5</td><td>空载损耗和空载电流测量</td><td>3.8</td></tr><tr><td>6</td><td>绕组对地及绕组间直流绝缘电阻测量</td><td>3.9</td></tr><tr><td>7</td><td>绝缘例行试验</td><td>3.10</td></tr><tr><td>8</td><td>有载分接开关试验（适用于有载调压变压器）</td><td>3.11</td></tr><tr><td>9</td><td>压力密封试验</td><td>3.12</td></tr><tr><td>10</td><td>内装电流互感器变比和极性试验</td><td>3.13</td></tr><tr><td>11</td><td>铁心和夹件绝缘检查</td><td>3.14</td></tr><tr><td>12</td><td>绕组对地和绕组间电容测量（适用于容量8000kVA及以上的35kV变压器以及电压等级66kV及以上 的所有变压器）</td><td>3.15</td></tr><tr><td>13</td><td>绝缘系统电容的介质损耗因数（ tan δ) 测量（适用于容量8000 kVA 及以上的35 kV 变压器以及电 压等级66kV及以上的所有变压器）</td><td>3.16</td></tr><tr><td>14</td><td>在90%和110%额定电压下的空载损耗和空载电流测量（适用 于U m ＞72.5kV的所有变压器）</td><td>3.29</td></tr></table>',7,'1483d5e1-6bc8-41f4-b88d-43bad28fd482',551,NULL,'["3  油浸式电力变压器试验", "3.1  试验项目"]','TABLE',NULL,'2026-03-11 11:17:42'),(27167,508,'## 3  油浸式电力变压器试验\n### 3.1  试验项目\n表 1  油浸式电力变压器试验项目\n<table><tr><td>序号</td><td>试验</td><td>条款</td></tr><tr><td colspan=\'3\'>例行试验</td></tr><tr><td>15</td><td>除分接开关油室外的每个独立油室的绝缘油中溶解气体测量（适用于U m ＞72.5kV的所有变压器）</td><td>3.4</td></tr><tr><td colspan=\'3\'>型式试验</td></tr><tr><td>16</td><td>绝缘型式试验</td><td>3.10</td></tr><tr><td>17</td><td>温升试验</td><td>3.17</td></tr><tr><td>18</td><td>声级测定</td><td>3.18</td></tr><tr><td>19</td><td>风扇和油泵电机吸取功率测量</td><td>3.19</td></tr><tr><td>20</td><td>短时过负载能力试验（适用于配电变压器）</td><td>3.27</td></tr><tr><td>21</td><td>强迫油循环变压器冷却油流系统的负压测试</td><td>3.28</td></tr><tr><td>22</td><td>在90%和110%额定电压下的空载损耗和空载电流测量</td><td>3.29</td></tr><tr><td colspan=\'3\'>特殊试验</td></tr><tr><td>23</td><td>绝缘特殊试验</td><td>3.10</td></tr><tr><td>24</td><td>绕组对地和绕组间电容测量</td><td>3.16</td></tr><tr><td>25</td><td>绝缘系统电容的介质损耗因数（ tan δ)测量</td><td>3.16</td></tr><tr><td>26</td><td>暂态电压传输特性测定</td><td>3.20</td></tr></table>',8,'927f51d1-a020-4b48-b076-195c6e45e48a',443,NULL,'["3  油浸式电力变压器试验", "3.1  试验项目"]','TABLE',NULL,'2026-03-11 11:17:42'),(27168,508,'## 3  油浸式电力变压器试验\n### 3.1  试验项目\n\nJB/T 501—2021',9,'9f26875e-13c5-478c-ac50-cd126d2befee',35,NULL,'["3  油浸式电力变压器试验", "3.1  试验项目"]','TEXT',NULL,'2026-03-11 11:17:42'),(27169,508,'## 3  油浸式电力变压器试验\n### 3.1  试验项目\n表 1（续）\n<table><tr><td>序号</td><td>试验</td><td>条款</td></tr><tr><td>27</td><td>三相变压器零序阻抗测量</td><td>3.21</td></tr><tr><td>28</td><td>短路承受能力试验</td><td>3.22</td></tr><tr><td>29</td><td>液浸式变压器真空变形试验</td><td>3.23</td></tr><tr><td>30</td><td>液浸式变压器压力变形试验</td><td>3.23</td></tr><tr><td>31</td><td>外部涂层检查</td><td>3.24</td></tr><tr><td>32</td><td>运输质量测定</td><td>3.25</td></tr><tr><td>33</td><td>频率响应测量</td><td>3.26</td></tr><tr><td>34</td><td>油箱开裂试验（适用于10kV电压等级的配电变压 器）</td><td>3.30</td></tr><tr><td>35</td><td>运输颠簸试验（适用于35kV及以下电压等级的配电变压器）</td><td>3.31</td></tr><tr><td>36</td><td>所有分接位置的负载损耗测量(适用于容量20 000 kVA 及以上具有独立调压绕组的35 kV 、66 kV 电 压等级的变压器和电压等级110kV及以上具有独 立调压绕组的变压器)</td><td>3.32</td></tr><tr><td>37</td><td>长时间空载试验（适用于220kV及以上电压等级的变压器）</td><td>3.33</td></tr><tr><td>38</td><td>油流静电试验（适用于220kV及以上电压等级的强迫油循环变压器）</td><td>3.34</td></tr><tr><td>39</td><td>转动油泵时的局部放电测量（适用于220kV及以上电压等级的强迫油循环变压器）</td><td>3.35</td></tr></table>',10,'fbeda5bf-d749-4d3e-a167-f292923d86fe',542,NULL,'["3  油浸式电力变压器试验", "3.1  试验项目"]','TABLE',NULL,'2026-03-11 11:17:42'),(27170,508,'## 3  油浸式电力变压器试验\n### 3.2  绝缘试验顺序\n\n绝缘试验前至少应完成以下试验项目：试验前的绝缘油试验、绕组电阻测量、电压比测量和联结组 标号检定、绕组对地及绕组间直流绝缘电阻测量及铁心和夹件绝缘检查。对于设备最高电压Um>72.5kV 的变压器还应完成绕组对地和绕组间电容测量、绝缘系统电容的介质损耗因数（tanδ) 测量及额定电 压下的空载损耗和空载电流测量。\n绝缘试验顺序一般应按照GB/T 1094.3的规定进行。试验顺序如下： ——雷电冲击试验（LI、LIC、LIN、LIMT，如果规定)；\n——操作冲击试验（SI，如果规定）； ——外施耐压试验（AV）；\n——线端交流耐压试验（LTAC，如果规定）； ——感应耐压试验（IVW，如果规定）；\n——带有局部放电测量的感应电压试验（IVPD，如果规定）。\n经制造方与用户协商同意也可以进行少量的更改，如操作冲击在雷电冲击试验前进行，在绝缘试验 前增加带有局部放电测量的感应电压试验（IVPD）。\n如果要求了带有局部放电测量的感应电压试验（IVPD），那么带有局部放电测量的感应电压试验 （IVPD）应作为最后的绝缘试验。',11,'3b47b27b-c7cb-4d74-95eb-a0400633575f',488,NULL,'["3  油浸式电力变压器试验", "3.2  绝缘试验顺序"]','TEXT',NULL,'2026-03-11 11:17:42'),(27171,508,'## 3  油浸式电力变压器试验\n### 3.3  一般试验条件\n\n本条是对油浸式电力变压器一般试验条件的要求，如试验项目中无具体的规定，则应按本条执行。 一般试验条件包括：\n——除绝缘试验及温升试验外，试验应在 5℃~40℃的环境温度下进行； ——温升试验宜介于 5℃与变压器设计所依据的最高环境温度之间；\n——绝缘试验时，绝缘系统的温度不低于 5℃, 但允许高于 40℃;\n——有可能影响变压器性能的外部组件和装置，均应安装在规定的位置上；\nJB/T 501—2021\n——试验应在主分接上进行，试验条款另有规定或供需双方另有协议时除外； ——参考温度应按照以下条款选取：\n●     对于绕组额定平均温升不大于 65K(OF 或 ON 冷却方式）或 70K(OD 冷却方式)的液浸式变压 器：\n◆    参考温度为 75℃;\n◆    按照用户要求，参考温度等于额定绕组平均温升加 20℃或额定绕组平均温升加外部 冷却介质年平均温度两者之中的较高者。\n●     对有其它额定绕组平均温升的液浸式变压器，参考温度等于额定绕组平均温升加 20℃或 额定绕组平均温升加外部冷却介质年平均温度两者之中的较高者。\n——测量及试验时的工频电源频率或变压器额定频率的偏差应在 1%内；\n——试验电源电压波形中的谐波含量不应超过 5%。除空载损耗和空载电流测量按照规定进行波形 校正外，其它损耗测量不应考虑谐波含量而将损耗向下校正；\n——当采用三相电源时，电源电压应对称，试验时，施加到每个相绕组上的最高电压与最低电压之 差不应超过 3%。\n制造方在额定频率下试验或测量能力方面的任何方面的不足，均应在投标书中说明，并协商适当的 转换系数。',12,'54530694-bbaa-4aa5-a40b-74bb10f7c4eb',692,NULL,'["3  油浸式电力变压器试验", "3.3  一般试验条件"]','TEXT',NULL,'2026-03-11 11:17:42'),(27172,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.1  概述\n\n绝缘油的例行试验包括击穿电压测量、介质损耗因数测量、含水量测定、含气量测定及溶解气体气 相色谱分析。',13,'2d9afb80-1477-4998-a983-13d4ade44172',82,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27173,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.1  试验目的\n\n绝缘油的击穿电压是衡量绝缘油被水和悬浮杂质污染程度的重要指标。油的击穿电压越低，变压器 的整体绝缘性能越差，直接影响变压器的安全运行。因此应严格测试，以便将绝缘油击穿电压控制在不 同范围内。',14,'0494d5da-3274-46f3-adbc-847dacaccd1c',131,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.1  试验目的"]','TEXT',NULL,'2026-03-11 11:17:43'),(27174,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.2  试验方法\n\n绝缘油击穿电压测量的试验方法按GB/T 507的规定进行。',15,'315582ec-1f16-4475-9e0c-1fec434a1ad4',65,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.2  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27175,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.3  试验仪器\n\n本导则推荐使用全自动击穿电压测试仪—油试验器，整套仪器应满足以下条件：\n——油杯：由透明的绝缘材料制成，且对绝缘油和所有清洗剂具有化学惰性。有效容积在 350mL~ 600mL 之间，并带有封盖；\n——电极：由黄铜或不锈钢磨制而成，形状可以是球形或球盖形（蘑菇形），几何尺寸应满足 GB/T\n507 的规定， 电极距离为 2.5 mm ±0.05 mm；\n——调压装置：采用自动升压系统，可采用自耦式调压器或电阻分压器；\n——变压器：采用低压侧电源为 50Hz 的升压变压器；高压侧输出电压波形应为近似正弦波，峰值\n因数应在  2 （1±7%）范围内，升压速度控制在（2kV±0.2 kV）/s，并且当电压大于 15kV\n时，变压器的最小短路电流应大于 20mA；\nJB/T 501—2021\n——保护装置：包括和试验电极串联的限流电阻和接在初级线路上的断路器，断路器应在试样击穿 后 0.01s 内受击穿电流作用而动作， 以保护试验设备；\n——其它部分：仪器应有自动搅拌器和安全防尘罩，最好具有自动显示和记录击穿电压值、计算平 均值和规定值偏差、打印试验结果的功能。',16,'b8ef51dc-2104-48ad-9346-1830f1e8ed38',519,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.3  试验仪器"]','TEXT',NULL,'2026-03-11 11:17:43'),(27176,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.4  试品取样\n\n试品按 GB/T 7597 规定的方法取样。',17,'842461be-273a-42a3-99dd-9ae58e7723b5',58,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.4  试品取样"]','TEXT',NULL,'2026-03-11 11:17:43'),(27177,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.5  试验过程\n\n试验过程如下：\na)  熟悉仪器使用说明书，按要求连接试验仪器并调试正常，且经计量部门检定合格；\nb)  首次使用时应拆卸电极，用清洗剂彻底清洗电极和油杯，再用蒸馏水清洗几遍，用电吹风彻底 吹干；安装电极时要用标准规调整电极间隙到 2.5mm；正常使用情况下不必每次拆洗电极；\nc)  将平衡到室温的试油(与环境温度之差小于 5℃)倒入油杯，并洗刷两次，最后倒入油杯的试油 油面至少超过电极 40mm；\nd)  盖上安全防尘罩，选定标准值，按“开始”键，仪器自动开始测试；每测试完一次，仪器打印 一次击穿电压值；在测试完六次后，仪器打印出六次击穿电压的平均值和标准值偏差。',18,'8135bcd8-8bf1-4d6c-849d-7660362c57bb',318,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.5  试验过程"]','TEXT',NULL,'2026-03-11 11:17:43'),(27178,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.6  注意事项\n\n注意事项如下：\n——检测交流电源，在保证仪器要求的情况下才能接通电源； ——仪器外壳和接地点应可靠接地；\n——油杯和电极清洗后，严禁用手或不洁净物接触；\n——油杯较长时间未用或测得击穿电压值过低（低于 10kV）时，应按 3.4.2.5 的 b）项要求重新 清洗；\n——环境相对湿度不得大于 75%；\n——确认仪器检定有效期，标准规也应定期检定，其厚度应保证在（2.5±0.05）mm 之内；\n——样品和规定值偏差大于 10%时应引起注意，最好重复取样做平行试验，以便证实是否是由操作 不当所引起。',19,'08c5a0d7-6520-453c-b4d8-2c50b7d5efd1',285,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.6  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27179,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.7  结果的判定\n\n在技术协议中没有规定时，试验结果的判定按表2。',20,'1fffdac4-77e8-49fa-8022-c5985c11a521',60,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.7  结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27180,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.7  结果的判定\n表 2  绝缘油耐压规定值\n<table><tr><td>电压等级kV</td><td>击穿电压kV</td></tr><tr><td>≤35</td><td>≥40</td></tr><tr><td>66～220</td><td>≥45</td></tr><tr><td>330</td><td>≥55</td></tr><tr><td>500</td><td>≥65</td></tr></table>',21,'20b4caf6-e46e-4b05-8d25-9fe68dceb58a',118,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.7  结果的判定"]','TABLE',NULL,'2026-03-11 11:17:43'),(27181,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.2.7  结果的判定\n\n在技术协议有特殊规定时，按技术协议规定判定是否合格。\nJB/T 501—2021',22,'e0384634-3bf7-4405-9c0d-b9fe642181cf',77,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.2.7  结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27182,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.3.1  试验目的\n\n绝缘油介质损耗因数是衡量绝缘油本身绝缘性能和被杂质污染程度的重要参数。油的损耗因数越 大，变压器的整体介质损耗因数也就越大，绝缘电阻相应降低，油纸绝缘的寿命也会缩短。因此应严格 测试， 以便将油的介质损耗因数控制在较低范围内。',23,'60b07e61-b0e8-42ce-a867-cc4ad8755675',149,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.3.1  试验目的"]','TEXT',NULL,'2026-03-11 11:17:43'),(27183,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.3.2  试验方法\n\n绝缘油介质损耗因数试验方法按GB/T 5654的规定进行。',24,'3752a6fb-8b5c-4378-8590-e88a12523e4a',65,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.3.2  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27184,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.3.3  试验仪器\n\n绝缘油介质损耗因数测量试验一般采用电桥及配套装置或介损仪进行测量。 具体要求如下：\n——主机：具有分辨率为 10-5 的交流（工频） 电桥；\n——电极杯：采用零件易于拆卸和清洗、重新装配后空杯电容量不易改变的三端电极杯； ——恒温加热装置：应能保持温度在规定值±0.5℃以内。',25,'92d4ff51-5b53-419f-a273-59720f958e81',174,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.3.3  试验仪器"]','TEXT',NULL,'2026-03-11 11:17:43'),(27185,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.3.4  试品取样\n\n试品按GB/T 7597规定的方法取样。',26,'b73993b1-65e7-4a68-a776-28c30f10a1f2',56,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.3.4  试品取样"]','TEXT',NULL,'2026-03-11 11:17:43'),(27186,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.3.5  试验过程\n\n试验过程如下：\na)  熟悉仪器使用说明书，按要求连接试验仪器并调试正常，且经计量部门检定合格；\nb)  完全拆卸电极杯，先用丙酮、后用洗涤剂彻底清洗，再用蒸馏水清洗几遍，并放到蒸馏水中煮 沸 1h；然后放在鼓风干燥箱里干燥 1h～2h 后，再重新装配电极；\nc)  测量空杯介损应接近零， 电容量应在规定值范围内；\nd)  用试油洗刷三次油杯，正式测试时按规定量（一般 40mL～45mL）倒入试油；\ne)  接通恒温控制装置，给试油加温至规定温度，按规定施加电压、测试；测试过程不宜超过 10min。\nf)  如使用自动介损测量仪，则设置完参数按“开始”键即可自动完成测试过程。\n对于新仪器，a）项、b）项、c）项应实施，而在正常使用情况下，可不必每次都实施。',27,'925600a5-aa81-4230-82d1-35a1d94c4b41',362,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.3.5  试验过程"]','TEXT',NULL,'2026-03-11 11:17:43'),(27187,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.3.6  注意事项\n\n注意事项如下：\n——检测交流电源，在保证仪器要求的情况下才能接通电源； ——仪器外壳和接地点应可靠接地；\n——确认仪器检定的有效期限；\n——自动介损测量仪电源不宜接在磁饱和稳压电源上； ——油杯清洗后严禁用手或不洁净物接触电极；\n——油杯使用时间较长或受到严重污染（介损值超过 10%）后应按 3.4.3.5 的 b）项、c）项清洗和 测量空杯介损；\n——测试下一个油样时，如果上次油样结果大于此油样对应的合格值，则油杯应用介损值较低的油 洗刷几次后，再用试油洗两次；\n——装、倒试油时， 内电极不宜接触任何物体。\nJB/T 501—2021',28,'91944346-2896-4f2f-b1af-b3f2ce931c7d',307,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.3.6  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27188,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.3.7  结果的判定\n\n测量同一油样时，两次测试值之差不应大于0.000 1加上两个值中较大一个的25%；如果不能满足上 述重复性要求，则应继续测量油样，直到满足要求，此时测量结果才能视为有效；取两次有效测量中较 小的一个值作为油样的介质损耗因数。\n在技术协议没有规定时，绝缘油介质损耗因数（90℃) 规定值：330kV级及以下产品，应小于0.010； 500kV级产品，应小于0.007。\n在技术协议有规定时，按技术协议规定判定是否合格。',29,'e20707cc-f9e1-4219-b31c-5d88a8dbea7d',245,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.3.7  结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27189,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.1  试验目的\n\n水分影响油纸绝缘性能、加快油纸绝缘老化速度，为了将绝缘油中含水量控制到较低范围，应在注 油前后对油中含水量进行测定。一般66kV级及以上产品进行此项试验。',30,'f3e62640-b1a1-44b0-a6b8-bd7174591e1c',113,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.1  试验目的"]','TEXT',NULL,'2026-03-11 11:17:43'),(27190,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.2  试验方法\n\n以下条款适用按照GB/T 7600进行绝缘油含水量测定，如按照GB/T 7601进行绝缘油含水量测定，则 应符合GB/T 7601的要求。',31,'6e350077-7c19-438a-a0e4-adb81415de68',105,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.2  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27191,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.3  试验仪器\n\n按GB/T 7600进行绝缘油含水量测定试验仪器按如下要求：\n——试验仪器应是以库仑法为基础、用卡尔 · 费休试剂作电解液的微量水分测试仪；\n——电解液最好分为阴极液和阳极液两种；\n——应定期用纯水或标准水分含量试剂校验仪器的准确性；\n——其它试验器材有：至少准备 1 支 2mL、5mL 和 100mL 的注射器用于取样，还要常备一个电吹风 用于干燥电解池。',32,'fa610a0d-f57e-425f-90dc-b06ccc737a7d',216,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.3  试验仪器"]','TEXT',NULL,'2026-03-11 11:17:43'),(27192,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.4  试品取样\n\n试品按GB/T 7597规定的方法取样。',33,'cbc412c9-b0c9-4a74-a744-e6c0f1c6e9f8',56,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.4  试品取样"]','TEXT',NULL,'2026-03-11 11:17:43'),(27193,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.5  试验过程\n\n试验过程如下：\n——按说明书要求接通微量水分测试仪的电源及设置仪器参数；\n——如果电解液发生过碘现象，则可以注入适量的含水甲醇或纯水予以消除；\n——仪器稳定后，用油样冲洗注射器不应少于三次，然后正式向仪器电解池中进样；进样量依油中 含水量大小来定，仪器说明书有规定的按其规定进行，无规定的一般一次所进试样中的水分含 量不得高于 10 mg/L。',34,'7fe21fd7-4267-4c49-a8e6-73666ee150f6',208,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.5  试验过程"]','TEXT',NULL,'2026-03-11 11:17:43'),(27194,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.6  注意事项\n\n注意事项如下：\n——在进样前应将进样口处及针头擦拭干净，不得用手接触上述位置； ——进样应迅速、利落；\n——环境湿度越高操作越应谨慎；夏季试验场地的相对湿度一般不应高于 85%；\n——每次更换电解液时，应用石油醚、无水乙醇将电解池彻底清洗并用电吹风吹干。\nJB/T 501—2021',35,'f92c12b3-8910-4ddc-86ea-7d812ac9d47a',177,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.6  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27195,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.7   结果的判定\n\n两次平行测试结果的差值不应超过如下规定：\n——样品含水范围为10mg/L以下，允许差为2mg/L；\n——样品含水范围为10mg/L～20mg/L，允许差为3mg/L； ——样品含水范围为21mg/L～40mg/L，允许差为4mg/L；\n——样品含水范围大于41mg/L，允许差为10%。\n取两次平行试验结果的算术平均值作为测定值。  在技术协议没有规定时，试验结果的判定按表3。',36,'3879f97c-558c-44de-9824-3bd94fe162a1',225,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.7   结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27196,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.7   结果的判定\n表 3  绝缘油含水量规定值\n<table><tr><td>电压等级kV</td><td>含水量mg/L</td></tr><tr><td>≤110</td><td>≤20</td></tr><tr><td>220</td><td>≤15</td></tr><tr><td>≥330</td><td>≤10</td></tr></table>',37,'347c8831-12b7-4e53-a4b0-060b7d460c1a',107,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.7   结果的判定"]','TABLE',NULL,'2026-03-11 11:17:43'),(27197,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.4.7   结果的判定\n\n在技术协议有规定时，按技术协议规定判定是否合格。',38,'77ad61db-3ee4-4044-a564-72426b06e122',61,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.4.7   结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27198,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.5.1  试验目的\n\n绝缘油溶解空气的能力很强，当空气含量过高时，在注油和运行中易在油中形成气泡，导致局部放 电。即使溶解的空气不产生气泡，其中的氧气也会加速油纸绝缘老化。因此绝缘油中的含气量应控制在 较低的范围内。一般330kV级及以上产品进行此项试验。',39,'94bf3ef8-3236-4c42-ae97-f18d526e46d7',153,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.5.1  试验目的"]','TEXT',NULL,'2026-03-11 11:17:43'),(27199,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.5.2.1  概述\n\n本导则规定的绝缘油中含气量的测定方法有两种：一种为气相色谱法，其方法按DL/T 703的规定； 另一种采用DL/T 423规定的真空压差法，真空压差法试验方法分为A法（电子真空计法）和B法（U形油 柱压差计法）。',40,'74c5d53f-f517-4689-87c8-5ca9c5a46bd7',142,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.5.2.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27200,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.5.2.2  取样\n\n按GB/T 7597规定的油中溶解气体分析样品采集方法进行采样、运输和保存。',41,'aa10c5ca-634c-4901-998d-ebb3fffab6a9',74,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.5.2.2  取样"]','TEXT',NULL,'2026-03-11 11:17:43'),(27201,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.5.2.3  试验方法\n\n试验中使用的仪器、器材、详细的试验步骤、含气量的计算及精密度的要求应符合DL/T 423和 DL/T 703的规定。',42,'c1079d6e-b22c-415a-b639-f59dddad6c9e',96,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.5.2.3  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27202,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.5.3  试验报告\n\n取连续两次满足精密度要求的测试结果算术平均值作为试油含气量报告值。',43,'07b7bf66-5ca5-4d69-8590-419b95527a43',69,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.5.3  试验报告"]','TEXT',NULL,'2026-03-11 11:17:43'),(27203,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.5.4  结果的判定\n\nJB/T 501—2021\n取两次平行试验结果的算术平均值为测定结果，两次测定值之差应小于平均值的10%。 在技术协议没有规定时，试验结果的合格判定见表4。',44,'fd459f08-0386-49e5-b77e-14c0f593ecf3',115,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.5.4  结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27204,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.5.4  结果的判定\n表 4  绝缘油含气量规定值\n<table><tr><td>电压等级kV</td><td>含气量%</td></tr><tr><td>≥330</td><td>≤1</td></tr></table>',45,'47d6cd4b-7258-46f5-b4f3-f19a79d461f6',78,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.5.4  结果的判定"]','TABLE',NULL,'2026-03-11 11:17:43'),(27205,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.5.4  结果的判定\n\n在技术协议有规定时，按技术协议规定判定是否合格。',46,'c724d2d3-d074-4d0c-9231-4b2782c33abb',61,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.5.4  结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27206,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.1  试验目的\n\n绝缘油中溶解的和气体继电器中收集的一氧化碳、二氧化碳、氢气、甲烷、乙烷、乙烯、乙炔等气 体的含量，间接地反映了充油设备（变压器、电抗器、套管等）本身的实际情况，通过对这些组分的变 化情况进行分析，就可以判断设备在试验或运行过程中的状态变化情况，并对判断和排除故障提供依据。 一般66 kV及以上产品进行此项试验。',47,'7d1e378d-2dc9-4d2b-9519-f39832e9e05a',192,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.1  试验目的"]','TEXT',NULL,'2026-03-11 11:17:43'),(27207,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.2.1  概述\n\n根据对绝缘油中溶解气体进行脱气的方式不同，在实际工作中所使用方法分为两种，都是先采集充 油设备中的油样，然后脱出油样中的气体，再用气相色谱仪进行分离、检测，最后对谱图数据进行处理， 计算出各组分的浓度。具体试验方法按GB/T 17623的规定。',48,'6c3bcfb2-3c50-4c5d-9c01-d8ff71642736',158,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.2.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27208,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.2.2  机械振荡法（溶解平衡法）\n\n机械振荡法按如下要求：\na)  脱气过程：一般用 40mL 油样注入 5mL 氮气，然后在 50℃下进行恒温定时振荡，振荡 20min、 静放 10min 即可达到平衡；取出气样，记下体积值（精确到 0.1mL）；\nb)  分离、检测气样：用 1mL 玻璃针管取出 1mL 气样，立即注入色谱仪、输入脱出气样体积值，色 谱仪进行分离、检测，色谱工作站随之记录谱图、读取峰高或峰面积值，并自动计算出油中溶 解气体各组分的浓度。',49,'39a33de2-4deb-4c68-bfef-d031e7f64377',256,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.2.2  机械振荡法（溶解平衡法）"]','TEXT',NULL,'2026-03-11 11:17:43'),(27209,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.2.3  真空脱气法（变径活塞泵全脱气法）\n\n真空脱气法按如下要求：\n——脱气过程：变径活塞脱气装置由变径活塞泵、脱气室、磁力搅拌器和真空泵、集气室等组成； 先由真空泵对脱气室抽真空，将 20mL 绝缘油注入脱气室，装置自动进行多次脱气、集气，使 气样合并、并收集到集气室内，最后排出油样；记下油样和气样的体积（精确到 0.1mL）；\n——分离、检测气样：同 3.4.6.2.2 的 b）项。',50,'2fddb4aa-5759-4118-b672-3617f6344c72',223,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.2.3  真空脱气法（变径活塞泵全脱气法）"]','TEXT',NULL,'2026-03-11 11:17:43'),(27210,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.3  气态样品中各组分浓度的测试\n\n主要是针对从气体继电器中取出的气样进行测试分析；取1mL气样注入色谱仪进行测试，得出峰面 积或峰高值，直接计算出结果。\nJB/T 501—2021',51,'4e1a1761-0fb4-4a15-a719-2f556bf565f5',118,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.3  气态样品中各组分浓度的测试"]','TEXT',NULL,'2026-03-11 11:17:43'),(27211,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.4   试验仪器\n\n试验仪器如：\n——色谱仪应具备热导鉴定器、氢焰离子化鉴定器及镍触媒转化器，建议使用单次进样自动阀切换 控制双柱分离的气路流程，便于自动控制；色谱柱对所测组分的分离度要满足定量分析的要求； 测试过程中，色谱仪基线要平稳；色谱仪对各种溶解气体的最小检测浓度(μL/L）为：氢气 2、 烃类 0.1、一氧化碳 5、二氧化碳 10；\n——色谱工作站要求结构简单、运行稳定；可针对不同的样品状态和脱气方式分别进行处理，通常 只需输入试验参数就可直接计算出结果，并保存、打印结果及谱图；\n——载气或反应气可用压缩气瓶或气体发生器作为气源，要求达到足够的纯度，氮气（或氩气）、 氢气纯度不低于99.99%、空气应纯净无油。',52,'63f21ab3-d43b-4745-8fb5-8b0fe592471e',340,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.4   试验仪器"]','TEXT',NULL,'2026-03-11 11:17:43'),(27212,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.5  试品取样\n\n试品按GB/T 7597规定的方法取样。',53,'5957ca31-43e8-41b9-bf6e-72fc571465e0',56,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.5  试品取样"]','TEXT',NULL,'2026-03-11 11:17:43'),(27213,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.6  仪器的标定\n\n仪器的标定按如下要求：\n——每次试验前均应采用外标法对仪器进行标定；\n——在仪器稳定的状态下，用 1mL玻璃针管取 1mL含待测组分各已知浓度的标准混合气注入色谱仪， 色谱工作站自动读取并记录色谱图的峰高或峰面积值；\n——标定的条件和试验的条件应相同，仪器工作要稳定，至少标定两次，且其重复性应在其平均值 的±2%以内；\n——仪器参数设定要以满足试验的要求为先决条件，根据仪器性能分别设定。',54,'6ed620b7-bd3f-4c05-8168-dfb424b920da',232,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.6  仪器的标定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27214,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.7  注意事项\n\n注意事项如下：\n——应根据待测油样中所溶解的气体组分含量的高低选用标气中各组分的浓度，对于例行试验和投 运试验，因其各组分含量较低，因此宜选用低浓度的标气；对于运行中的设备，因气体含量较 高，因此宜选用高浓度的标气；\n——仪器标定和样品分析应使用同一进样注射器，保证进样体积相同； ——标气应在有效期内使用，禁止超期使用；\n——取样时针管内的空气要排净，针芯可自由滑动、不卡涩； ——胶头内的空气亦应排净；\n——对于真空脱气装置，要定期对它的气密性进行测试，保证脱气完全； ——气样应尽快地测试，防止泄露，保存期应短于油样；\n——对结果进行判定时，应考虑到各种可能对结果产生干扰的因素（如：电焊、油样被污染等原因）， 防止误判；\n——应对所有针管体积进行标定， 以减小误差。',55,'f176d487-5f91-423d-9951-d2d71d72e851',373,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.7  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27215,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.8.1  气体组分的含量判定\n\n对出厂和新投运的产品，各种气体组分的含量应满足表5的规定，并且在产品绝缘耐受电压试验、 局部放电试验、温升试验及空载运行试验前后各组分不能有明显升高。\nJB/T 501—2021',56,'b1d86e5a-d759-4558-aea4-0ebb40e12cb1',132,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.8.1  气体组分的含量判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27216,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.8.1  气体组分的含量判定\n表 5  绝缘油溶解气体气相色谱分析含量值\n<table><tr><td>组分</td><td>变压器和电抗器µL/L</td><td>套管µL/L</td></tr><tr><td>氢气</td><td>＜30</td><td>＜150</td></tr><tr><td>乙炔</td><td>0</td><td>0</td></tr><tr><td>总烃</td><td>＜20</td><td>＜10</td></tr></table>',57,'c148e7fb-8102-4cc9-99b8-ab8ef4ec77ab',139,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.8.1  气体组分的含量判定"]','TABLE',NULL,'2026-03-11 11:17:43'),(27217,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.8.1  气体组分的含量判定\n\n如不符合上述要求，则应仔细辩明原因；出现乙炔时应考虑有放电电现象；如果用户有特殊要求， 则其结果还要符合技术协议规定。',58,'c5e4bac6-78e9-4e6b-a644-eba7141a01fb',102,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.8.1  气体组分的含量判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27218,508,'## 3  油浸式电力变压器试验\n### 3.4  绝缘油试验\n#### 3.4.6.8.2  结果的重复性和再现性\n\n同一试样至少要进行两次平行试验，取两次结果的算术平均值为试验结果；当油中溶解的气体浓 度大于10μL/L时，两次测定结果值之差应小于平均值的10%；当油中溶解的气体浓度小于或等于10μL/L 时，两次测定结果值之差应小于平均值的15%；不同试验室对于同一试样测定值的相对偏差，当组分浓 度大于10μL/L时，应小于平均值的15%；当组分浓度小于或等于10μL/L时，应小于平均值的30%。',59,'a45d6371-9b70-4dea-8d33-d75c1f6ff720',238,NULL,'["3  油浸式电力变压器试验", "3.4  绝缘油试验", "3.4.6.8.2  结果的重复性和再现性"]','TEXT',NULL,'2026-03-11 11:17:43'),(27219,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.1  试验一般要求\n\n变压器注入绝缘油后，至少3 h不励磁，顶层液体与底部液体温度之差不应超过5 K。为快速达到目 的，可以用泵强迫液体循环。测量应采用直流，在测量中，应注意将自感效应的影响降到最低。\n带分接的绕组，每个分接都应测量。',60,'e6b00c59-261f-44a4-8539-c0ffef2a25b4',143,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27220,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.2  测量仪器和仪器精度\n\n测量仪器推荐采用精度不低于 0.2 级恒流输出的直流电阻测试仪；也可采用精度不低于 0.5 级的电 阻电桥。',61,'c3c74565-9671-40a3-ab3a-ee37a8914fbb',94,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.2  测量仪器和仪器精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27221,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.3.1  绕组温度的测量\n\n对于油浸式变压器应测量顶层液体温度和底部液体温度，取顶层液体温度和底部液体温度的平均温 度作为绕组温度。',62,'e880a409-2fe6-4f47-b69a-499668e898c1',92,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.3.1  绕组温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27222,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.3.2  测量电流的选取\n\n根据样品绕组电阻计算值，测量电流按照仪器规定的范围选取；测量电流不得大于被试绕组额定电 流的15%。',63,'b269f9a0-90d7-48d4-be1f-8c48b990b9a9',90,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.3.2  测量电流的选取"]','TEXT',NULL,'2026-03-11 11:17:43'),(27223,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.3.3  绕组电阻测量\n\n绕组的电阻应分别在各绕组的线端上测量；三相变压器绕组为Y（y）联结无中性点引出时应测量其 线电阻，如果有中性点引出时，则应测量其相电阻，但对中性点引线电阻所占比例较大的yn（YN）联结 的变压器，应测量其线电阻及中性点对一个线端的电阻。绕组为D（d）联结时，首末端均引出的应测量 其相电阻；封闭三角形的试品应测量其线电阻。\nJB/T 501—2021',64,'bf8c96c8-2a64-4073-be18-cb73838f091d',214,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.3.3  绕组电阻测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27224,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.4  结果判定\n\n结果判定见表6。',65,'647be641-ed6d-484f-9fdb-942af016ac9c',43,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27225,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.4  结果判定\n表 6  变压器绕组电阻不平衡率判定要求\n<table><tr><td>变压器的要求</td><td>相</td><td>线</td></tr><tr><td>10kV</td><td>≤4%</td><td>≤2%</td></tr><tr><td>35kV  配电变压器</td><td>≤4%</td><td>≤2%</td></tr><tr><td>35kV电力变压器</td><td>≤2%</td><td>≤1%</td></tr><tr><td>66kV  容量≤1600kVA</td><td>≤4%</td><td>≤2%</td></tr><tr><td>66kV  容量≥2000kVA</td><td>≤2%</td><td>≤1%</td></tr><tr><td>110kV 及以上</td><td>≤2%</td><td>≤1%</td></tr></table>',66,'44c07ce9-55fb-4995-8695-282f19f7cd2f',223,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.4  结果判定"]','TABLE',NULL,'2026-03-11 11:17:43'),(27226,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.4  结果判定\n\n当由于结构原因和线材原因造成的电阻不平衡率超过上述要求时，试验报告应注明原因。',67,'6c948a63-863f-49b0-9ec8-2903966c4c95',74,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27227,508,'## 3  油浸式电力变压器试验\n### 3.5  绕组电阻测量\n#### 3.5.5  注意事项\n\n对于带有无励磁分接开关的变压器应在绕组断电的情况下切换分接开关的位置。',68,'df9d0539-5323-400d-b4c0-96140c5f7f86',70,NULL,'["3  油浸式电力变压器试验", "3.5  绕组电阻测量", "3.5.5  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27228,508,'## 3  油浸式电力变压器试验\n### 3.6  电压比测量和联结组标号检定\n#### 3.6.1  试验一般要求\n\n每个分接都应进行电压比测量。应检定单相变压器的极性和三相变压器的联结组标号。 如果采用双电压表法测量，则两个绕组的电压应同时测量。',69,'d29063af-a364-4783-bcfa-0d2eeba33e04',109,NULL,'["3  油浸式电力变压器试验", "3.6  电压比测量和联结组标号检定", "3.6.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27229,508,'## 3  油浸式电力变压器试验\n### 3.6  电压比测量和联结组标号检定\n#### 3.6.2  测量仪器精度\n\n仪器的精度应不低于 0.2 级。',70,'b04b714e-27c3-4a13-b118-ab958bf50733',60,NULL,'["3  油浸式电力变压器试验", "3.6  电压比测量和联结组标号检定", "3.6.2  测量仪器精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27230,508,'## 3  油浸式电力变压器试验\n### 3.6  电压比测量和联结组标号检定\n#### 3.6.3.1  概述\n\n测量方法推荐采用电压比测试仪测量。',71,'e8515a26-c157-4b90-b533-de93129d5ffa',59,NULL,'["3  油浸式电力变压器试验", "3.6  电压比测量和联结组标号检定", "3.6.3.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27231,508,'## 3  油浸式电力变压器试验\n### 3.6  电压比测量和联结组标号检定\n#### 3.6.3.2  试验接线示意图\n\n单相变压器试验接线示意图见图1。 三相变压器试验接线示意图见图2。\n图 1  单相变压器电压比测量接线示意图\nJB/T 501—2021\n图 2  三相变压器电压比测量接线示意图',72,'de67b321-f447-4fba-a409-4e2e4dfd8ce1',134,NULL,'["3  油浸式电力变压器试验", "3.6  电压比测量和联结组标号检定", "3.6.3.2  试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27232,508,'## 3  油浸式电力变压器试验\n### 3.6  电压比测量和联结组标号检定\n#### 3.6.3.3  电压比值的基准值计算\n\n电压比值的基准值计算应按照产品铭牌标称的电压值进行计算，当使用分接因数计算所对应的分接 位置的电压比与产品标称的电压所计算的电压比一致时，允许只计算主分接的电压比，其它分接可以使 用主分接的电压比与分接因数进行计算，否则应按产品铭牌标称的电压值计算所有分接位置的电压比。',73,'f59868b5-de75-46d2-b0df-c55e5a0b2f7e',185,NULL,'["3  油浸式电力变压器试验", "3.6  电压比测量和联结组标号检定", "3.6.3.3  电压比值的基准值计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27233,508,'## 3  油浸式电力变压器试验\n### 3.6  电压比测量和联结组标号检定\n#### 3.6.3.4  绕组对和分接的选择\n\n带有分接的绕组应在所有分接下进行测量。\n如果无其它规定，则测量一对绕组的电压比，如果两个绕组都带有分接，则可以先测量较高绕组所 有分接对较低绕组额定分接位置电压比。较低绕组其它分接位置的电压比，可以与其它不带分接的绕组 组成的绕组对进行测量。例如： 电压组合（110±8×1.25%）/(35±2×2.5%)/11kV 的电压比测量为：\n——高压（所有分接）/中压（额定分接）；\n——高压（所有分接）/低压； ——中压（所有分接）/低压。',74,'b99660ad-8680-4488-89e9-93fc4ac7371d',268,NULL,'["3  油浸式电力变压器试验", "3.6  电压比测量和联结组标号检定", "3.6.3.4  绕组对和分接的选择"]','TEXT',NULL,'2026-03-11 11:17:43'),(27234,508,'## 3  油浸式电力变压器试验\n### 3.6  电压比测量和联结组标号检定\n#### 3.6.4  结果判定\n\n按 GB/T 1094.1—2013  的表 1 中空载电压比偏差的规定：\n——第一绕组对的主分接或极限分接（如果规定） ：规定电压比的±0.5％或实际阻抗百分数的 ±1／10，取两者中的较小者；\n——第一绕组对的其它分接：匝数比设计值的±0.5%; ——其它绕组对：匝数比设计值的±0.5％。',75,'d17e6162-0425-460e-ab54-9fa198b205e0',188,NULL,'["3  油浸式电力变压器试验", "3.6  电压比测量和联结组标号检定", "3.6.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27235,508,'## 3  油浸式电力变压器试验\n### 3.6  电压比测量和联结组标号检定\n#### 3.6.5  注意事项\n\n注意在绕组电阻测量或短路承受能力试验后，铁心剩磁可能影响测量结果。',76,'a9d30371-439b-40ec-8798-e194efed63de',75,NULL,'["3  油浸式电力变压器试验", "3.6  电压比测量和联结组标号检定", "3.6.5  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27236,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.1  试验一般要求\n\n变压器的温度接近试验时的环境温度，油浸式变压器测量顶层与底层油温度，其平均值作为绕组温 度。\n一对绕组的短路阻抗和负载损耗测量时，应在额定频率下，将电压施加到一个绕组上，另一绕组短 路，其它绕组(如果有）开路。宜施加等于相应的额定电流（分接电流）的试验电流，但不应低于该电\nJB/T 501—2021\n流的 50%。试验应尽快进行，以减少温升引起的明显误差。顶层油与底部油的温差应足够小，以便准确 得到油平均温度。顶层油与底部油的温差不应大于 5K。为了更快速得到结果，可以用泵搅拌油。\n负载损耗测量值应乘以额定电流（或分接电流）对试验电流之比的平方。得到的结果应校正到参考 温度。I2R损耗（R为绕组直流电阻）随绕组温度呈正向变化，而所有其它损耗与温度呈反向变化。\n对于大容量、低电压变压器的负载试验（如：双分裂变压器，低压 1 对低压 2 绕组的负载试验）， 当受试验设备能力限制时，在制造方与用户协商一致的情况下，可以根据试验能力降低试验电流。\n对于分接范围不超过±5%的变压器，一般在主分接进行短路阻抗和负载损耗测量。\n对于分接范围超过±5%的变压器，应对主分接、两个极限分接进行短路阻抗和负载损耗测量。试验 报告中，除了提供主分接短路阻抗和负载损耗外还应提供两个极限分接短路阻抗。\n对于分接范围不超过±5%，但额定容量超过 2500kVA 的变压器，如果产品进行温升试验，为了温升 试验的目的，应对主分接、两个极限分接进行短路阻抗和负载损耗测量。如果不进行温升试验则对主分 接进行短路阻抗和负载损耗测量。对于这类变压器在短路后的复试中也仅在主分接进行短路阻抗和负载 损耗测量。\n负载试验施加的电流以三相负载电流的算术平均值为准。',77,'9aaf990b-9c60-4499-8779-d482dcdf713c',761,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27237,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.2  测量仪器和精度\n\n互感器的精度不低于 0.2 级，对于大型变压器推荐采用精度不低于 0.05 级的互感器；所用仪表精度 应不低于 0.5 级。',78,'31eb7dad-6ad7-44cf-a661-acce172003b7',105,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.2  测量仪器和精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27238,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.3.1  试验接线示意图\n\n三相变压器负载试验接线示意图见图3，单相变压器负载试验接线示意图见图4。\n图 3  三相变压器负载试验接线示意图\nJB/T 501—2021\n图 4  单相变压器负载试验接线示意图',79,'f60de7dc-45a1-4168-95c3-06e4e087d7dc',133,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.3.1  试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27239,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.3.2.1  环境温度下损耗和短路阻抗换算到参考温度\n<table><tr><td>损耗按式（1）折算：</td><td>.................................................................</td></tr><tr><td>式中：</td><td> </td></tr></table>',80,'bb5c45d0-3a5f-4f72-9c2e-8e34739bac16',148,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.3.2.1  环境温度下损耗和短路阻抗换算到参考温度"]','TABLE',NULL,'2026-03-11 11:17:43'),(27240,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.3.2.1  环境温度下损耗和短路阻抗换算到参考温度\n\nPk ——参考温度下的负载损耗，kW； Pkt ——t ℃时的负载损耗，kW；\nΣ I 2R ——试验温度下一对绕组的电阻损耗，kW； Kt ——电阻温度换算系数。\n短路阻抗按式（2）折算：\n........................................................................\n式中：\nZkt ——绕组温度为 t ℃时的短路阻抗，%；\nUkt ——绕组 t ℃时通过试验电流 Ik 的阻抗电压，kV； Ik    ——试验施加电流，A；\nUr ——施加电压侧的额定电压，kV； Ir ——施加电压侧的额定电流，A；  Zk ——参考温度时的短路阻抗，%；\nJB/T 501—2021\nPkt ——t ℃时的负载损耗，kW；\nPk ——参考温度下的负载损耗，kW； Sr ——额定容量，MVA。',81,'c744089c-c281-4100-ae3a-5e12d7e79df8',431,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.3.2.1  环境温度下损耗和短路阻抗换算到参考温度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27241,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.3.2.2  电阻损耗计算\n\n典型三相变压器一对绕组的电阻损耗应为两绕组电阻损耗之和，计算方法见式（3）：\n(\nr\nr\nxn\nr\nxg\n)P = 1.5I2R   = 3I2R   （Y 或 YN 联结的绕组）\n(\nr\nr\nxn\nr\nxg\n)P = 1.5I2R   = I2R   （D联结的绕组）                               (3)\n式中：\nPr ——电阻损耗，kW； I r ——额定电流，A；  Rxn ——线电阻， Ω;   Rxg ——相电阻， Ω。',82,'c8ed4620-ffed-4988-a5a2-af16b6f15281',237,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.3.2.2  电阻损耗计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27242,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.4  结果判定\n\n结果判定按技术协议的规定，但不得低于表7的规定。',83,'18accf2b-4628-4417-a2c0-1a7b892310e6',64,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27243,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.4  结果判定\n表 7  油浸式电力变压器负载损耗和短路阻抗的允许偏差\n<table><tr><td colspan=\'2\'>项目</td><td colspan=\'2\'>允许偏差</td></tr><tr><td colspan=\'2\'>负载损耗</td><td colspan=\'2\'>+15%<br/>但总损耗不得超过+10%</td></tr><tr><td rowspan=\'5\'>短路阻抗</td><td rowspan=\'2\'>a）有两个独立绕组的变压器，或<br/>b）多绕组变压器中规定的第一对独立绕组</td><td>主分接</td><td>当阻抗值≥10 ％时，±7.5%当阻抗值&lt;10 ％时，±10%</td></tr><tr><td>其它分接</td><td>当阻抗值≥10 ％时，±10%当阻抗值 &lt;10 ％时，±15%</td></tr><tr><td rowspan=\'2\'>a）自耦联结的一对绕组，或<br/>b）多绕组变压器中规定的第二对绕组</td><td>主分接</td><td>规定值的±10%</td></tr><tr><td>其它分接</td><td>设计值的±10%</td></tr><tr><td>其它绕组对</td><td colspan=\'2\'>按协议，但绝对值不小于15%</td></tr></table>',84,'f9038bcc-a475-400b-9c07-018e318e1e2b',325,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.4  结果判定"]','TABLE',NULL,'2026-03-11 11:17:43'),(27244,508,'## 3  油浸式电力变压器试验\n### 3.7  短路阻抗和负载损耗测量\n#### 3.7.5  注意事项\n\n对于低电压、大电流的试品， 电压互感器一次线应连接到试品线端， 以免线路损耗影响测量结果。\n对于大容量变压器，采用低压侧短接，由于低压电流很大，短路连接的电阻损耗引入的测量误差较 大，可在试验结果中加以校正。\n对于功率因数较低的试品，如果互感器的相位差对测量结果产生影响，则应按照 GB/T 13499 的规 定进行校正。',85,'d907074c-ba37-4c37-9479-8206a3a08251',201,NULL,'["3  油浸式电力变压器试验", "3.7  短路阻抗和负载损耗测量", "3.7.5  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27245,508,'## 3  油浸式电力变压器试验\n### 3.8  空载损耗和空载电流测量\n#### 3.8.1  试验一般要求\n\n变压器的温度接近试验时的环境温度。\nJB/T 501—2021\n通常由被试品的低压侧施加额定频率的额定电压（应尽可能为对称的正弦波电压），其余绕组 开路；如果施加电压的绕组是带有分接的，应使分接开关处于主分接的位置；如果被试品绕组中有 开口三角形连接绕组，则应使其闭和。运行中的地电位处（分级绝缘变压器其中性点、铁心、夹件 等）和油箱或外壳应可靠接地。\n对于三相变压器，选择接到试验电源的绕组和联结方式时，应尽可能使三个心柱上出现对称的 正弦电压。\n如果无其它规定，则对于有不同容量的多绕组变压器，空载电流百分数应换算到最大容量。',86,'6a9262fc-0d04-4600-a5ce-26aa8a25241f',307,NULL,'["3  油浸式电力变压器试验", "3.8  空载损耗和空载电流测量", "3.8.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27246,508,'## 3  油浸式电力变压器试验\n### 3.8  空载损耗和空载电流测量\n#### 3.8.2  测量仪器和精度\n\n空载损耗和空载电流测量，对于测量系统的要求低于负载损耗的测量，因此能够满足负载损耗测量 的测量系统适用于空载损耗和空载电流测量。',87,'e20a0731-9dce-4033-b5c2-ea0df0db3448',107,NULL,'["3  油浸式电力变压器试验", "3.8  空载损耗和空载电流测量", "3.8.2  测量仪器和精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27247,508,'## 3  油浸式电力变压器试验\n### 3.8  空载损耗和空载电流测量\n#### 3.8.3.1  试验接线示意图\n\n三相变压器空载试验接线示意图见图5，单相变压器空载试验接线示意图见图6。\n图 5  三相变压器空载试验接线示意图\n图 6  单相变压器空载试验接线示意图',88,'c9e23465-bc3a-4458-9c7e-86c42a232394',119,NULL,'["3  油浸式电力变压器试验", "3.8  空载损耗和空载电流测量", "3.8.3.1  试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27248,508,'## 3  油浸式电力变压器试验\n### 3.8  空载损耗和空载电流测量\n#### 3.8.3.2  试验电压的施加\n\nJB/T 501—2021\n试验电压的施加应从零开始升压，在升压过程中应连续观察所有测量仪表的指示状况，尤其在测量 过程中，应注意剩磁对测量结果的影响，在测量仪器和试验设备不过载的情况下，先对被试品进行 110% 额定电压励磁，降压时尽可能降到零电压，然后进行额定电压励磁，保持几分钟，待损耗和电流没有下 降的趋势，进行测量记录。\n励磁电压应以平均值电压表的读数 U\'为准，该读数与方均根值电压表的读数 U 具有同一刻度。',89,'40650534-f5c5-49c3-8df3-3f24b2dfbdbc',256,NULL,'["3  油浸式电力变压器试验", "3.8  空载损耗和空载电流测量", "3.8.3.2  试验电压的施加"]','TEXT',NULL,'2026-03-11 11:17:43'),(27249,508,'## 3  油浸式电力变压器试验\n### 3.8  空载损耗和空载电流测量\n#### 3.8.3.3  空载损耗的波形校正\n\n如果 U\'与 U 相差 3%以内，则按照 Po=Pm(1+d)进行校正，其中 Po 为校正后的空载损耗，Pm 为测量 的空载损耗，d=（U\'- U）/ U\'。\n如果 U\'与 U 相差不大于 3%，则此电压的波形满足试验要求。如果 U\'与 U 相差大于3%，则应按照 协议确认试验的有效性。在高于额定电压时，可以接受超过 3%的读数差，但测量值属于保证值的情况 除外。',90,'f89ae825-2a31-4ac9-96f8-77db4615b585',230,NULL,'["3  油浸式电力变压器试验", "3.8  空载损耗和空载电流测量", "3.8.3.3  空载损耗的波形校正"]','TEXT',NULL,'2026-03-11 11:17:43'),(27250,508,'## 3  油浸式电力变压器试验\n### 3.8  空载损耗和空载电流测量\n#### 3.8.4  结果判定\n\n如果无技术协议规定，则空载电流允许偏差为+30%，空载损耗允许偏差为+15%。 如果有技术协议，则按技术协议的规定，但不得低于上述要求。',91,'a70740be-2740-452e-a6a1-e4875107e411',108,NULL,'["3  油浸式电力变压器试验", "3.8  空载损耗和空载电流测量", "3.8.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27251,508,'## 3  油浸式电力变压器试验\n### 3.8  空载损耗和空载电流测量\n#### 3.8.5  注意事项\n\n绕组电阻测量、冲击试验及短路承受能力试验后铁心可能产生剩磁，应注意剩磁对于空载损耗和空 载电流测量的影响',92,'5f22956f-b190-4ade-89f3-5406956725c1',92,NULL,'["3  油浸式电力变压器试验", "3.8  空载损耗和空载电流测量", "3.8.5  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27252,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.1  试验一般要求\n\n试验应在环境温度（被试品温度）为 5℃~40℃、湿度小于 85％的条件下进行。',93,'16aaeaa9-e6db-430b-97b7-88773cf82127',86,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27253,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.2  测量仪器和精度\n\n测量仪器采用数值兆欧表，精度不低于 5%。',94,'b355b31b-b552-4b39-86ce-122abaa51490',69,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.2  测量仪器和精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27254,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.3.1  测量参数\n\n测量被试品的温度和环境湿度。\n电压等级 35kV（额定容量 4000kVA 以下）及以下的变压器提供 R60（60s 时)的绝缘电阻值；电压等 级 35kV（额定容量 4000kVA 及以上）及以上，电压等级 220kV 以下的变压器提供 R60 的绝缘电阻值和吸 收比 R60/R15（15s 时的绝缘电阻值）的值；电压等级 220kV 及以上的变压器提供 R60 的绝缘电阻值、吸收 比 R60/R15 及极化指数 R600（10min 的绝缘电阻值）/R60 的值。\n铁心和夹件提供 R60（60s 时)的绝缘电阻值。',95,'400b34cd-a7ea-4e2b-ab85-8ef86a1c6296',309,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.3.1  测量参数"]','TEXT',NULL,'2026-03-11 11:17:43'),(27255,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.3.2  测量组合方式\n\n对于双绕组变压器绝缘电阻测量的组合方式不少于表8的规定。 对于三绕组变压器绝缘电阻测量的组合方式不少于表9的规定。\nJB/T 501—2021',96,'ba96f6de-9135-4480-85a8-3460bffcf7b1',120,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.3.2  测量组合方式"]','TEXT',NULL,'2026-03-11 11:17:43'),(27256,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.3.2  测量组合方式\n表 8  双绕组变压器绝缘电阻测量的组合方式\n<table><tr><td>序号</td><td>被试部位</td><td>接地部位</td></tr><tr><td>1</td><td>高压</td><td>低压、铁心、夹件及油箱</td></tr><tr><td>2</td><td>低压</td><td>高压、铁心、夹件及油箱</td></tr><tr><td>3 a</td><td>高压及低压</td><td>铁心、夹件及油箱</td></tr><tr><td>4</td><td>铁心</td><td>夹件及油箱</td></tr><tr><td>5</td><td>夹件</td><td>铁心及油箱</td></tr><tr><td colspan=\'3\'>a 仅适用于额定容量为16000kVA以上变压器。</td></tr></table>',97,'58a43976-cddb-476f-8bf3-53af5848bed2',222,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.3.2  测量组合方式"]','TABLE',NULL,'2026-03-11 11:17:43'),(27257,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.3.2  测量组合方式\n表 9  三绕组变压器绝缘电阻测量的组合方式\n<table><tr><td>序号</td><td>被试部位</td><td>接地部位</td></tr><tr><td>1</td><td>高压</td><td>中压、低压、铁心、夹件及油箱</td></tr><tr><td>2</td><td>中压</td><td>高压、低压、铁心、夹件及油箱</td></tr><tr><td>3</td><td>低压</td><td>高压、中压、铁心、夹件及油箱</td></tr><tr><td>4 a</td><td>高压及中压</td><td>低压、铁心、夹件及油箱</td></tr><tr><td>5 a</td><td>高压、中压及低压</td><td>铁心、夹件及油箱</td></tr><tr><td>6</td><td>铁心</td><td>夹件及油箱</td></tr><tr><td>7</td><td>夹件</td><td>铁心及油箱</td></tr><tr><td colspan=\'3\'>a 仅适用于额定容量为16000kVA及 以上变压器。</td></tr></table>',98,'e38ced2c-12de-4ded-946d-ad7b0750a6a0',287,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.3.2  测量组合方式"]','TABLE',NULL,'2026-03-11 11:17:43'),(27258,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.3.3  被试品温度的测量\n\n油浸式变压器测量顶层与底部油的温度，其平均值作为被试品的温度。顶层与底部油的温度接近时， 顶层的温度作为被试品的温度。',99,'480ba467-8113-42c3-b903-b3b5c57459ed',110,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.3.3  被试品温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27259,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.3.4  测量电压的选择\n\n电压为 35kV、容量为 4000kVA 和 66kV 及以上的变压器测量时使用 5000V 电压。其它变压器测量时 使用 2500V 电压。\n铁心和夹件测量时使用 2500V 电压。',100,'99f5cacb-2f0a-4aa1-8473-42fc45b0bbbe',142,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.3.4  测量电压的选择"]','TEXT',NULL,'2026-03-11 11:17:43'),(27260,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.3.5  不同温度下的绝缘电阻值换算\n\n不同温度下的绝缘电阻值按式（4）换算：\nR2  = R1 × 1.5(t1 -t2 ) / 10 ......................................................................... (4)\n式中：\nR1 、R2——分别为温度 t1 、t2 时的绝缘电阻值。',101,'8c777283-9bcc-4b34-b19a-8ec4d8195f51',215,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.3.5  不同温度下的绝缘电阻值换算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27261,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.4  结果判定\n\n如果无技术协议规定，则铁心和夹件的绝缘电阻值应不小于 500MΩ（60s 、20℃下）。 如果有技术协议，则结果判定按照技术协议规定。\nJB/T 501—2021',102,'7ecb73a1-0063-48d0-b79e-f34c197efa8e',126,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27262,508,'## 3  油浸式电力变压器试验\n### 3.9  绕组对地及绕组间直流绝缘电阻测量\n#### 3.9.5  注意事项\n\n充电时间会影响绝缘电阻值的测量结果，在进行不同方式的绝缘电阻测量时应对绕组进行充分的放 电。\n当环境湿度较大时，可能影响测量结果，应对靠近加压端子的绝缘体用金属环进行屏蔽，以降低泄 漏电流对测量结果的影响。',103,'1020972f-b9e1-440b-ae97-6c8792858fc2',148,NULL,'["3  油浸式电力变压器试验", "3.9  绕组对地及绕组间直流绝缘电阻测量", "3.9.5  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27263,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.1  绝缘试验的一般要求\n\n对于油浸式变压器绝缘试验仅适用于内绝缘。外绝缘补充要求或试验应由制造方与用户商定。\n在进行绝缘试验时，如果有必要，则可以对套管端子采取屏蔽措施，但是与套管端子相邻的接地部 分的任何屏蔽应视为运行时变压器的一部分，局部放电试验期间所需要的屏蔽除外。',104,'e2e2f6c6-d6b5-4e44-abe0-04423e84e4ed',163,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.1  绝缘试验的一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27264,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.2  不同类别变压器的绝缘试验项目\n\n变压器的绝缘试验项目是按被试变压器中最高电压绕组 Um 值确定的，试验项目见表 10。',105,'42550085-0d35-4221-b524-d7564fc84105',88,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.2  不同类别变压器的绝缘试验项目"]','TEXT',NULL,'2026-03-11 11:17:43'),(27265,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.2  不同类别变压器的绝缘试验项目\n表 10  不同类别变压器的要求与试验\n<table><tr><td>电压等级</td><td>Um≤72.5kV</td><td colspan=\'2\'>72.5&lt;Um≤170kV</td><td>Um＞170kV</td></tr><tr><td>绝缘类型</td><td>全绝缘</td><td>全绝缘</td><td>分级绝缘</td><td>全绝缘和分级绝缘</td></tr><tr><td>线端雷电冲击试验（LI）</td><td>型式 （包含在LIC中）</td><td>例行</td><td>例行</td><td>例行</td></tr><tr><td>线端雷电冲击截波试验（LIC）</td><td>型式</td><td>型式</td><td>型式</td><td>型式</td></tr><tr><td>中性点端子雷电冲击试验（LIN）</td><td>型式a</td><td>型式a</td><td>型式</td><td>型式</td></tr><tr><td>线端操作冲击试验（SI）</td><td>不适用</td><td>特殊</td><td>特殊</td><td>例行</td></tr><tr><td>外施耐压试验（AV)</td><td>例行</td><td>例行</td><td>例行</td><td>例行</td></tr><tr><td>感应耐压试验（IVW)</td><td>例行</td><td>例行</td><td>例行</td><td>不适用</td></tr><tr><td>带有局部放电测量的感应耐压<br/>试验（IVPD)</td><td>特殊b</td><td>例行b</td><td>例行b</td><td>例行</td></tr><tr><td>线端交流耐压试验（LTAC)</td><td>不适用</td><td>特殊</td><td>例行c</td><td>特殊</td></tr><tr><td>辅助接线的绝缘试验（AuxW)</td><td>例行</td><td>例行</td><td>例行</td><td>例行</td></tr><tr><td colspan=\'5\'>注：如果用户另有要求，不同类别绕组的要求与试验也可参照GB/T 1094.3—2017中E.1的有关规定，但需要在订货合同中注明。</td></tr><tr><td colspan=\'5\'>a对全绝缘的三相变压器，当中性点不引出时，中性点端子雷电全波冲击试验(LIN)为特殊试验。<br/>bIVW的试验要求包括在IVPD试验中，因此只需要一个试验。此外，Um=72.5kV且额定容量为10 000kVA及以上变压器的IVPD试验为例行试验。<br/>C经用户与制造方协商一致，该变压器的LTAC试验可由SI试验代替。</td></tr></table>',106,'520c2cca-9849-4f7a-88ae-6d10c4712b61',726,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.2  不同类别变压器的绝缘试验项目"]','TABLE',NULL,'2026-03-11 11:17:43'),(27266,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.3  绕组的绝缘试验电压水平\n\n根据被试变压器不同种类绕组的 Um 要求确定的试验电压水平见表 11。 所有试验电压均为相电压。\n一般情况下，表 11 中每行给定的值是配合使用的。如果只规定雷电冲击电压水平，那么与雷电冲 击电压水平位于同一行的其它试验电压值将被采用。\nJB/T 501—2021',107,'b5242952-64d2-40a6-a96a-63d926813800',174,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.3  绕组的绝缘试验电压水平"]','TEXT',NULL,'2026-03-11 11:17:43'),(27267,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.3  绕组的绝缘试验电压水平\n表 11  绕组的试验电压水平单位为千伏\n<table><tr><td>系统标称电压<br/>（方均根值）</td><td>设备最高电压Um<br/>（方均根值）</td><td>雷电全波冲击（LI）<br/>（峰值）</td><td>雷电截波冲击（LIC）<br/>（峰值）</td><td>操作冲击（SI）<br/>（峰值）</td><td>外施电压或线端交流电压（AV）或（LTAC）<br/>（方均根值）</td></tr><tr><td>—</td><td>≤1.1</td><td>—</td><td>—</td><td>—</td><td>5</td></tr><tr><td>3</td><td>3.6</td><td>40</td><td>45</td><td> </td><td>18</td></tr><tr><td>6</td><td>7.2</td><td>60</td><td>65</td><td>—</td><td>25</td></tr><tr><td>10</td><td>12</td><td>75</td><td>85</td><td>—</td><td>35</td></tr><tr><td>15</td><td>18</td><td>105</td><td>115</td><td>—</td><td>45</td></tr><tr><td>20</td><td>24</td><td>125</td><td>140</td><td>—</td><td>55</td></tr><tr><td>35</td><td>40.5</td><td>200</td><td>220</td><td>—</td><td>85</td></tr><tr><td>66</td><td>72.5</td><td>325</td><td>360</td><td>—</td><td>140</td></tr><tr><td>110</td><td>126</td><td>480</td><td>530</td><td>395</td><td>200</td></tr><tr><td>220</td><td>252</td><td>850</td><td>950</td><td>650</td><td>360</td></tr></table>',108,'8bfd4534-7e1d-4c2c-bfde-d40c7bc6fc57',494,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.3  绕组的绝缘试验电压水平"]','TABLE',NULL,'2026-03-11 11:17:43'),(27268,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.3  绕组的绝缘试验电压水平\n表 11  绕组的试验电压水平单位为千伏\n<table><tr><td>系统标称电压<br/>（方均根值）</td><td>设备最高电压Um<br/>（方均根值）</td><td>雷电全波冲击（LI）<br/>（峰值）</td><td>雷电截波冲击（LIC）<br/>（峰值）</td><td>操作冲击（SI）<br/>（峰值）</td><td>外施电压或线端交流电压（AV）或（LTAC）<br/>（方均根值）</td></tr><tr><td>—</td><td>≤1.1</td><td>—</td><td>—</td><td>—</td><td>5</td></tr><tr><td>950</td><td>1050</td><td>750</td><td>395</td></tr><tr><td rowspan=\'2\'>330</td><td rowspan=\'2\'>363</td><td>1 050</td><td>1 175</td><td>850</td><td>460</td></tr><tr><td>1 175</td><td>1 300</td><td>950</td><td>510</td></tr><tr><td rowspan=\'2\'>500</td><td rowspan=\'2\'>550</td><td>1 425</td><td>1 550</td><td>1 050</td><td>630</td></tr><tr><td>1 550</td><td>1 675</td><td>1 175</td><td>680</td></tr><tr><td>750</td><td>800</td><td>1 950</td><td>2 100</td><td>1 550</td><td>900</td></tr><tr><td>1 000</td><td>1 100</td><td>2 250</td><td>2 400</td><td>1 800</td><td>1 100</td></tr></table>',109,'364c50eb-1e23-4de9-b6d5-87509802ef1b',462,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.3  绕组的绝缘试验电压水平"]','TABLE',NULL,'2026-03-11 11:17:43'),(27269,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.3  绕组的绝缘试验电压水平\n表 11  绕组的试验电压水平单位为千伏\n<table><tr><td>系统标称电压<br/>（方均根值）</td><td>设备最高电压Um<br/>（方均根值）</td><td>雷电全波冲击（LI）<br/>（峰值）</td><td>雷电截波冲击（LIC）<br/>（峰值）</td><td>操作冲击（SI）<br/>（峰值）</td><td>外施电压或线端交流电压（AV）或（LTAC）<br/>（方均根值）</td></tr><tr><td>—</td><td>≤1.1</td><td>—</td><td>—</td><td>—</td><td>5</td></tr><tr><td colspan=\'6\'>注1： 对于系统标称电压为750 kV 和1 00 0 kV 级的产品，除表中给出的试验电压水平外，制造方与用户可结合具体工 程的实际情况，协商确定其它的试验电压水平。<br/>注 2：如果用户另有要求，则试验电压水平也可按 GB/T 1094.3—2017 中 E.2 有关规定选取 ，但需要在订货合同中 注明。</td></tr></table>',110,'78350456-2afc-45b2-826e-670cb76c092e',363,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.3  绕组的绝缘试验电压水平"]','TABLE',NULL,'2026-03-11 11:17:43'),(27270,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.3  绕组的绝缘试验电压水平\n表 12  分级绝缘变压器中性点端的试验电压水平单位为千伏\n<table><tr><td>系统标称电压<br/>（方均根值）</td><td>中性点端的设备最高电压<br/>Um<br/>（方均根值）</td><td>中性点接地方式</td><td>雷电全波冲击（LI）<br/>（峰值）</td><td>外施电压或线端交流电压（AV）<br/>（方均根值）</td></tr><tr><td rowspan=\'2\'>110</td><td>52</td><td rowspan=\'2\'>不直接接地</td><td>250</td><td>95</td></tr><tr><td>72.5</td><td>325</td><td>140</td></tr><tr><td rowspan=\'2\'>220</td><td>40.5</td><td>直接接地</td><td>185</td><td>85</td></tr><tr><td>126</td><td>不直接接地</td><td>400</td><td>200</td></tr><tr><td rowspan=\'2\'>330</td><td>40.5</td><td>直接接地</td><td>185</td><td>85</td></tr><tr><td>145</td><td>不直接接地</td><td>550</td><td>230</td></tr><tr><td rowspan=\'2\'>500</td><td>40.5</td><td>直接接地</td><td>185</td><td>85</td></tr><tr><td>72.5</td><td>经小阻抗接地</td><td>325</td><td>140</td></tr><tr><td>750</td><td>40.5</td><td>直接接地</td><td>185</td><td>85</td></tr><tr><td rowspan=\'2\'>1 000</td><td>40.5</td><td rowspan=\'2\'>直接接地</td><td>185</td><td>85</td></tr><tr><td>72.5</td><td>325</td><td>140</td></tr></table>',111,'bc272cc3-d072-42a5-a126-81fb8cf9a0b7',468,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.3  绕组的绝缘试验电压水平"]','TABLE',NULL,'2026-03-11 11:17:43'),(27271,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.3  绕组的绝缘试验电压水平\n表 12  分级绝缘变压器中性点端的试验电压水平单位为千伏\n<table><tr><td>系统标称电压<br/>（方均根值）</td><td>中性点端的设备最高电压<br/>Um<br/>（方均根值）</td><td>中性点接地方式</td><td>雷电全波冲击（LI）<br/>（峰值）</td><td>外施电压或线端交流电压（AV）<br/>（方均根值）</td></tr><tr><td colspan=\'5\'>注 1 ：表中 U m =52 和 U m =145 是参照 GB/T 1094.3—2017 中 E.2 的有关规定确定的。用户也可参照 GB/T 1094.3—2017 中<br/>E.2 的有关规定，另行确定中性点端的设备最高电压及相应的试验电压水平，但需要在订货合同中注明。<br/>注 2 ：其它中性点端 U m 的标准值可由用 户规定（可参考 GB/T 1094.3 — 2017 中附录 E 的有关规定通过计算确定）。</td></tr></table>',112,'004dfc7d-d402-4329-ac9e-21c66c634736',374,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.3  绕组的绝缘试验电压水平"]','TABLE',NULL,'2026-03-11 11:17:43'),(27272,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.4  辅助接线的绝缘试验（AuxW)\n\n辅助电源和控制线路的接线应承受 2kV（方均根值）、1min 交流外施电压的对地耐压试验，如果电 压没有突然下降或没有其它击穿特征，则表明通过了试验。\n电流互感器二次绕组接线应进行 2.5kV（方均根值）、1min 交流外施电压的对地耐压试验，如果互 感器的拐点电压超过交流 2kV，那么试验应在交流 4kV 进行。如果电压没有突然下降或没有其它击穿特 征，则表明通过了试验。\n辅助设备用的电机和其它二次原件的绝缘要求应符合产品技术条件的规定。所有固态、基于微处理 器的设备将不连接在试验线路中。所有三相继电器和可拆卸设备应从试验线路中拆除。',113,'995682ca-53fd-4c18-a420-684591604c89',317,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.4  辅助接线的绝缘试验（AuxW)"]','TEXT',NULL,'2026-03-11 11:17:43'),(27273,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.5.1  试验前的准备\n\n被试品铁心、夹件引出接线端子应可靠接地。 被试品油箱应可靠接地。\n对装有放气塞的套管升高座、低压接线盒、穿缆式套管及有载分接开关均应放气，直到溢油为止。',114,'386d4801-815f-432d-bb8c-18ac0bc3f18e',115,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.5.1  试验前的准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27274,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.5.2  试验一般要求\n\n外施耐压试验的频率应为不低于 80%额定频率的任意一合适频率，取峰值电压除以  作为试验电 压。电压的波形应接近正弦波，即峰值除以 ·2 与方均根值的偏差不大于 5%。\n施加试验电压的允许偏差为±1%。\nJB/T 501—2021',115,'f20b0428-ef19-4750-95da-7309d74febdf',153,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.5.2  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27275,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.5.3  测量系统的不确定度\n\n电压测量系统的不确定度为±3%。',116,'7b696639-3749-47cd-800a-a9ba63f1ad2a',58,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.5.3  测量系统的不确定度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27276,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.5.4.1  试验接线示意图\n\n外施耐压典型接线示意图（以试验高压绕组为例）见图 7。\n图 7  外施耐压试验典型接线示意图',117,'a6beff65-72d4-4d99-be66-ec0b09d51808',87,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.5.4.1  试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27277,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.5.4.2  施加电压程序和方法\n\n试验应从不大于规定试验电压值的 1/3 电压开始，并与测量相配合尽快地增加到试验电压值，在规 定试验电压下持续 1min 时间，试验完毕，应将电压迅速地降到 1/3 规定试验电压值以下，并切断电源。',118,'224b9873-31b3-47ae-8d4b-556cd58260ae',143,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.5.4.2  施加电压程序和方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27278,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.5.5  结果判定\n\n试验过程中，如果电压不突然下降，则认为试验合格；',119,'2d734064-af6d-4edb-bfcf-1d84d2360f94',61,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.5.5  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27279,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.6.1  试验前的准备\n\n见 3.10.5.1。',120,'b35b0f8b-f6f2-4a47-80ab-00377cd216b7',50,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.6.1  试验前的准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27280,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.6.2  试验一般要求\n\n中性点和其它正常运行情况下处于地电位的端子应接地。\n三相变压器应使用三相对称电压加压。任何不与试验电源相连的线路端子应开路。 带分接的绕组，除非特别指定或由用户同意，一般在主分接进行。\n施加的相对地试验电压为（2×Ur ）/  3 （Ur 为绕组额定电压）。\n电压的波形应接近正弦波，试验中电压的峰值与方均根值都应测量，取电压峰值除以  2 与方均根\n值两者间的较小值作为试验电压值。\n试验电压应在最高电压端子上测量，如果不可行，则应在与电源相连的端子上测量。可以在 50%~ 80%的试验电压下进行校正，同时记录被试品励磁侧的试验电压。外推出最高电压端子在 100%试验电压\nJB/T 501—2021\n时的被试品励磁侧的试验电压。\n试验时间在 60s 以内的试验电压的允许偏差为±1%。如果试验持续时间超过 60s，则在整个试验过 程中试验电压的测量值应保持在规定电压的±3%以内。',121,'456c44d7-efa8-4999-a23a-7b3a428221be',430,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.6.2  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27281,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.6.3  测量系统的不确定度\n\n测量系统的不确定度为±3%。',122,'ec30ea19-544b-492c-91a6-773c5d8c74e5',56,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.6.3  测量系统的不确定度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27282,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.6.4.1  试验接线示意图\n\n感应耐压试验典型接线示意图（以联结组标号为 YNyn0d11 的三绕组变压器为例）见图 8。\n图 8  感应耐压试验典型接线示意图',123,'48332b6a-cf78-42f0-b62a-41bb1083c14c',106,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.6.4.1  试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27283,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.6.4.2  施加电压的程序和方法\n\n为了防止试验时励磁电流过大，试验电压频率应适当地比额定频率高。对于某些产品，励磁电流可 能呈现容性电流，为了防止发电机自励磁现象发生，可以在励磁线路中并联补偿电抗器。\n除非另有规定，当试验电压的频率等于或小于两倍额定频率时，其全电压下的试验时间应为 60s。 当试验频率超过两倍额定频率时，试验时间为：120×额定频率/试验频率，但不少于 15s。\n试验应从不大于规定试验电压值的 1/3 电压开始，并与测量相配合尽快地增加到试验电压值（相对\n地试验电压为(2×Ur)/  3 ），在规定试验电压下持续到规定时间，试验完毕，应将电压迅速地降到 1/3 规定试验电压值以下，并切断电源。',124,'790e6152-36b8-454a-aea1-3e77cd54c11c',336,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.6.4.2  施加电压的程序和方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27284,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.6.5  结果判定\n\n试验过程中，如果电压不出现突然下降，则试验合格。',125,'61491034-6611-4d28-ab87-07b6b2f2860c',61,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.6.5  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27285,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.7  带有局部放电测量的感应电压试验（IVPD）\n\nJB/T 501—2021',126,'bc8bdd12-d867-48b4-a21f-858f3068afff',65,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.7  带有局部放电测量的感应电压试验（IVPD）"]','TEXT',NULL,'2026-03-11 11:17:43'),(27286,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.7.1  试验前的准备\n\n见 3.10.5.1。',127,'f567ae51-fbfc-4a4b-98bc-a9d59ad98c39',50,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.7.1  试验前的准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27287,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.7.2  试验一般要求\n\n中性点和其它正常运行情况下处于地电位的端子应接地。\n三相变压器应使用三相对称电压加压。任何不与试验电源相连的线路端子应开路。 带分接的绕组，除非特别指定或由用户同意，一般在主分接进行。\n为了避免由于容升电压和电压波形畸变而影响试验电压，试验电压应在最高电压端子上测量，如果 不可行，则应在与电源相连的端子上测量。可以在 50%～80%的试验电压下进行校正， 同时记录被试品 励磁侧的试验电压，外推出最高电压端子在 100%试验电压时的被试品励磁侧的试验电压。在甩掉高压 测量系统后进行局部放电测量时，可以采用外推的被试品励磁侧的试验电压对被试品施加试验电压。\n电压的波形应接近正弦波，试验中电压的峰值与方均根值都应测量，取峰值除以  2 与方均根值两\n者间的较小值作为试验电压值。\n试验时间在 60s 以内的试验电压的允许偏差为±1%。如果试验持续时间超过 60s，则在整个试验过 程中试验电压的测量值应保持在规定电压的±3%以内。',128,'8e72cfea-2964-4efa-a067-3f32208fa57d',454,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.7.2  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27288,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.7.3  测量系统的不确定度\n\n工频测量系统的不确定度为±3%。\n局部放电测量系统的不确定度为±10%。',129,'cd719401-5832-4407-bcb3-8ba83b1975a9',78,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.7.3  测量系统的不确定度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27289,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.7.4.1  带有局部放电测量的感应电压试验接线示意图\n\n带有局部放电测量的感应电压试验接线示意图见图 9（以联结组标号为 YNyn0d11 的三绕组变压器 为例）。\n图 9  带有局部放电测量的感应电压试验接线示意图\nJB/T 501—2021',130,'0dcb57bc-90c2-408a-8abe-9bda3fcc3a66',148,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.7.4.1  带有局部放电测量的感应电压试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27290,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.7.4.2  施加电压的程序和方法\n\n除非另有规定，当试验电压的频率等于或小于2倍额定频率时，对于Um≤800kV的变压器，其增强电 压下的试验时间应为60s，对于Um>800kV的变压器，其增强电压下的试验时间应为300s，当试验频率超 过2倍额定频率时，试验时间为：\n120×额定频率/试验频率（s)，但不少于 15s(Um≤800kV) 或\n600×额定频率/试验频率（s)，但不少于 75s(Um>800kV) 试验顺序如下:\n—— 在不大于（0.4×Ur ）/  的电压下接通电源；\n—— 试验电压升高至（0.4×Ur ）/  ， 进行背景 PD 测量并记录； —— 试验电压升高至（1.2×Ur ）/  ；\n—— 测量并记录 PD 水平；\n—— 试验电压升高至 1h 的 PD 测量电压，保持至少 5min 钟以进行稳定的 PD 测量； —— 测量并记录 PD 水平；\n—— 电压上升至增强电压，保持规定时间；\n—— 之后立刻不间断地将电压降至 1h 的 PD 测量电压； —— 测量并记录 PD 水平；\n—— 保持 1h 的 PD 测量电压至少 1h，并进行 PD 测量； —— 在 1h 内每隔 5min 测量并记录 PD 水平；\n—— 1h 的 PD 测量最后一次测量完毕后，降低电压至（1.2×Ur）/  ，保持至少 1min 以进行稳定 的PD测量；\n—— 测量并记录 PD 水平；\n—— 测量电压降至（0.4×Ur ）/  ， 进行背景 PD 测量并记录； —— 试验电压降至（0.4×Ur ）/   以下；\n—— 切断电源。\n增强电压为（1.8×Ur ）/  ， 对于Um ≤170kV的产品，当增强电压采用（2×Ur ）/  时，本试验可 以代替感应耐压试验（IVW）。\n试验顺序主要特征见图10。\n图 10  带有局部放电测量的感应电压试验施加电压的时间顺序\n经用户与制造方协商，对于Um ≤72.5kV的产品PD测量电压可持续较短的时间，推荐时间为5min。\n如果用户要求，则可采用较高的电压水平，此时，增强电压（相对地）按(  ×Um ）/  ， 局部放 电测量电压按（1.5×Um ）/-',131,'e7f6997b-b4a8-44a7-bbfb-369f8c0825a1',926,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.7.4.2  施加电压的程序和方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27291,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.7.4.3  局部放电测量方法\n\nJB/T 501—2021\n局部放电测量前应对包括套管和电容耦合器在内的每个 PD 测量通道按照视在电荷法（pC）进行校 正。\nPD 测量结果用 pC 给出，应参考测量仪器指示的最高稳态重复脉冲而得出。 偶然出现的高幅值局部放电脉冲可以不计入。\n试验期间对于所有 Um ≥72.5kV 的套管出线端子均要进行局部放电测量并记录，除非特别指定，对 于超过 6 个这样出线端子时仅需测量并记录 6 个出线端子（依最高电压线端排序）的局部放电测量。\n整个测量时间内至少能在一个测量通道连续观测到局部放电水平。 更详细的局部放电测量技术见 GB/T 7354。',132,'710db53b-177b-4c7c-a81d-5524f42cc3d8',319,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.7.4.3  局部放电测量方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27292,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.7.5  结果和判定\n\n在试验开始和结束时测得的 PD 背景噪声均没有超过 50pC 时试验方有效。 如果满足下列判据则试验合格：\na)  试验电压不产生突然下降；\nb)  在 1h 局部放电试验期间，没有超过 250pC 的局部放电记录；\nc)  在 1h 局部放电试验期间，局部放电水平无上升趋势；在最后 20min 局放水平无突然持续增加；\nd)  在 1h 局部放电试验期间，局部放电水平的增加量不超过 50pC；\ne)  1h 局部放电测量后电压降至（1.2×Ur ）/  3 时测量的局部放电水平不超过 100pC。\n如果判据 c)项或 d)项不满足，则可以延长 1h 测量时间，如果在后续的连续 1h 内满足上述条件， 则可以认为合格。',133,'32842674-5a13-45de-b3d3-ca325bf16df3',345,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.7.5  结果和判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27293,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.8.1  试验前的准备\n\n被试品铁心、夹件引出接线端子应可靠接地；被试品油箱应可靠接地；对装有放气塞的套管升高座、 低压接线盒、穿缆式套管及有载分接开关均应放气，直到溢油为止。',134,'1dc08f2e-8fd4-46c1-873f-64342f853910',114,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.8.1  试验前的准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27294,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.8.2  试验一般要求\n\n本试验的目的是考核分级绝缘绕组每个线端对地的耐压试验，而不以相间和匝间的电压试验为目 的。该项试验是对操作冲击试验的有效补充。\n对于带分接绕组的变压器，应选择合适的分接使被试绕组产生所要求的电压，其它绕组端子出现的 电压尽可能接近于所要求的试验电压值。\n受试验设备和产品结构限制时，较低电压绕组端子承受的试验电压不应比规定电压低 8%。 如果无其它规定，则分接位置和感应倍数由制造方确定。\n电压的波形应接近正弦波，试验中电压的峰值与方均根值都应测量，取峰值除以  2 作为试验电压。\n试验电压应在最高电压端子上测量，如果不可行（如受外绝缘距离和高压绝缘系统绝缘限值），则 应在与电源相连的端子上测量。可以在 50%～80%的试验电压下进行校正， 同时记录被试品励磁侧的试 验电压，外推出最高电压端子在 100%试验电压时的被试品励磁侧的试验电压。在甩掉高压测量系统后， 可以采用外推的被试品励磁侧的试验电压对被试品施加试验电压。\n试验电压的允许偏差为±1%。',135,'d80e30b0-e594-477a-9cf7-2a3be854b0ff',467,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.8.2  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27295,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.8.3  测量系统的不确定度\n\nJB/T 501—2021\n工频测量系统的不确定度为±3%。',136,'46950136-f842-487a-b626-8b1c1d2137e6',72,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.8.3  测量系统的不确定度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27296,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.8.4.1  接线示意图\n\n当被试变压器的中性点的绝缘水平大于线端绝缘水平的 1/3 时，典型的试验方法为非被试验相支撑 法，图 11 为联结组标号为 YNyn0d11 的三相三绕组变压器（试验 A 相时）的典型接线示意图。\n图 11  三相三绕组变压器线端交流耐压试验典型接线示意图\n单相变压器进行试验时，为了使被试变压器的感应倍数不超过 2 倍， 同时使具有较低 Um 电压的绕 组线端尽可能接近试验电压，典型的试验方法是采用中性点外接支撑电位的方法，见图 12 所示。\n图 12  单相变压器中性点外接支撑电位的线端交流耐压试验典型接线示意图',137,'9a496bd6-2cb5-4088-85b7-7f01c554214c',298,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.8.4.1  接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27297,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.8.4.2  施加电压的程序和方法\n\n除非另有规定，当试验电压的频率等于或小于 2 倍额定频率时，试验时间为：\nJB/T 501—2021\n120×额定频率/试验频率（s)，但不少于 15s\n试验应在不大于规定电压的 1/3 电压下接通电源，并与测量相配合尽快升至试验电压值。施加电压 达到规定时间后，应将电压迅速降至试验电压 1/3 下，然后切断电源。',138,'94112052-f53b-463c-86a0-13bd791bef9d',203,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.8.4.2  施加电压的程序和方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27298,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.8.5  结果和判定\n\n如果试验电压不出现突然下降，则试验合格。',139,'e651ebcb-86c2-4796-9c3f-e8cc6361ee82',58,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.8.5  结果和判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27299,508,'## 3  油浸式电力变压器试验\n### 3.10  绝缘试验\n#### 3.10.9  操作冲击和雷电冲击试验\n\n操作冲击和雷电冲击试验按GB/T 1094.4的规定进行。',140,'46807d14-787f-4bc2-ac7f-b7d5046ab800',71,NULL,'["3  油浸式电力变压器试验", "3.10  绝缘试验", "3.10.9  操作冲击和雷电冲击试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27300,508,'## 3  油浸式电力变压器试验\n### 3.11  有载分接开关试验（适用于有载调压变压器）\n#### 3.11.1  操作试验\n\n在变压器完成装配后，有载分接开关应承受如下顺序的操作试验，且不应发生故障：\n——变压器不励磁，完成 8 个操作循环（一个操作循环是从分接范围的一端到另一端，并返回到原 始位置）；\n——变压器不励磁，且操作电压降到额定值 85%时，完成一个操作循环； ——变压器在额定频率、额定电压下空载励磁时, 完成一个操作循环；\n——将变压器的一个绕组短路，并尽可能使分接绕组中的电流达到额定值，在粗调选择器或极性选 择器操作位置处或中间分接每一侧的两个分接范围内，完成 10 次分接变换操作（分接开关经 过转换位置 20 次）；\n——对于大型变压器受设备容量的限制，如果不能完成在粗调选择器或极性选择器操作位置处或中 间分接每一侧的两个分接范围内的分接转换，则允许分段进行，但分接开关经过转换位置应为 20 次。',141,'2342c831-fac8-44d6-9dea-c238aabc8168',401,NULL,'["3  油浸式电力变压器试验", "3.11  有载分接开关试验（适用于有载调压变压器）", "3.11.1  操作试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27301,508,'## 3  油浸式电力变压器试验\n### 3.11  有载分接开关试验（适用于有载调压变压器）\n#### 3.11.2  安装在变压器本体上的有载分接开关密封试验\n\n本试验可结合变压器本体的压力密封试验进行，对分接开关施加比油箱顶层压力高20kPa的压力， 持续24h，分接开关表面应无渗漏，压力表的指示降低应不超过70%。',142,'26bdf68f-4b98-433c-94ac-d969b43f5e13',146,NULL,'["3  油浸式电力变压器试验", "3.11  有载分接开关试验（适用于有载调压变压器）", "3.11.2  安装在变压器本体上的有载分接开关密封试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27302,508,'## 3  油浸式电力变压器试验\n### 3.12  压力密封试验\n#### 3.12.1  一般要求\n\n压力密封试验应在装配完毕的产品上进行，对于可拆卸的储油柜、净油器、散热器或冷却器可单独 进行。对于拆卸运输的变压器一般进行两次密封试验，第一次是在变压器装配完毕，且装全所有充油组 件后进行的；第二次是在变压器拆卸外部组部件、在运输状态下对变压器本体进行的。压力以最高油面 为基准施加。',143,'76c9feda-e821-4d44-84ec-d8c28bb97968',179,NULL,'["3  油浸式电力变压器试验", "3.12  压力密封试验", "3.12.1  一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27303,508,'## 3  油浸式电力变压器试验\n### 3.12  压力密封试验\n#### 3.12.2  试验目的\n\n检测变压器油箱和充油组部件本体及装配部位的密封性能，防止运行时渗漏油的发生，以及防止变 压器主体在运输时的漏气、漏油或因进水而引起的变压器受潮。',144,'5bcda51a-441e-4072-9eb1-e10c6dec3981',109,NULL,'["3  油浸式电力变压器试验", "3.12  压力密封试验", "3.12.2  试验目的"]','TEXT',NULL,'2026-03-11 11:17:43'),(27304,508,'## 3  油浸式电力变压器试验\n### 3.12  压力密封试验\n#### 3.12.3.1  试验准备\n\nJB/T 501—2021\n试验前连接好试验管路、紧固试漏系统的所有紧固件，安装好压力表，并擦净油箱及充油组部件的 外表面，以便在试漏过程中观察渗漏油情况。打开注油系统通向变压器及变压器组部件之间连接的所有 阀门，并打开吸湿器连管的盖板（中小型变压器打开储油柜上部放气塞），向变压器内注入变压器油至 规定油面高度。',145,'a2ece822-73ff-4bf6-a67e-f2000398239e',196,NULL,'["3  油浸式电力变压器试验", "3.12  压力密封试验", "3.12.3.1  试验准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27305,508,'## 3  油浸式电力变压器试验\n### 3.12  压力密封试验\n#### 3.12.3.2  装全所有充油组部件的密封试验\n\n3.12.3.2.1  吊罐油柱法：利用吊罐油柱的静压力来达到要求的试漏压力的方法。\n从油箱底部连接好吊罐，关闭储油柜与油箱间的阀门，打开吊罐与油箱间的所有阀门，利用垂直的 吊罐油面压力给变压器油箱及组部件施加一个静压力； 吊罐油柱的高度由试漏压力计得出。\n3.12.3.2.2  充气加压法：利用向储油柜胶囊内或储油柜油面上充入一定压力的干燥气体来达到要求的 试漏压力的方法。\n将储油柜内油面调整到规定高度，通过吸湿器联管上安装的充气装置或在储油柜放气塞外装的气  门，向储油柜的胶囊内或储油柜内充入干燥空气或氮气，通过压力传递向油箱及组部件施加油压；注意 充气速度不要过快，当压力表指示达到规定值时关闭阀门。',146,'c8f56756-5b98-4db4-b151-8d3ea2201044',352,NULL,'["3  油浸式电力变压器试验", "3.12  压力密封试验", "3.12.3.2  装全所有充油组部件的密封试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27306,508,'## 3  油浸式电力变压器试验\n### 3.12  压力密封试验\n#### 3.12.3.3  试漏压力及持续时间\n\n试漏压力及持续时间应符合GB/T 6451或GB/T 1094.1的规定或按用户要求，但最后一次补漏后的试 漏时间不得少于试漏规定总时间的1/3，应注意油箱底部所受压力一般不要超过油箱所能承受的压力值。',147,'426202be-7582-459b-85a2-ea1dcff92b29',145,NULL,'["3  油浸式电力变压器试验", "3.12  压力密封试验", "3.12.3.3  试漏压力及持续时间"]','TEXT',NULL,'2026-03-11 11:17:43'),(27307,508,'## 3  油浸式电力变压器试验\n### 3.12  压力密封试验\n#### 3.12.3.4  试验结果的判定\n\n试验过程中要随时检查压力表的压力是否下降，油箱及其充油组部件表面是否渗漏油，重点检查可 漏焊缝和密封面的渗漏油情况。如果符合GB/T 6451的规定，则判定该变压器密封试验合格。',148,'25fbb605-1014-4241-9aae-e8cb43a078fb',131,NULL,'["3  油浸式电力变压器试验", "3.12  压力密封试验", "3.12.3.4  试验结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27308,508,'## 3  油浸式电力变压器试验\n### 3.13  内装电流互感器变比和极性试验\n\n本试验的目的是检查内装电流互感器的二次接线位置是否正确。试验可采用CT测试仪或变比测试 仪。对于精度的要求应能够定性的检查电流互感器的变比和极性。\n对所有内装的电流互感器的变比和极性进行检查。 检查的结果应与铭牌标称一致。',149,'2a2ca2e0-3dc3-43c4-8c28-c6021503092d',144,NULL,'["3  油浸式电力变压器试验", "3.13  内装电流互感器变比和极性试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27309,508,'## 3  油浸式电力变压器试验\n### 3.14  铁心和夹件绝缘检查\n\n本项试验通常与绕组对地及绕组间直流绝缘电阻测量一同进行。试验见3.9。',150,'07883816-7f8c-40dd-90f7-b486be38322f',63,NULL,'["3  油浸式电力变压器试验", "3.14  铁心和夹件绝缘检查"]','TEXT',NULL,'2026-03-11 11:17:43'),(27310,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.1  试验一般要求\n\n试验应在湿度小于 85％、环境温度（被试品温度）为 5℃~40℃并尽可能在 20℃左右进行。\n电压等级为 35kV、额定容量为 8000kVA 及以上的变压器及电压等级高于 35kV 的变压器应进行本项 试验。',151,'7db5b8b4-cd18-44cb-a978-4be3ab0723dc',150,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27311,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.2  试验前的准备\n\n被试品油箱及测量仪器接地端应牢固接地，被试品应放气，并应接地放电。如果铁心和夹件单独 引出时，则应将引出端子可靠接地。\nJB/T 501—2021',152,'f342c830-7bc6-4a0b-ac47-f8ec8fa996de',118,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.2  试验前的准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27312,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.3  测量仪器和精度\n\n测量仪器可采用西林电桥或介质损耗测试仪，精度不低于 2%。',153,'38f51bcd-8725-4d3a-83dd-c3f7d0487b75',75,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.3  测量仪器和精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27313,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.4.1  试验接线示意图\n\n绕组对地电容测量接线示意图（“反接”法）见图13。\n图 13  绕组对地电容测量接线示意图（“反接”法）',154,'7c2c8aa8-493b-4366-96f4-d4da51315795',99,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.4.1  试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27314,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.4.2  测量方式组合\n\n双绕组变压器的测量组合方式应不少于表 13 的规定。',155,'6e234d13-b740-45ae-85f2-ce4ddc930879',73,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.4.2  测量方式组合"]','TEXT',NULL,'2026-03-11 11:17:43'),(27315,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.4.2  测量方式组合\n表 13  双绕组变压器绕组对地和绕组间电容测量组合方式\n<table><tr><td>序号</td><td>被试绕组</td><td>接地部位</td><td>测量方法</td></tr><tr><td>1</td><td>高压</td><td>低压、铁心、夹件及油箱</td><td rowspan=\'3\'>“反接”法</td></tr><tr><td>2</td><td>低压</td><td>高压、铁心、夹件及油箱</td></tr><tr><td>3</td><td>高压及低压</td><td>铁心、夹件及油箱</td></tr></table>',156,'add6db5a-ef89-42b8-b0c1-36f4843a1fa3',177,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.4.2  测量方式组合"]','TABLE',NULL,'2026-03-11 11:17:43'),(27316,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.4.2  测量方式组合\n\n三绕组变压器的测量组合方式应不少于表 14 规定。',157,'955fe59c-1b8a-43ca-ac30-42fe1456f5f8',72,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.4.2  测量方式组合"]','TEXT',NULL,'2026-03-11 11:17:43'),(27317,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.4.2  测量方式组合\n表 14  三绕组变压器绕组对地和绕组间电容测量组合方式\n<table><tr><td>序号</td><td>被试绕组</td><td>接地部位</td><td>测量方法</td></tr><tr><td>1</td><td>高压</td><td>中压、低压及、铁心、夹件及油箱</td><td rowspan=\'5\'>“反接”法</td></tr><tr><td>2</td><td>中压</td><td>高压、低压、铁心、夹件及油箱</td></tr><tr><td>3</td><td>低压</td><td>高压、中压、铁心、夹件及油箱</td></tr><tr><td>4</td><td>高压及中压</td><td>低压、铁心、夹件及油箱</td></tr><tr><td>5</td><td>高压、中压及低压</td><td>铁心、夹件及油箱</td></tr></table>',158,'8c63d9cb-f8d7-42eb-9898-0ca043807f99',239,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.4.2  测量方式组合"]','TABLE',NULL,'2026-03-11 11:17:43'),(27318,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.4.3  测量电压的选取\n\n被试绕组为 10kV 及以上时，测量电压选用 10kV；被试绕组为 10kV 以下时，测量电压选用接近额 定电压。',159,'21828ba6-70a2-4be9-b006-9c43dda5b221',105,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.4.3  测量电压的选取"]','TEXT',NULL,'2026-03-11 11:17:43'),(27319,508,'## 3  油浸式电力变压器试验\n### 3.15  绕组对地和绕组间电容测量\n#### 3.15.5  结果的判定\n\nJB/T 501—2021\n应提供实测值。\n结果的判定按照技术协议的规定。',160,'8680aaf0-a6e8-4257-a74f-1864a8bda572',81,NULL,'["3  油浸式电力变压器试验", "3.15  绕组对地和绕组间电容测量", "3.15.5  结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27320,508,'## 3  油浸式电力变压器试验\n### 3.16  绝缘系统电容的介质损耗因数（tanδ) 测量\n#### 3.16.1  试验方法\n\n本项试验与绕组对地和绕组间的电容测量一起完成。试验要求见3.15。',161,'864dc16e-d226-46ce-b8e5-2c57c9c9fb17',86,NULL,'["3  油浸式电力变压器试验", "3.16  绝缘系统电容的介质损耗因数（tanδ) 测量", "3.16.1  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27321,508,'## 3  油浸式电力变压器试验\n### 3.16  绝缘系统电容的介质损耗因数（tanδ) 测量\n#### 3.16.2  结果的判定\n\n测试结果的判定条件如下：\n——应尽可能在同一温度下比较 tanδ值； ——符合技术协议规定；\n——提供实测值。',162,'8d4f2a02-7c7d-4bc1-855b-becf7d794bed',109,NULL,'["3  油浸式电力变压器试验", "3.16  绝缘系统电容的介质损耗因数（tanδ) 测量", "3.16.2  结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27322,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.1  试验前准备\n\n被试品绝缘油面应处于合适的位置。\n被试品周围不得有墙壁、热源、堆积物及外来辐射气流等干扰。 被试品铁心、夹件引出接线端子应可靠接地。\n被试品油箱应可靠接地。\n对装有放气塞的套管升高座、低压接线盒、套管、冷却系统及有载分接开关均应放气，直到溢油为 止。\n应确认油泵、风机旋转方向是否正确。\n应确认分接开关的位置是否正确。 应布置温度传感器。\n应按照 3.5 的要求测量冷电阻。',163,'33971409-4f0a-4665-8ea4-e6456297b705',223,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.1  试验前准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27323,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.2  试验一般要求\n\n测定稳态温升的标准方法是采用短路接线的等效试验方法。 按照协议也可采用“直接负载法”和“相互负载法”。\n试验温度应介于 5℃与变压器设计所依据的最高环境温度之间。\n冷却水的温度应介于 5℃与变压器设计所依据的最高冷却水温度之间。\n对于分接范围不超过±5%，且额定容量不超过 2500kVA（单相 833kVA）的变压器，在主分接下进行 温升试验。\n对于分接范围超过±5%的变压器，或额定容量超过 2500kVA（单相 833kVA）的变压器，试验时施加 的总损耗应是最大总损耗分接下的损耗，在第二阶段施加的电流，应是最大电流分接的电流。\n如果变压器具有多个额定容量值（两种或多种冷却方式），则原则上温升试验应在每个额定容量下 进行，但经制造方与用户协商同意，试验的数量可以减少。\n对于多绕组变压器，当一个绕组的额定容量等于其余绕组的容量之和时，其温升要求是指所有绕组 均同时在各自额定负载下的。如果情况不是这样，则应选定一种或多种特定的组合，并规定相应的温升 限值。\n多绕组变压器的损耗按 GB/T 13499 的规定进行计算。\nJB/T 501—2021\n对于三相变压器，绕组平均温升测量应包含中间相绕组。对于星接、低电压且大电流绕组，应测量 线路端子间的电阻， 以排除中性点引线对于绕组平均温升测量的影响。',164,'55099ded-0577-4a71-a873-c42a648f488a',592,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.2  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27324,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.3  主要测量仪器和精度\n\n主要测量仪器和精度如下：\n——电压互感器和电流互感器：中型以下变压器推荐采用不低于 0.2 级，大型变压器推荐采用不低 于 0.05 级；\n——功率分析仪或类似仪器： 在测量的功率因数下推荐采用不低于 0.5 级； ——温度测试仪：推荐采用测量偏差不大于±0.5℃;\n——直流电阻测试仪：推荐采用不低于 0.2 级。',165,'a1abca23-34ef-4b83-8517-94df9855ebd7',198,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.3  主要测量仪器和精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27325,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.4  接线示意图\n\n接线示意图与“短路阻抗和负载损耗测量”的接线示意图相同。',166,'54b593d1-c802-4513-8f59-935be990e815',64,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.4  接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27326,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.1  概述\n\n试验分下面两个阶段进行：\n——施加总损耗（试验第一阶段）：本阶段可以测定顶层液体温升和液体平均温升，试验中，应当 监测顶层液体和冷却介质的温度，试验需持续进行，直到液体的温升稳定为止。当顶层液体温 升的变化率小于 1K/h，并至少维持 3h，本试验阶段可以结束；\n——施加额定电流（试验第二阶段）：顶层液体温升测定之后，应立即将试验电流降至额定电流继 续试验。持续1h，在此期间应至少每间隔5min记录一次顶层液体、绕组热点（如果测量）和外 部冷却介质温度，并连续记录。施加1h（如果要求进行油箱表面热点温升测量，则应在此试验 阶段结束前测量）结束时，应迅速切断电源和打开短路接线测量绕组的电阻。如果电阻测量失 败，或需要对其它的绕组进行电阻测量，则可重复上述过程。',167,'92e21574-9bdc-4255-858b-4fe511c40cff',368,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27327,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.2.1  环境温度的测量\n\n温度传感器或温度计在试品周围不少于 4 个，大型变压器（额定容量不小于 100MVA)不少于 6 个。 对于 ONAN 变压器，其周围的环境温度传感器应放置在冷却表面高度约一半的位置处。\n传感器应沿油箱四周分布，距油箱和冷却表面 2m，高度为冷却表面高度的一半，应避免直接受热 辐射的影响。为了防止由空气湍流而引起剧烈的温度变化，应为温度传感器配备与变压器时间常数近似 的适当吸热容器。\n对于强迫风冷变压器，温度传感器应放置在距冷却器进风口处约 0.5m 的位置。',168,'452d68d4-e898-43bd-a8be-decabe7d30bf',274,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.2.1  环境温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27328,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.2.2  冷却水温度\n\n冷却水温变化应尽量小，测量冷却器入口温度，定期记录水温和水的流量。',169,'0a445897-7ed9-4c66-b420-02f35cadd3b2',73,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.2.2  冷却水温度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27329,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.3.1  顶层油温度的测量\n\n顶层油的温度测量是用 1 个或多个浸入油箱内顶层液体中的温度传感器或箱盖上的传感器座中的\nJB/T 501—2021\n温度传感器测定的，传感器数量规定如下：\n——额定容量不小于 100MVA：3 个；\n——额定容量从 20MVA 至小于 100MVA：2 个； ——额定容量小于 20MVA ：1 个。\n如果传感器的数量大于 1，则取温度读数的平均值。',170,'8ed03744-60a9-46ac-9f81-2b1c7d15daec',219,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.3.1  顶层油温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27330,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.3.2  底部油温度的测量\n\n底部油温度是用置于散热器（或冷却器）回到油箱中的油联管处的传感器来测定的。 如果装有几组散热器（或冷却器），则应用多个传感器来测量。',171,'1aad8e4c-8296-45ba-9e60-368096324502',109,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.3.2  底部油温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27331,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.3.3  油平均温度的测量\n\n油平均温度是顶层油温度与底部油温度的平均值。',172,'79131bfe-f0ee-4654-af4e-57d4c39730d6',65,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.3.3  油平均温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27332,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.4.1  顶层液体温升、液体平均温升计算\n\n顶层液体温升按式（5）计算：\nΔθo=θo-θa   ................................................................................ (5)\n式中：\nΔθo ：——顶层液体温升；\nθo ——施加总损耗结束时测得的顶层液体温度；\nθa  ——施加总损耗结束时测得的外部冷却介质温度。 液体平均温升计算按式（6）计算：\nΔθom=θom-θa ............................................................................... (6)\n式中：\nΔθom ——液体平均温升；\nθom ——施加总损耗结束时计算的液体平均温度；\nθa ——施加总损耗结束时测得的外部冷却介质温度。',173,'189c7104-e23a-4438-9987-ec9ec45cc0f5',411,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.4.1  顶层液体温升、液体平均温升计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27333,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.4.2  绕组平均温度的计算\n\n根据测量绕组的电阻值，可按式（7）或式（8）计算绕组平均温度：\n- 235    （对于铜）......................................................... (7)\n- 225    （对于铝）......................................................... (8)\n式中：\nθ1 ——稳定的环境温度下的绕组温度；\nθ2 ——电源断开瞬间的绕组平均温度；\nJB/T 501—2021\nR1 ——稳定环境温度下的绕组电阻值；\nR2 ——用断开电源后测得的绕组电阻值外推到断开电源瞬间的绕组电阻值。',174,'65913cff-0abd-4e8e-a11c-7b84ee2e9587',335,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.4.2  绕组平均温度的计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27334,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.5  电源断开瞬间的绕组电阻测定\n\n测量电源断开瞬间的绕组电阻时的冷却系统运行方式宜与产品温升试验时一致。\n尽可能减少断开试验线路与接通电阻测量电路的时间，并合理选择电路参数以减少电气时间常数， 以便尽快测量出第一个有效的绕组热电阻值。对于额定容量小于 100MVA 的变压器，测得的第一个有 效的绕组热电阻值不宜超过 2min；对于额定容量不小于 100MVA 至小于 500MVA，测得的第一个有效 的绕组热电阻值不宜超过 3min；对于额定容量不小于 500MVA 的变压器，测得的第一个有效的绕组热 电阻值不宜超过 4min。\n中型变压器的热电阻测量时间为 20min，大型变压器的热电阻测量时间为 30min。',175,'666a065f-7393-47ea-8169-4c616448a5b0',338,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.5  电源断开瞬间的绕组电阻测定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27335,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.6  冷却（下降）曲线的数值外推法\n\n电源断开瞬间绕组温度和冷却曲线的数值外推过程采用计算机程序来进行，以使这组温度读数数值 拟合成一个解析函数估算出绕组的平均温度值。更详细的内容见 GB/T 1094.2—2013 的附录 B。计算 机程序外推冷却曲线见图 14 所示。\n图 14  计算机程序外推冷却曲线',176,'05c7769c-d8e4-42a4-9ee2-508213f2f6c3',181,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.6  冷却（下降）曲线的数值外推法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27336,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.7  绕组热点温升确定\n\n对于额定容量小于 20/3（MVA/相）的变压器绕组热点温升既不需要直接测量也不需要计算。通常 认为绕组平均温升足以满足热点温升的要求。\n对于额定容量不小于 20/3（MVA/相）的变压器绕组热点温升应以试验结果为基础计算得出，也可 以通过直接测量得到。\n根据温升试验结果按照式（9）计算绕组热点温升：\nΔθh= Δθo+H × g ........................................................................... (9)\n式中：\nΔθh ——绕组热点温升； Δθo ——顶层液体温升；\nJB/T 501—2021\nH ——热点系数（按照 GB/T 1094.2—2013 的附录 D 计算得出）；\ng ——绕组与液体之间的平均温度梯度（绕组平均温升与液体平均温升之差）。 按照式（10）计算直接测量的绕组热点温升：\nΔθh=θh+Δθof  -θa  .................................................................... (10)\n式中：\nθh       ——电源断开瞬间绕组的热点温度；\nΔθof ——在额定电流下 1h 试验期间的顶层液体温度的降低值；\nθa        ——施加总损耗结束时测得的外部冷却介质温度。',177,'c2375a1c-a4af-4869-b3aa-585da670b209',608,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.7  绕组热点温升确定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27337,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.5.8  油箱表面热点温升的确定\n\n油箱表面热点温度应在温升试验施加额定电流 1h 结束前进行测量，油箱表面热点温升按照式（11） 计算：\nΔθbh=θbh+Δθof  -θa  ....................................................................... (11)\n式中：\nΔθbh  ——油箱表面的热点温升；\nθbh     ——电源断开前油箱表面的热点温度；\nΔθof ——在额定电流下 1h 试验期间的顶层液体温度的降低值；\nθa        ——施加总损耗结束时测得的外部冷却介质温度。',178,'0d8f0012-f54d-4419-81cf-6c9ad12a2d70',294,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.5.8  油箱表面热点温升的确定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27338,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.6  温升修正\n\n如果不能施加规定的总损耗或电流时，则其测试结果应按下列规定进行修正。修正的有效范围是： 施加的总损耗与规定的总损耗之差在±20%之内；施加的电流与规定的电流之差在±10%之内。\n通过协商，也可扩大修正的适用范围。但施加的总损耗不应低于规定总损耗的 70%；施加的电流不 应低于规定电流的 85%。\n施加总损耗结束时高于外部冷却介质的液体温升应乘以：\n(\nx\n) (\n试验损耗\n)[ 总损耗 ]\n修正指数 x 如下：\n——对于 ONAN 冷却方式的配电变压器，x=0.8；\n——对于 ON 冷却方式的中、大型变压器，x=0.9；\n——对于 OD 或 OF 冷却方式的中、大型变压器，x=1.0。\n电源断开瞬间，高于顶层液体温度的绕组平均温升应乘以：\n(\ny\n) (\n试验电流\n)[额定电流  ]\n修正指数 y 如下：\n——对于 ON 或 OF 冷却方式的变压器，y=1.6； ——对于 OD 冷却方式的变压器，y=2.0。\nJB/T 501—2021',179,'1302208a-c1b7-4387-9177-c3f2646ca5f2',458,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.6  温升修正"]','TEXT',NULL,'2026-03-11 11:17:43'),(27339,508,'## 3  油浸式电力变压器试验\n### 3.17  温升试验\n#### 3.17.7  试验结果判断\n\n对于绝缘系统温度为 105℃的固体绝缘，绝缘液为矿物油或燃点不大于 300℃的合成液体，在正常 使用条件下温升限值按技术协议规定，但不得高于以下规定限值：\n——顶层液体温升：60K；\n——绕组平均温升：65K （ON 及 OF 冷却方式）、70K （OD 冷却方式）； ——绕组热点温升：78K。\n对于特殊冷却条件下的温升限值，应按照 GB/T 1094.2 的规定进行修正。 油中的许可气体增长率应符合 GB/T 1094.2—2013 中附录 A 的要求。',180,'65e62f75-5a80-4709-bec9-09f4018d4796',267,NULL,'["3  油浸式电力变压器试验", "3.17  温升试验", "3.17.7  试验结果判断"]','TEXT',NULL,'2026-03-11 11:17:43'),(27340,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.1  概述\n\n声级测定通常采用声压法，也可采用声强法，详见 GB/T 1094.10 的规定。',181,'98050e4c-4025-47ba-8568-56fd121d3cf3',73,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27341,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.2  试验前准备\n\n被试品铁心、夹件引出端子应可靠接地。 被试品油箱应可靠接地。\n确认产品励磁绕组分接开关位置（额定分接下）。 确认风机和油泵电机的旋转方向。\n画出规定的轮廓线和测量时传声器的位置。',182,'9566be8e-82b8-4605-a073-dda3c9ded51e',125,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.2  试验前准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27342,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.3  试验一般要求\n\n试验应在 5℃~40℃环境温度（被试品温度）下进行。反射物体应尽可能远离被试品，地面的反射 面应大于被试品表面积在其上的投影。\n如果无其它规定，则是否进行负载电流下的声级测量可按照式（12）估算：\nLWA,IN ≈39+18lg(Sr/SP)....................................................................... (12)\n式中：\nLWA,IN——变压器在额定电流、额定频率及短路阻抗下的 A 计权声功率级； Sr    ——额定容量；MVA；\nSP    ——基准容量，1MVA。\n如果 LWA,IN 值比保证的声功率级低 8dB 或更多时，则负载电流声级测量不必进行。\n如果进行负载电流声级测量，则除试验电流不得低于 70％额定电流外，其余要求与短路阻抗和负 载损耗测量一致。\n应在测量即将开始前和测量刚结束后对测量设备进行校准。如果校准变化超过 0.3dB，则本次测量 结果无效，应重新进行测量。\n声压级测量采用 A 计权，用 A 计权声压测量确定声功率级数值，应使用仪器的快速响应指示。\n对于其它要求，空载下的声级测量与空载电流和空载损耗测量时一致，负载下的声级测量与短路阻 抗和负载损耗测量时一致。',183,'35b0e474-524b-4230-9c46-6179fb23e8c9',571,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.3  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27343,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.4  测量仪器的要求\n\n测量用声级计应符合 GB/T 3785.1—2010 和 GB/T 3785.2—2010 中的 1 型声级计，声校准器的偏差 应不大于 2dB。\nJB/T 501—2021\n声级计在测量前和测量后的校准偏差应小于 0.3dB。\n对于其它仪器要求，空载下的声级测量与空载电流和空载损耗测量时一致，负载下的声级测量与短 路阻抗和负载损耗测量时一致。',184,'bb7fab4e-c5c0-4f21-add9-9ccf6fe70b83',211,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.4  测量仪器的要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27344,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.5  试验接线示意图\n\n对于试验接线示意图，空载下的声级测量与空载电流和空载损耗测量一致，负载下的声级测量与短 路阻抗和负载损耗测量时一致。',185,'181d1e0a-bc30-4761-859d-a50c0ce9f3e3',96,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.5  试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27345,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.1.1  带或不带冷却设备的变压器基准发射面确定\n\n基准发射面应将距变压器油箱距离小于 3m 的冷却设备、箱壁加强铁及诸如电缆盒和分接开关等辅 助设备包括在内。距变压器油箱距离为 3m 及以上的冷却设备，则不包括在内。其它部件：如套管、油 管路和储油柜、油箱或冷却设备的底座、阀门及其它次要附件也不包括在内。',186,'fef08a9d-e509-4b0d-89b8-9c4114162302',182,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.1.1  带或不带冷却设备的变压器基准发射面确定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27346,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.1.2  规定轮廓线的确定\n\n在风冷却设备（如果有）停止运行条件下进行声级测量时，规定的轮廓线应距基准发射面 0.3m， 在风冷却设备投入运行条件下进行声级测量时，规定的轮廓线应距基准发射面 2m。\n对于油箱高度小于 2.5m 的变压器，规定轮廓线应位于油箱高度 1/2 处的水平面上。对于油箱高度 为 2.5m 及以上的变压器，应有 2 个轮廓线，分别位于油箱高度 1/3 处和 2/3 处的水平面上，但如果由 于安全的原因，则选择位于油箱高度更低处的轮廓线。\n在仅有冷却设备工作条件下进行声级测量时，如果冷却设备总高度（不包括储油柜、管路等）小于 4m，则规定轮廓线应位于总高度 1/2 处的水平面上。如果冷却设备总高度（不包括储油柜、管路等）为 4m 及以上，应有 2 个轮廓线，分别位于冷却设备总高度 1/3 处和 2/3 处的水平面上，但如果由于安全 的原因，则选择位于冷却设备总高度更低处的轮廓线。',187,'bb1a839a-0cec-48e8-8c62-b2dabfa5e0ef',433,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.1.2  规定轮廓线的确定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27347,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.1.3  传声器位置的确定\n\n传声器应位于规定轮廓线上，彼此间距大致相等，间距不得大于 1 m 。至少应设有 6 个传声器位 置。\n典型被试品基准发射面、规定轮廓线及传声器的位置见图 15～图 18 所示。\nJB/T 501—2021\n图 15  不带冷却设备的变压器声级测量时传声器的典型位置\nJB/T 501—2021\n图 16  冷却设备直接安装在油箱上或冷却设备距主油箱基准发射面小于 3m处分体式安装的变压器声级 测量时传声器的典型位置\nJB/T 501—2021\n图 17  风冷却设备独立安装在油箱上或冷却设备距主油箱基准发射面小于3m处分体式安装的变压器声 级测量时传声器的典型位置\nJB/T 501—2021\n图 18  距变压器基准发射面距离 3m 及以上处分体式安装的冷却设备声级测量时传声器的典型位置',188,'dc01477f-ac78-4e5f-99b8-932beb3dfd48',386,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.1.3  传声器位置的确定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27348,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.2  背景噪声的测量\n\n测量应在背景噪声值近似恒定时进行。\n在即将对试品噪声测量前，应先测出背景噪声的 A 计权声压级。测量背景噪声时，传声器所处的高 度应与测量试品噪声时其所处的高度相同，背景噪声的测量点应在规定的轮廓线上。\n当测量点总数超过 10 个时，允许只在试品周围呈均匀分布的 10 个测量点上测量背景噪声。\n如果背景噪声的声级明显低于试品和背景噪声的合成声级（即差值大于 10dB）,则可仅在一个测量 点上进行背景噪声测量，且不需对所测出的试品的声级进行修正。\n如果试验前、后背景的平均声压级之差大于 3dB，且较高者与未修正的 A 计权声压级之差小于 8dB，\nJB/T 501—2021\n则本次测量无效，应重新进行试验。但是，当未修正的平均 A 计权声压级小于保证值时除外。此时，应 认为试品符合声级保证值的要求。这种情况应在试验报告中予以记录。\n如果两个背景的平均 A 计权声压级中的较高者，与未修正的 A 计权声压级之差小于 3dB，则本次测 量无效，应重新进行试验。但是，当未修正的平均 A 计权声压级小于保证值时除外。此时，应认为试品 符合声级保证值的要求。这种情况应在试验报告中予以记录。试验接受准则见表 15。',189,'ed933c8e-e43f-432f-9497-87156de5d3e6',547,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.2  背景噪声的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27349,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.2  背景噪声的测量\n表 15  试验接受准则\n<table><tr><td>LpA0与较高的LbgA之差</td><td>试验前的LbgA与试验后的LbgA之差</td><td>结论</td></tr><tr><td>≥8dB</td><td>—</td><td>接受</td></tr><tr><td>＜8dB</td><td>＜3dB</td><td>接受</td></tr><tr><td>＜8dB</td><td>&gt;3dB</td><td>重新试验（见注）</td></tr><tr><td>＜3dB</td><td>—</td><td>重新试验（见注）</td></tr><tr><td colspan=\'3\'>注：如果LpA0小于保证值，则认为试品符合声级保证值的要求。这种情况宜在试验报告中予以记录。</td></tr></table>',190,'09448582-d7e7-4088-9c0d-5b106260bf17',226,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.2  背景噪声的测量"]','TABLE',NULL,'2026-03-11 11:17:43'),(27350,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.3  测量表面积的计算\n\n式中：\nS——测量表面积，m2； h——油箱高度，m；\nlm——轮廓线周长，m。\n考虑到安全因素，要求整个轮廓线或其中一部分距基准发射面的测量距离超过上述规定的试品上的 测量。\n测量表面积按式（16）计算：\nS=3/(4π)l2m                                                                                   (16)\n式中：\nS——测量表面积，m2；\nlm——按安全距离考虑的轮廓线周长，m。',191,'d1bd75c6-edbc-4793-b216-50dd65c9c19a',199,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.3  测量表面积的计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27351,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.4  环境修正值 K 的计算\n\n环境修正值 K 按式（17）计算：\nK=10lg[1+4/(A/S)]                                      (17)\n式中：\nK——环境修正值； A=αSv；\nJB/T 501—2021\nS——测量表面积\nSv——试验室（墙壁、天棚和地面）的总面积，m2； α——平均吸声系数，工业厂房取 0.15。',192,'eefd159f-01ef-4949-86bd-d87ae987721b',176,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.4  环境修正值 K 的计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27352,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.5  平均声压级计算\n\n未修正的平均 A 计权声压级 LpA 0  应根据在试品供电时各测点上测得的 A 计权声压级 LpAi 按式（18） 计算：\n=10lg                                                           (18)\n式中的N为测点总数。\n注：当各 LpAi 差别不大于 5dB 时，可用简单的算术平均值来计算。\n背景噪声的平均 A 计权声压级 LbgA  应根据试验前、后各测点上测得的背景噪声 A 计权声压级 LbgAi 分别按式（19）计算：\n=10lg                                                           (19)\n=10lg  —K........................................................\n式中的100.1LbgA   为两个计算出的背景噪声平均 A 计权声压级中较小者。',193,'70711e73-c761-4f66-a3ae-0f339e533a5a',343,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.5  平均声压级计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27353,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.6  声功率级计算\n\n试品的 A 计权声功率级 LWA 应根据修正的平均 A 计权声压级 LpA  按式（21）计算：\nLWA  =  + 10lg  ......................................................................\n式中：\nS——测量表面积，m2；\nS0——基准参考面积，1m2。\n对于冷却设备直接安装在油箱上的变压器，其冷却设备的声功率级 LWAO 按式（22）计算：\nLWAO=10lg(100.1LWA1            100.1LWA2    ）                                 (22)\n式中：\nLWA1 ——变压器和冷却设备的声功率级； LWA2 ——变压器的声功率级。\n对于冷却设备为独立安装的变压器，变压器和冷却设备的声功率级按式（23）计算：\nLWA1  =10lg(100.1LWA0   +100.1LWA2    ）                                (23)\nJB/T 501—2021',194,'f0b4c70e-c25e-493d-86e1-4c954223f29f',420,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.6  声功率级计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27354,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.7  降低的负载电流声功率级计算\n\n如果只能在降低的电流下进行声级测量时，则在额定电流下的 A 计权声功率级 LWA，IN 应按式（24） 计算：\nLWA,IN  = LWA,IT  + 40 lg  .................................................................\n式中：\nLWA，IT——降低电流下的 A 计权声功率级； IN——额定电流；\nIT——降低电流。\n该公式只在降低的电流为额定电流的 70%及以上时适用。',195,'3b99e4bb-c4d1-4507-9a6f-97eff0c21fe4',268,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.7  降低的负载电流声功率级计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27355,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.8  空载声功率级和负载电流声功率级相加的计算\n\n对于在额定电压和额定电流下运行的变压器，其 A 计权声功率级 LWA，SN 可由 A 计权空载声功率级 LWA，UN 和 A 计权额定电流声功率级 LWA，IN 按式（25）来计算：\nLWA，SN  = 10lg（100.1LWA ，UN        + 100.1LWA ，IN    ）                            (25)',196,'6eeb4a92-a8ed-4e8f-a99b-fd45b1010137',193,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.8  空载声功率级和负载电流声功率级相加的计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27356,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.6.9  被试品的声级测定\n\n按技术协议对试品进行供电。\n对于空载下的声级测量，其供电方式与空载电流和空载损耗测量时一致。 对于负载下的声级测量，其供电方式与短路阻抗和负载损耗测量时一致。\n在绕组电阻测量或短路承受能力试验后进行声级测量时，应注意剩磁对测量结果的影响。 一旦达到稳定状态应立即进行测量，避免因试品温度变化而导致声级变化。\n所允许的供电组合如下：\n——变压器供电，冷却设备及油泵不运行；\n——变压器供电，冷却设备及油泵投入运行；\n——变压器供电，冷却设备不运行，油泵投入运行； ——变压器不供电，冷却设备及油泵投入运行。\n对于每一测点上的 A 计权声压级需予以记录。',197,'f56f84d6-bba5-49be-9181-c8f69a0382ff',316,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.6.9  被试品的声级测定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27357,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.7  试验结果的判定\n\n试验结果应符合 JB/T 10088 或技术协议的规定。',198,'c39c9061-ddc3-4d6b-9a81-1535041fa938',66,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.7  试验结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27358,508,'## 3  油浸式电力变压器试验\n### 3.18  声级测定\n#### 3.18.8  注意事项\n\n应使传声器的位置限制在安全范围内。',199,'fb2d305c-9e16-4df4-81a3-79cd8df89dab',52,NULL,'["3  油浸式电力变压器试验", "3.18  声级测定", "3.18.8  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27359,508,'## 3  油浸式电力变压器试验\n### 3.19  风扇和油泵电机所吸取功率测量\n#### 3.19.1  试验前准备\n\n检查仪器功能是否正常，并确认仪器检定有效期。\n相关试验设备及仪表应按要求正确接线，试验接线见图 19。\nJB/T 501—2021\n被试冷却（散热）装置的风扇和油泵应装备完好。',200,'4ff6226e-b4f6-484c-b234-18e84b66f954',134,NULL,'["3  油浸式电力变压器试验", "3.19  风扇和油泵电机所吸取功率测量", "3.19.1  试验前准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27360,508,'## 3  油浸式电力变压器试验\n### 3.19  风扇和油泵电机所吸取功率测量\n#### 说明：\n\nK1、K2—刀闸开关； T—调压器；\nG—电机；\nA—电流表； V—电压表； W—瓦特表。\n图 19  风扇和油泵电机功率测量原理图',201,'16680863-7218-4fe4-bf36-6864e5e1e7e9',102,NULL,'["3  油浸式电力变压器试验", "3.19  风扇和油泵电机所吸取功率测量", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27361,508,'## 3  油浸式电力变压器试验\n### 3.19  风扇和油泵电机所吸取功率测量\n#### 3.19.2  试验方法\n\n试验方法采用两瓦特表法或三瓦特表法。',202,'09d7fccf-dec3-4066-957b-d67a1e7b6a73',63,NULL,'["3  油浸式电力变压器试验", "3.19  风扇和油泵电机所吸取功率测量", "3.19.2  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27362,508,'## 3  油浸式电力变压器试验\n### 3.19  风扇和油泵电机所吸取功率测量\n#### 3.19.3  注意事项\n\n应根据电机铭牌数据正确选择瓦特表、电压及电流表的电压、电流量程及功率因数（cosφ=0.8）。\n正确接线后，应首先合刀闸开关K1 ，调节电压至额定电压，启动电机并调整转向正确，然后合刀闸 开关K2 ；将刀闸开关K1拉掉，待表计起值稳定后同时读取各表的起值。\n测量结果应与铭牌数据符合对应规律。',203,'01e84622-6fa6-4100-8c60-c47779d0f7df',191,NULL,'["3  油浸式电力变压器试验", "3.19  风扇和油泵电机所吸取功率测量", "3.19.3  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27363,508,'## 3  油浸式电力变压器试验\n### 3.20  暂态电压传输特性测定\n#### 3.20.1  试验一般要求\n\n试验主要按照 GB/T 1094.3—2017的附录C.2 进行。一般只是在具有大的匝数比的发电机变压器或 具有低电压的第三绕组的高电压系统用的大容量变压器上进行。',204,'7817a016-98b6-494e-ba19-aea6e3e26596',125,NULL,'["3  油浸式电力变压器试验", "3.20  暂态电压传输特性测定", "3.20.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27364,508,'## 3  油浸式电力变压器试验\n### 3.20  暂态电压传输特性测定\n#### 3.20.2  测量仪器和精度\n\n测量仪器主要为示波器和电容分压器，系统精度应不低于3%。',205,'e8aec24f-31e6-48b0-b1dc-778286a1803e',72,NULL,'["3  油浸式电力变压器试验", "3.20  暂态电压传输特性测定", "3.20.2  测量仪器和精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27365,508,'## 3  油浸式电力变压器试验\n### 3.20  暂态电压传输特性测定\n#### 3.20.3.1  概述\n\n试验可以采用冲击发生器重复施加降低电压的雷电全波冲击电压，配合冲击测量系统进行测量；也 可采用低电压重复波发生器配合示波器进行测量。\nJB/T 501—2021',206,'1dac7ffa-7922-400c-8db7-30be25356956',121,NULL,'["3  油浸式电力变压器试验", "3.20  暂态电压传输特性测定", "3.20.3.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27366,508,'## 3  油浸式电力变压器试验\n### 3.20  暂态电压传输特性测定\n#### 3.20.3.2  试验接线示意图\n\n暂态电压传输特性试验接线按照图20进行。\n图 20  暂态电压传输特性测定接线示意图',207,'b99b46aa-e2e9-445b-a42b-0af37e12c7e8',87,NULL,'["3  油浸式电力变压器试验", "3.20  暂态电压传输特性测定", "3.20.3.2  试验接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27367,508,'## 3  油浸式电力变压器试验\n### 3.20  暂态电压传输特性测定\n#### 3.20.3.3  施加电压的波形和阻抗\n\n施加的电压波形为低电压雷电全波冲击波形：1.2μs±30%/50μs±20%。\n系统波阻抗由用户提供，如果用户不能提供系统波阻抗，则制造方宜提供端子开路时的传递过电压。',208,'c7f90908-eab4-4149-824d-04592fd327eb',133,NULL,'["3  油浸式电力变压器试验", "3.20  暂态电压传输特性测定", "3.20.3.3  施加电压的波形和阻抗"]','TEXT',NULL,'2026-03-11 11:17:43'),(27368,508,'## 3  油浸式电力变压器试验\n### 3.20  暂态电压传输特性测定\n#### 3.20.4  试验结果的判断\n\n试验结果应符合技术协议规定。 应提供实测值。',209,'a3dcbcdb-296c-428e-b76c-f7af104e656a',66,NULL,'["3  油浸式电力变压器试验", "3.20  暂态电压传输特性测定", "3.20.4  试验结果的判断"]','TEXT',NULL,'2026-03-11 11:17:43'),(27369,508,'## 3  油浸式电力变压器试验\n### 3.21  三相变压器零序阻抗测量\n#### 3.21.1  概述\n\n对于运行中有零序回路的绕组（YN联结）均需测量零序阻抗，试验的原理接线图见图21。',210,'e50c3b5c-c397-462a-a319-005f0bf96bad',81,NULL,'["3  油浸式电力变压器试验", "3.21  三相变压器零序阻抗测量", "3.21.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27370,508,'## 3  油浸式电力变压器试验\n### 3.21  三相变压器零序阻抗测量\n#### 说明：\n\nTA—电流互感器； TV—电压互感器；\nA—电流表； V—电压表。\n图 21  三相变压器零序阻抗试验原理接线图\nJB/T 501—2021\n试验时一般从三相线端对中性点供电，以电流为准，测量电压。零序阻抗通常以每相的欧姆数表示， 计算公式见式（26）：\nZ0  = 3U / I ......................................................................... (26)\n式中：\nZ0 ——零序阻抗， Ω/相；\nU ——试验电压，V； I ——试验电流，A。',211,'39f1e9e3-d235-4230-84b4-26ca96938ea2',295,NULL,'["3  油浸式电力变压器试验", "3.21  三相变压器零序阻抗测量", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27371,508,'## 3  油浸式电力变压器试验\n### 3.21  三相变压器零序阻抗测量\n#### 3.21.2  有平衡安匝的零序阻抗测量\n\n对于联结组标号为YNyn0d11、Dyn11yn11的三绕组变压器和YNd11的双绕组变压器，绕组中有一个封 闭的三角形联结的绕组均属有平衡安匝的试品。\n有平衡安匝的试品其零序阻抗是线性的，一般只测量一点，试验电源的波形和测量系统的精度应满 足要求。\n如无特殊要求，零序阻抗的测量应按下列测量组合进行：\n——对于联结组标号为 YNd11 的试品，只测量高压绕组，试验时 ABC—O 供电、低压开路。 ——对于联结组标号为 YNyn0d11 的试品，低压开路时的测量组合见表 14。',212,'d414ce90-be01-4012-ba48-e01b32ef8a1a',290,NULL,'["3  油浸式电力变压器试验", "3.21  三相变压器零序阻抗测量", "3.21.2  有平衡安匝的零序阻抗测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27372,508,'## 3  油浸式电力变压器试验\n### 3.21  三相变压器零序阻抗测量\n#### 3.21.2  有平衡安匝的零序阻抗测量\n表 16  YNyn0d11 的试品零序阻抗测量组合\n<table><tr><td>序号</td><td>供电端子</td><td>开路端子</td><td>短路端子</td></tr><tr><td>1</td><td>ABC—O</td><td>A m B m C m — O m</td><td>——</td></tr><tr><td>2</td><td>ABC—O</td><td>——</td><td>A m B m C m — O m</td></tr><tr><td>3</td><td>A m B m C m — O m</td><td>ABC—O</td><td> </td></tr><tr><td>4</td><td>A m B m C m — O m</td><td>——</td><td>ABC—O</td></tr></table>',213,'58fc87e7-5e6a-4d40-bfb2-78ea1c428d8b',247,NULL,'["3  油浸式电力变压器试验", "3.21  三相变压器零序阻抗测量", "3.21.2  有平衡安匝的零序阻抗测量"]','TABLE',NULL,'2026-03-11 11:17:43'),(27373,508,'## 3  油浸式电力变压器试验\n### 3.21  三相变压器零序阻抗测量\n#### 3.21.2  有平衡安匝的零序阻抗测量\n\n对于其它有平衡安匝的绕组联结组合可参照以上两种联结组合的部位进行测量。在以上测量中由于 电流沿三角接线自行构成回路，因此所测的零序阻抗都是短路零序阻抗，而没有空载零序阻抗。',214,'beb2e0b7-591f-4f0e-add4-e788c7a79090',136,NULL,'["3  油浸式电力变压器试验", "3.21  三相变压器零序阻抗测量", "3.21.2  有平衡安匝的零序阻抗测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27374,508,'## 3  油浸式电力变压器试验\n### 3.21  三相变压器零序阻抗测量\n#### 3.21.3  无平衡安匝的零序阻抗测量\n\n对于联结组标号为YNyn0yn0的三绕组变压器和Yyn0的双绕组变压器及所有联结组合中无闭合三角 形的试品，均属无平衡安匝的试品。\n无平衡安匝的试品其零序阻抗是非线性的，每个测试组合均需测量4点～5点的零序阻抗。试验电流 应尽量等于额定电流，如果零序阻抗太大，则应控制其试验电压不超过额定的相电压。以该试验电流等 差递减分别测量各点的零序阻抗。\n如无特殊要求，零序阻抗的测量组合按下列规定进行： ——对于 Yyn0 的试品，只测量低压绕组；\n——试验时 abc—o 供电、高压绕组开路；\n——这种试品只有空载零序阻抗，没有短路零序阻抗； ——对于 YNyn0yn0 的试验，测量组合见表 15。\nJB/T 501—2021',215,'d473fdb6-cf92-4e10-81d9-84cc20fe3d23',361,NULL,'["3  油浸式电力变压器试验", "3.21  三相变压器零序阻抗测量", "3.21.3  无平衡安匝的零序阻抗测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27375,508,'## 3  油浸式电力变压器试验\n### 3.21  三相变压器零序阻抗测量\n#### 3.21.3  无平衡安匝的零序阻抗测量\n表 17  YNyn0yn0 的试品零序阻抗测量组合\n<table><tr><td>序号</td><td>供电端子</td><td>开路端子</td><td>短路端子</td></tr><tr><td>1</td><td>ABC—O</td><td>A m B m C m — O m abc—o</td><td> </td></tr><tr><td>2</td><td>ABC—O</td><td>abc—o</td><td>A m B m C m — O m</td></tr><tr><td>3</td><td>ABC—O</td><td>A m B m C m — O m</td><td>abc—o</td></tr><tr><td>4</td><td>ABC—O</td><td>——</td><td>A m B m C m — O m abc—o</td></tr><tr><td>5</td><td>A m B m C m — O m</td><td>ABC—O abc—o</td><td>——</td></tr><tr><td>6</td><td>A m B m C m — O m</td><td>abc—o</td><td>ABC—O</td></tr><tr><td>7</td><td>A m B m C m — O m</td><td>ABC—O</td><td>abc—o</td></tr><tr><td>8</td><td>A m B m C m — O m</td><td> </td><td>ABC—O abc—o</td></tr><tr><td>9</td><td>abc—o</td><td>ABC—O<br/>A m B m C m — O m</td><td> </td></tr><tr><td>10</td><td>abc—o</td><td>A m B m C m — O m</td><td>ABC—O</td></tr><tr><td>11</td><td>abc—o</td><td>ABC—O</td><td>A m B m C m — O m</td></tr><tr><td>12</td><td>abc—o</td><td>——</td><td>ABC—O<br/>A m B m C m — O m</td></tr></table>',216,'1e9c1349-2678-4e0a-9c81-29e37b3cd311',596,NULL,'["3  油浸式电力变压器试验", "3.21  三相变压器零序阻抗测量", "3.21.3  无平衡安匝的零序阻抗测量"]','TABLE',NULL,'2026-03-11 11:17:43'),(27376,508,'## 3  油浸式电力变压器试验\n### 3.21  三相变压器零序阻抗测量\n#### 3.21.3  无平衡安匝的零序阻抗测量\n\n以上测试组合中序号1、6、10是空载零序阻抗，其它均为短路零序阻抗。对于空载零序阻抗测量时， 应指派专人监视试品油箱各部位，避免由于零序磁通集中而引起箱壁局部过热，大型产品尤应注意。\n对于其它无平衡安匝的试品可参照以上的测量组合进行测量。',217,'c68c9329-612c-4a5f-81c1-9008eda77946',169,NULL,'["3  油浸式电力变压器试验", "3.21  三相变压器零序阻抗测量", "3.21.3  无平衡安匝的零序阻抗测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27377,508,'## 3  油浸式电力变压器试验\n### 3.22  短路承受能力试验\n\n3.22.1  短路承受能力试验是模拟运行中最严酷的短路故障。变压器绕组、分接开关、套管、引线及各\n机械紧固部件将承受来自短路电流所产生的巨大的动稳定效应与热效应的考核。从而验证结构的合理性 与运行的可靠性。\n3.22.2  变压器承受热稳定的能力，通常按照产品在运行温度下发生短路，对称短路电流产生的热效应\n全部用来提高绕组温度，其最高温度应不超过 GB/T 1094.5 的规定。变压器承受热稳定能力可通过计算 来验证。\n试品的对称短路电流值及持续时间按GB/T 1094.5的规定。\n3.22.3  承受短路的动稳定能力应通过试验或计算验证其结构、工艺和制造的可靠性。试验通常在大容\n量试验站进行。试验电源可以是网络，也可以是冲击发电机组，一般均需配置合适的短路试验变压器和 电抗器。\n3.22.4  对于三角形联结的绕组进行三相试验时，如果低压侧为星形联结，则可采用测量低压电流的方\n法。对于三角形联结的绕组进行单相试验时，单相电压应施加在三角形的两个角上，试验时的电压应与 三相试验时的相间电压相同。对于星形联结绕组，如果电源容量不足以进行单相试验，而中性点可以利\nJB/T 501—2021\n用且能承受相关的电流时，则经协商单相电源可施加于线端与中性点之间。短路承受能力试验的接线示 意图见图 22。\na）三相法\nb）单相法（D联结、虚线为Y联结）\nc）单相法（YN联结组）',218,'ffaadca6-2733-4556-b861-3830e6dc2aeb',616,NULL,'["3  油浸式电力变压器试验", "3.22  短路承受能力试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27378,508,'## 3  油浸式电力变压器试验\n### 3.22  短路承受能力试验\n#### 说明：\n\nQF1、QF2、QF3、QF4—断路器； L—限流电抗器；\nT2—中间变压器； T—试品；\nTA—电流互感器(接示波器电流测量回路) ； TV—电压互感器(接示波器电压测量回路)。\n图 22  三相变压器短路承受能力试验接线示意图',219,'d111384e-ec2f-4d28-b077-c8707f5371d5',145,NULL,'["3  油浸式电力变压器试验", "3.22  短路承受能力试验", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27379,508,'## 3  油浸式电力变压器试验\n### 3.22  短路承受能力试验\n#### 3.22.5  短路试验前变压器应具备的条件如下：\n\nJB/T 501—2021\n——应进行 GB/T 1094.1 中规定的例行试验项目（不包括雷电冲击试验），试验合格后方能进行短 路试验；对试验没有影响的附件（如可拆卸的冷却器）可以不安装；其中负载试验应在最大分\n接、主分接和最小分接上进行，提供以上三个分接的短路阻抗和负载损耗； ——短路试验开始时，绕组的平均温度最好在 10℃~40℃之间；\n——试品运到试验站后，宜在现场吊心,沿线圈的轴向在高压侧和低压侧的线段和垫块上分别画出 2 条～3 条直线，如有可能幅向也应画对应轴向的等条数的直线作为标记；然后拍照，定为试 品短路试验前的形态；\n——试验前还应精确测量被试一对绕组试验分接的电抗值，重复测量电抗的误差应在±0.2% 以内。 ——有条件时，可进行绕组频谱分析测量。\n3.22.6  短路电流非对称分量的峰值计算按 GB/T 1094.5 的规定。\n3.22.7  短路试验可以采用预先短路、选相合闸，也可以采用预先送电、选相短路的方法。\n对于单同心式绕组的变压器采用预先短路时，为了避免最初几个周波中由于铁心饱和产生的励磁电 流迭加在短路电流上，施加电压的绕组应该选距铁心较远的那个绕组。\n对于双同心式绕组（高/低/高）和交叠式绕组的变压器采用预先短路的方法试验时，制造方需与用 户协商。\n3.22.8  为了在试品绕组中获得规定的初始峰值电流，应采用选相合闸装置控制在电压过零的瞬间合\n闸；Y 联结的绕组应在相电压过零时合闸，D 联结的绕组应在线电压过零时合闸。\n3.22.9  三相变压器应使用三相电源进行试验，没有三相电源也可使用单相电源；使用单相电源时，D\n联结的绕组单相电源应施加在三角形的两个角上；试验期间该单相电源应相当于三相试验的线电压。Y 联结的绕组单相电源应施加于一个线端与另外两个连在一起的线端上；试验期间单相电压应等于三相试\n验时线电压的  3 /2 倍。\n分级绝缘变压器需考虑其中性点绝缘是否能够满足单相电源的试验要求；Y联结的变压器，如电源 容量不足且有中性点可以利用时，则经制造方与用户协商，可在线端与中性点间使用单相电源进行试验。\n3.22.10  首先施加小于 70%试验电流进行调试；当合闸相角、试验电流的峰值和对称值及持续时间均\n达到要求时，再进行 100%试验电流的正式试验；小于 70%试验电流不记入试验次数。\n3.22.11  对于Ⅰ类和Ⅱ类的单相变压器，试验次数为三次；如无另行规定，带有分接的变压器的试验\n应分别在最大、额定和最小分接位置上各进行一次；三相变压器试验次数为九次，在不同分接位置上进 行，即在旁柱的最大分接、中柱的额定分接和另一旁柱的最小分接位置上分别进行三次。\n对于Ⅲ类变压器，其试验程序和分接位置通常由制造方与用户协商确定，一般与Ⅰ类和Ⅱ类变压器 相同。\n每次试验施加的短路电流偏差：峰值电流为±5%，方均根值电流为±10%。\n每次试验的持续时间为：对Ⅰ类变压器0.5s、对Ⅱ类和Ⅲ类变压器0.25s，其允许偏差为±10%。\n3.22.12  每次试验除用示波器记录电流波形外，还应派专人监视试品；每次试验过后，应对电流波形、\n气体继电器进行观察，并测量该分接的电抗值。\n3.22.13  短路试验后应重复全部例行试验，包括在 100%规定试验电压下的绝缘试验；如果规定了雷电\n冲击试验，则也应在此阶段中进行；但对于Ⅰ类变压器，除绝缘试验外的其它试验项目，可以不做。\nJB/T 501—2021\n3.22.14  首先外观检查油箱的几何形状有无变形、套管有无裂痕、压力释放阀有无喷油。然后吊心检\n查，查看分接开关有无熔焊现象、引线机械紧固及绝缘包扎有无松动、开裂及变形，绕组有无变形，垫 块和各支撑件有无位移，各部位有无放电痕迹。\n最后分别在高压侧与低压侧按短路试验前的部位拍照， 以进行比较。\n3.22.15  如果试验中短路电流峰值与稳定值、持续时间及试验次数均达到 GB/T 1094.5 的规定；试验\n中的波形和电抗与原始值比较，符合 GB/T 1094.5 的规定；且例行试验复试项目，包括 100%规定试验  电压下的外施耐压试验、感应耐压试验及雷电冲击试验（如有规定）合格；在外观及吊心检查中油箱的 几何形状无变形、高低压套管与分接开关无损伤、绕组和支撑件无变形、标记无明显位移、无放电痕迹、 气体继电器中无气体、压力释放阀无喷油等，则认为该产品经受住短路试验考核，试验合格；如果以上 任何一项超出了允许范围和规定，则认为试验不合格。',220,'113d839a-9661-45a3-be8a-ddab8582b078',1903,NULL,'["3  油浸式电力变压器试验", "3.22  短路承受能力试验", "3.22.5  短路试验前变压器应具备的条件如下："]','TEXT',NULL,'2026-03-11 11:17:43'),(27380,508,'## 3  油浸式电力变压器试验\n### 3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验\n#### 3.23.1  概述\n\n按照GB/T 1094.1的要求，真空变形试验和压力变形试验应在装配完整的变压器上进行。',221,'2a848d64-63bf-4ffc-b719-bbeeadf32ee3',98,NULL,'["3  油浸式电力变压器试验", "3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验", "3.23.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27381,508,'## 3  油浸式电力变压器试验\n### 3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验\n#### 3.23.2  试验目的\n\n通过正压和真空试验检测变压器的机械强度是否符合设计要求，保证变压器在后续的使用过程中不 出现异常变形。',222,'c12ea3a9-67ea-4c01-8b3c-20a8c3c67968',107,NULL,'["3  油浸式电力变压器试验", "3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验", "3.23.2  试验目的"]','TEXT',NULL,'2026-03-11 11:17:43'),(27382,508,'## 3  油浸式电力变压器试验\n### 3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验\n#### 3.23.3  试验方法\n\n试验方法如下：\n——试验准备：首先将变压器放置平稳，并连接好真空泵或压缩空气泵及试验管路，在变压器上安 装好合适量程的压力表或真空表，按规定紧固箱沿和法兰盖板的螺栓；\n——测试点的选择：测试点一般选在强度比较薄弱、变形比较大的位置,测试点的具体数量可根据 变压器的结构、大小及加强铁的数量按如下选择：\n●     高、低压侧：一般在变压器高度方向的中部箱壁和加强铁上至少各取 3 点,带盒壁结构的 变压器需在盒壁上至少选取 1 个测试点；\n●     箱顶：根据不同结构或变形有特殊要求的，选择易变形的位置作为测试点，应在箱盖中部 或其它薄弱部位至少选取 2 个测试点；\n●     两侧端面：是否选择测试点可根据变压器宽度及加强铁而定，对于宽度较大、加强铁较少 的变压器可设测试点。\n——测试基准线：在每个被测试面拉细绳作为测试基准线，在测试点的两端将细绳固定好，注意基 准线的固定不可随变压器的变形而移动；\n——初始值的确定：试验时一般先进行真空变形试验，然后进行压力变形试验；在试验之前，为释 放焊接应力可先对变压器进行真空预抽，使之消除一定的变形应力；预抽解除后，测量测试基 准线到变压器上各测试点的距离，将此数值作为真空变形试验的初始值；预抽真空度可根据变 压器的大小由企业自行制定；真空变形试验后，变压器恢复变形后的测量值为正压试验的初始 值；\n——试验数据的获得：试验压力和时间按 GB/T 1094.1 的规定进行；当达到规定的试验压力和时间 时，测量基准线到各测试点的距离，该数值与它的初始值之差为测试点的弹性变形量；解除压 力或真空后再次进行测量，此数值与它的初始值之差为测试点的永久变形量。\nJB/T 501—2021',223,'e34cfc16-f2ea-4d01-9ba7-b61e8c2db0c9',764,NULL,'["3  油浸式电力变压器试验", "3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验", "3.23.3  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27383,508,'## 3  油浸式电力变压器试验\n### 3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验\n#### 3.23.4  结果的判定\n\n变压器的弹性变形量或永久变形量应符合企业有关技术条件的规定，如果弹性变形量或永久变形量 在规定范围内，则变压器的压力变形试验和真空变形试验合格。如果超出了规定，则应对变压器进行加 固，并重新按上述规定试验。',224,'9dd2e290-92fc-43fb-9de6-7932ae9dbaee',160,NULL,'["3  油浸式电力变压器试验", "3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验", "3.23.4  结果的判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27384,508,'## 3  油浸式电力变压器试验\n### 3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验\n#### 3.23.5  注意事项\n\n注意事项如下：\n——变压器的所有紧固件应装配齐全且要紧固到位；\n——整个试验应指派专人监视，在试验过程中应随时观察压力表和真空表的指示值和变压器的变形 量，特别是压力变形试验时应控制试验压力不得超出规定值。如果发现变压器有异常变形或声 音，则应立即停止试验并查找原因。压力变形试验时不要在变压器附近长时间停留，随时注意 安全。',225,'238283cb-f278-419f-a05b-92e90bf3c61a',219,NULL,'["3  油浸式电力变压器试验", "3.23  液浸式变压器压力变形试验和液浸式变压器真空变形试验", "3.23.5  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27385,508,'## 3  油浸式电力变压器试验\n### 3.24  外部涂层检查\n\n外部涂层检查包含漆膜厚度测量和划格试验。试验方法分别按照GB/T 4956 和GB/T 4893.4的规定。 测量结果应符合用户技术协议及制造方工艺文件的规定。',226,'d16db373-f840-4aa6-b65a-47cb7e3c3846',105,NULL,'["3  油浸式电力变压器试验", "3.24  外部涂层检查"]','TEXT',NULL,'2026-03-11 11:17:43'),(27386,508,'## 3  油浸式电力变压器试验\n### 3.25  运输质量测定\n\n额定容量不大于1.6MVA的变压器采用整体测量。大型变压器采用测量或计算，具体由制造方与用户 协商。',227,'979bf2b9-783a-4d37-ad3f-d52c782fc897',75,NULL,'["3  油浸式电力变压器试验", "3.25  运输质量测定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27387,508,'## 3  油浸式电力变压器试验\n### 3.26  频率响应测量\n\n频率响应测量（频率响应分析FRA）按照GB/T 1094.18或DL/T 911进行。',228,'e65ddf1c-f308-4bf6-a74b-46059fae382f',68,NULL,'["3  油浸式电力变压器试验", "3.26  频率响应测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27388,508,'## 3  油浸式电力变压器试验\n### 3.27  短时过负载能力试验\n#### 3.27.1  试验一般要求\n\n测量系统的精度和试验接线与温升试验一致。试验应在最高油位下进行。',229,'e60255b4-ab07-489c-967d-25efda6f9bdb',74,NULL,'["3  油浸式电力变压器试验", "3.27  短时过负载能力试验", "3.27.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27389,508,'## 3  油浸式电力变压器试验\n### 3.27  短时过负载能力试验\n#### 3.27.2  试验方法\n\n一般在温升试验结束后立即施加1.5倍额定电流，持续时间2h。',230,'cffc4d00-0e3d-489c-8ba2-ca1419771564',70,NULL,'["3  油浸式电力变压器试验", "3.27  短时过负载能力试验", "3.27.2  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27390,508,'## 3  油浸式电力变压器试验\n### 3.27  短时过负载能力试验\n#### 3.27.3  试验结果的判断\n\n如果符合下列条件，则试验合格： ——压力保护装置不动作；\n——无渗漏油现象；\n——油箱波纹及片式散热器的变形量在规定范围内； ——油箱外壳及套管温升不大于 85K。',231,'bb194bdc-c0a0-41ea-80ae-279b15a3a7fb',125,NULL,'["3  油浸式电力变压器试验", "3.27  短时过负载能力试验", "3.27.3  试验结果的判断"]','TEXT',NULL,'2026-03-11 11:17:43'),(27391,508,'## 3  油浸式电力变压器试验\n### 3.28  强迫油循环变压器冷却油流系统的负压测试\n#### 3.28.1  试验一般要求\n\n变压器冷却系统的安装应与运行一致。变压器的油位应符合规定的要求。\nJB/T 501—2021',232,'2bcffa49-f779-46dd-80e1-04cacfe73165',98,NULL,'["3  油浸式电力变压器试验", "3.28  强迫油循环变压器冷却油流系统的负压测试", "3.28.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27392,508,'## 3  油浸式电力变压器试验\n### 3.28  强迫油循环变压器冷却油流系统的负压测试\n#### 3.28.2  试验方法\n\n在每个冷却器油泵进油端的放气处安装压力表。\n试验前应通过变压器本体及冷却器的放气塞放气，确认冷却器油泵的油流方向正确。 同时开启所有油泵，连续观测并记录稳定的压力表读数。',233,'984e20fe-841b-4e11-8be2-5af36c3741e1',135,NULL,'["3  油浸式电力变压器试验", "3.28  强迫油循环变压器冷却油流系统的负压测试", "3.28.2  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27393,508,'## 3  油浸式电力变压器试验\n### 3.28  强迫油循环变压器冷却油流系统的负压测试\n#### 3.28.3  试验结果的判断\n\n压力表不出现负压读数。',234,'95099ac3-a19d-4536-86ee-b996d1cab1c4',64,NULL,'["3  油浸式电力变压器试验", "3.28  强迫油循环变压器冷却油流系统的负压测试", "3.28.3  试验结果的判断"]','TEXT',NULL,'2026-03-11 11:17:43'),(27394,508,'## 3  油浸式电力变压器试验\n### 3.29  在 90%和 110%额定电压下的空载损耗和空载电流测量\n\n试验应按照3.8的规定进行。\n在 110%额定电压时，如果用户未要求空载损耗保证值，则允许平均值电压表的读数（该读数与方 均根值电压表的读数具有同一刻度）与方均根值电压表读数的差值超过 3%。',235,'708fc961-c2ef-4c64-bd77-a09a5e28eba5',143,NULL,'["3  油浸式电力变压器试验", "3.29  在 90%和 110%额定电压下的空载损耗和空载电流测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27395,508,'## 3  油浸式电力变压器试验\n### 3.30  油箱开裂试验\n\n试验按照 GB/T 6451—2015 的 4.3.9 进行。在系列产品中抽取一台变压器油箱，对其施加 103kPa 正压力（液压），历经 10min 后，不应出现开裂现象。',236,'a8a5f47b-c128-45e9-a583-d761aa4f3ba1',112,NULL,'["3  油浸式电力变压器试验", "3.30  油箱开裂试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27396,508,'## 3  油浸式电力变压器试验\n### 3.31  运输颠簸试验\n\n试验按照GB/T 6451—2015的4.3.10和5.3.13进行。试验方法及要求由用户与制造方协商。',237,'b91c307f-e02d-46df-a27b-9111003671d3',77,NULL,'["3  油浸式电力变压器试验", "3.31  运输颠簸试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27397,508,'## 3  油浸式电力变压器试验\n### 3.32  所有分接位置的负载损耗测量\n\n应在所有分接下进行负载损耗测量，试验方法按照3.7。\n如果无其它规定，则除主分接外的其它分接负载损耗测量结果应符合制造方的设计要求。',238,'d7dc89b7-d1be-41fd-bfca-b8c3fe7d898e',98,NULL,'["3  油浸式电力变压器试验", "3.32  所有分接位置的负载损耗测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27398,508,'## 3  油浸式电力变压器试验\n### 3.33  长时间空载试验\n\n本项试验应在绝缘试验后进行。对变压器施加1.1倍额定电压，开启正常运行时的全部油泵，运行 12h。试验过程中，应无明显的局部放电声、电信号。试验前、后油中应无乙炔，总烃含量应无明显变 化。',239,'8888d50c-9a7a-461e-a9a1-2b338a9afd2b',120,NULL,'["3  油浸式电力变压器试验", "3.33  长时间空载试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27399,508,'## 3  油浸式电力变压器试验\n### 3.34  油流静电试验\n#### 3.34.1  试验一般要求\n\n试验前产品油箱应可靠接地。产品本体及冷却器应放气。产品油位应符合要求。确认油泵的转动方 向是否正确。',240,'f103dbc3-4f07-4c0b-a822-81ed64c981a3',89,NULL,'["3  油浸式电力变压器试验", "3.34  油流静电试验", "3.34.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27400,508,'## 3  油浸式电力变压器试验\n### 3.34  油流静电试验\n#### 3.34.2  测量仪器的要求\n\n直流纳安表：0.5级，分辨率不低于0.1nA。',241,'6e8eecb8-82f7-4001-a589-fb10d82dc806',63,NULL,'["3  油浸式电力变压器试验", "3.34  油流静电试验", "3.34.2  测量仪器的要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27401,508,'## 3  油浸式电力变压器试验\n### 3.34  油流静电试验\n#### 3.34.3  接线示意图\n\n接线示意图见图23。\nJB/T 501—2021\n图 23   油流静电试验接线示意图',242,'2c5e6aee-1355-40c1-bc37-a0055420bd20',79,NULL,'["3  油浸式电力变压器试验", "3.34  油流静电试验", "3.34.3  接线示意图"]','TEXT',NULL,'2026-03-11 11:17:43'),(27402,508,'## 3  油浸式电力变压器试验\n### 3.34  油流静电试验\n#### 3.34.4  试验方法\n\n变压器不励磁，开启所有油泵，历时4h，测量各绕组端子及铁心对地的泄漏电流，直至电流达到稳 定值。',243,'d519c0e4-6b29-4143-b7a7-a631362c6cf7',85,NULL,'["3  油浸式电力变压器试验", "3.34  油流静电试验", "3.34.4  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27403,508,'## 3  油浸式电力变压器试验\n### 3.34  油流静电试验\n#### 3.34.5  试验结果的判断\n\n试验中应无放电信号。；',244,'c403cb95-2e3e-4de6-a0f3-268f9c453f3e',51,NULL,'["3  油浸式电力变压器试验", "3.34  油流静电试验", "3.34.5  试验结果的判断"]','TEXT',NULL,'2026-03-11 11:17:43'),(27404,508,'## 3  油浸式电力变压器试验\n### 3.35  转动油泵时的局部放电测量\n#### 3.35.1  试验一般要求\n\n试验应按照3.10.7的规定进行。',245,'4ad86cb8-c715-4c4d-9905-333a5c9bc24b',62,NULL,'["3  油浸式电力变压器试验", "3.35  转动油泵时的局部放电测量", "3.35.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27405,508,'## 3  油浸式电力变压器试验\n### 3.35  转动油泵时的局部放电测量\n#### 3.35.2  试验方法\n\n启动全部油泵运行4h，期间连续测量中性点、铁心对地的泄漏电流，并监视有无放电信号。然后在 不停油泵的情况下进行局部放电试验，对低压线端施加电压，使高压绕组线端电压为1.58Ur/  ， 并维 持60min，期间连续观察测量局部放电量。',246,'6673e514-7585-458f-8b5a-98b3fbd33bc8',159,NULL,'["3  油浸式电力变压器试验", "3.35  转动油泵时的局部放电测量", "3.35.2  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27406,508,'## 3  油浸式电力变压器试验\n### 3.35  转动油泵时的局部放电测量\n#### 3.35.3  试验结果的判断\n\n运转油泵时的局部放电量测量值与油泵不运转时的局部放电量测量值相比，放电量应无明显变化； 油中应无乙炔。',247,'e6023b5d-217e-43c0-aa67-e82489beeef8',97,NULL,'["3  油浸式电力变压器试验", "3.35  转动油泵时的局部放电测量", "3.35.3  试验结果的判断"]','TEXT',NULL,'2026-03-11 11:17:43'),(27407,508,'## 4  干式电力变压器试验\n### 4.1  试验项目\n\n例行试验、型式试验及特殊试验的项目按照GB/T 1094.11和GB/T 10228的规定，详见表18。\nJB/T 501—2021',248,'55875a86-74b8-4a43-ac9b-6205a00c0b88',87,NULL,'["4  干式电力变压器试验", "4.1  试验项目"]','TEXT',NULL,'2026-03-11 11:17:43'),(27408,508,'## 4  干式电力变压器试验\n### 4.1  试验项目\n表 18  干式电力变压器试验项目\n<table><tr><td>序号</td><td>试验</td><td>条款</td></tr><tr><td colspan=\'3\'>例行试验</td></tr><tr><td>1</td><td>绕组电阻测量</td><td>4.4</td></tr><tr><td>2</td><td>电压比测量和联结组标号检定</td><td>4.5</td></tr><tr><td>3</td><td>短路阻抗和负载损耗测量</td><td>4.6</td></tr><tr><td>4</td><td>空载损耗和空载电流测量</td><td>4.7</td></tr><tr><td>5</td><td>绝缘电阻测量</td><td>4.8</td></tr><tr><td>6</td><td>外施耐压试验</td><td>4.9</td></tr><tr><td>7</td><td>感应耐压试验</td><td>4.10</td></tr><tr><td>8</td><td>局部放电测量</td><td>4.11</td></tr><tr><td>9</td><td>有载分接开关试验（适用于有载调压变压器）</td><td>4.12</td></tr><tr><td colspan=\'3\'>型式试验</td></tr><tr><td>10</td><td>雷电冲击试验</td><td>4.13</td></tr><tr><td>11</td><td>温升试验</td><td>4.14</td></tr><tr><td colspan=\'3\'>特殊试验</td></tr><tr><td>12</td><td>局部放电测量</td><td>4.11</td></tr><tr><td>13</td><td>声级测定</td><td>4.15</td></tr><tr><td>14</td><td>短路承受能力试验</td><td>4.16</td></tr><tr><td>15</td><td>环境试验</td><td>4.17</td></tr><tr><td>16</td><td>气候试验</td><td>4.18</td></tr><tr><td>17</td><td>燃烧性能试验</td><td>4.19</td></tr></table>',249,'97c5a5e8-5938-4619-babc-cd89d3f28567',440,NULL,'["4  干式电力变压器试验", "4.1  试验项目"]','TABLE',NULL,'2026-03-11 11:17:43'),(27409,508,'## 4  干式电力变压器试验\n### 4.2  气候、环境和燃烧性能等级的试验准则\n\n当变压器被宣称符合某一气候、环境和燃烧性能等级时，则应按表17所给出的试验顺序，在同一台 变压器上进行这些相应的试验， 以验证其是否符合所宣称的相应等级的要求。\n4.17～4.19所规定的试验，应在能代表所设计类型的同一台变压器上进行。',250,'46e5b0be-bd44-41a9-b9a8-fa1b7b69c025',152,NULL,'["4  干式电力变压器试验", "4.2  气候、环境和燃烧性能等级的试验准则"]','TEXT',NULL,'2026-03-11 11:17:43'),(27410,508,'## 4  干式电力变压器试验\n### 4.2  气候、环境和燃烧性能等级的试验准则\n表 19  试验顺序\n<table><tr><td colspan=\'3\'>等级</td><td colspan=\'2\'>气候</td><td colspan=\'3\'>环境</td><td colspan=\'2\'>燃烧性能</td></tr><tr><td colspan=\'2\'>试验</td><td>条号</td><td>C1</td><td>C2</td><td>E0</td><td>E1</td><td>E2</td><td>F0</td><td>F1</td></tr><tr><td>1</td><td>-5℃下的热冲击</td><td>4.18.4</td><td>是</td><td>否</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>2</td><td>-25℃下的热冲击</td><td>4.18.5</td><td>否</td><td>是</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>3</td><td>凝露试验</td><td>4.17.4</td><td>—</td><td>—</td><td>否</td><td>是</td><td>否</td><td>—</td><td>—</td></tr><tr><td>4</td><td>凝露和湿渗透试验</td><td>4.17.5</td><td> </td><td> </td><td>否</td><td>否</td><td>是</td><td> </td><td> </td></tr><tr><td>5</td><td>燃烧性能试验</td><td>4.19</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>否</td><td>是</td></tr></table>',251,'37a42630-c477-4cfe-83fa-4ab9093d57fe',359,NULL,'["4  干式电力变压器试验", "4.2  气候、环境和燃烧性能等级的试验准则"]','TABLE',NULL,'2026-03-11 11:17:43'),(27411,508,'## 4  干式电力变压器试验\n### 4.3  一般试验条件\n\n本章是对干式电力变压器一般试验条件的要求，如果试验项目中无具体的规定应按本章执行。一般 试验条件包括：\nJB/T 501—2021\n——试验应在 5℃~40℃的环境温度下进行； ——定期的型式试验应至少每 5 年进行一次；\n——变压器进行绝缘试验时，其温度应与试验场所的温度接近；\n——试验应在相关附件装好后的完整变压器上进行（绝缘试验外壳可不装）；\n——带分接的绕组应在主分接下进行试验，但相应试验条款另有规定或供、需双方另有协议时除外。 除绝缘试验外，变压器其它所有特性的试验均以额定条件为基础，但有关试验条款另有规定时除外。',252,'855c0680-3002-461f-9f50-69a98ec8a9f4',288,NULL,'["4  干式电力变压器试验", "4.3  一般试验条件"]','TEXT',NULL,'2026-03-11 11:17:43'),(27412,508,'## 4  干式电力变压器试验\n### 4.4  绕组电阻测量\n#### 4.4.1  试验一般要求\n\n变压器在恒定的环境温度下静止的时间不应少于 3h。绕组温度近似等于环境温度（按 GB/T 1094.1 —2013  中 11.2.2）。\n带分接的绕组，每个分接都应测量。对所有引出的相应端子间的电阻值均应进行测量。',253,'957b9b13-7b4b-4bd7-a698-9e3be306dd0e',143,NULL,'["4  干式电力变压器试验", "4.4  绕组电阻测量", "4.4.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27413,508,'## 4  干式电力变压器试验\n### 4.4  绕组电阻测量\n#### 4.4.2  测量仪器和仪器精度\n\n测量仪器推荐采用准确度不低于0.2级恒流输出的直流电阻测试仪；也可采用准确度不低于0.5级的 电阻电桥。',254,'5ff80e93-26c6-4678-bbcf-f586854c70bc',91,NULL,'["4  干式电力变压器试验", "4.4  绕组电阻测量", "4.4.2  测量仪器和仪器精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27414,508,'## 4  干式电力变压器试验\n### 4.4  绕组电阻测量\n#### 4.4.3.1  试验接线\n\n绕组电阻测量试验接线示意图见图24。\n图 24  绕组电阻测量试验接线示意图',255,'6418635f-633d-42db-a88f-822fab45ac47',73,NULL,'["4  干式电力变压器试验", "4.4  绕组电阻测量", "4.4.3.1  试验接线"]','TEXT',NULL,'2026-03-11 11:17:43'),(27415,508,'## 4  干式电力变压器试验\n### 4.4  绕组电阻测量\n#### 4.4.3.2  绕组温度的测量\n\n测量时的温度应取放于线圈表面至少3个温度计（温度传感器或热电偶）的读数平均值。绕组的电 阻和温度应同时记录。',256,'75168597-7100-4785-90d5-2fdfd487dac2',93,NULL,'["4  干式电力变压器试验", "4.4  绕组电阻测量", "4.4.3.2  绕组温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27416,508,'## 4  干式电力变压器试验\n### 4.4  绕组电阻测量\n#### 4.4.3.3  测量电流的选取\n\n根据试品绕组电阻计算值，测量电流应按照仪器规定的范围选取；测量电流不得大于被试绕组额定 电流的 15%。',257,'af0ac6bd-b7ad-4e75-b1f1-0582280dd6f7',91,NULL,'["4  干式电力变压器试验", "4.4  绕组电阻测量", "4.4.3.3  测量电流的选取"]','TEXT',NULL,'2026-03-11 11:17:43'),(27417,508,'## 4  干式电力变压器试验\n### 4.4  绕组电阻测量\n#### 4.4.4  结果判定\n\n对于额定容量为2500kVA及以下的配电变压器，其绕组直流电阻不平衡率：相为不大于4%，线为不 大于2%；\nJB/T 501—2021\n对于额定容量为630kVA及以上的电力变压器，其绕组直流电阻不平衡率：相（有中性点引出时）为 不大于2%，线（无中性点引出时）为不大于2%。\n如果由于线材及引线结构等原因而使绕组直流电阻不平衡率超过上述值时，除应在例行试验记录中 记录实测值外，还应写明引起这一偏差的原因。使用单位应与同温度下的例行试验测量值进行比较，其 偏差应不大于2%。',258,'7e435f26-5b56-4431-bd87-22baaca61daa',272,NULL,'["4  干式电力变压器试验", "4.4  绕组电阻测量", "4.4.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27418,508,'## 4  干式电力变压器试验\n### 4.5  电压比测量和联结组标号检定\n#### 4.5.1  试验一般要求\n\n每个分接都应进行电压比测量。应检定单相变压器的极性和三相变压器的联结组标号。',259,'f3ed5010-5f0d-4b31-b998-cab25c43edac',81,NULL,'["4  干式电力变压器试验", "4.5  电压比测量和联结组标号检定", "4.5.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27419,508,'## 4  干式电力变压器试验\n### 4.5  电压比测量和联结组标号检定\n#### 4.5.2  测量仪器精度\n\n仪器的精度应不低于 0.2 级。',260,'f03c6874-6136-4b00-b572-f91435deea0c',59,NULL,'["4  干式电力变压器试验", "4.5  电压比测量和联结组标号检定", "4.5.2  测量仪器精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27420,508,'## 4  干式电力变压器试验\n### 4.5  电压比测量和联结组标号检定\n#### 4.5.3.1  测量方法\n\n测量方法推荐采用电压比测试仪测量。',261,'7a2cf37b-5414-46c2-9dce-7ddcc19fdc96',60,NULL,'["4  干式电力变压器试验", "4.5  电压比测量和联结组标号检定", "4.5.3.1  测量方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27421,508,'## 4  干式电力变压器试验\n### 4.5  电压比测量和联结组标号检定\n#### 4.5.3.2.1  单相变压器试验接线\n\n单相变压器电压比测量接线示意图见图 25。\n图 25  单相变压器电压比测量接线示意图',262,'0eefb54a-8a54-475f-8322-3ff106d20472',92,NULL,'["4  干式电力变压器试验", "4.5  电压比测量和联结组标号检定", "4.5.3.2.1  单相变压器试验接线"]','TEXT',NULL,'2026-03-11 11:17:43'),(27422,508,'## 4  干式电力变压器试验\n### 4.5  电压比测量和联结组标号检定\n#### 4.5.3.2.2  三相变压器试验接线\n\n三相变压器电压比测量接线示意图见图26。\nJB/T 501—2021\n图 26  三相变压器电压比测量接线示意图',263,'fe4f9eb2-0b25-4afb-973e-d5c393ea9e35',105,NULL,'["4  干式电力变压器试验", "4.5  电压比测量和联结组标号检定", "4.5.3.2.2  三相变压器试验接线"]','TEXT',NULL,'2026-03-11 11:17:43'),(27423,508,'## 4  干式电力变压器试验\n### 4.5  电压比测量和联结组标号检定\n#### 4.5.3.3  电压比值的基准值计算\n\n电压比值的基准值计算应按照产品铭牌标称的电压值进行，当使用分接因数计算所对应的分接位置 的电压比与使用产品标称的电压所计算的电压比一致时，允许只计算主分接的电压比，其它分接可以使 用主分接的电压比与分接因数进行测量，否则应计算所有分接位置的电压比。',264,'1c36034d-0004-4afa-8f6a-46bbcbd44a09',173,NULL,'["4  干式电力变压器试验", "4.5  电压比测量和联结组标号检定", "4.5.3.3  电压比值的基准值计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27424,508,'## 4  干式电力变压器试验\n### 4.5  电压比测量和联结组标号检定\n#### 4.5.4  结果判定\n\n按 GB/T 1094.1—2013  的表 1 中空载电压比偏差的规定：\n——第一绕组对的主分接或极限分接（如果规定） ：规定电压比的±0.5％或实际阻抗百分数的 ±1／10，取两者中的较小者；\n——第一绕组对的其它分接：匝数比设计值的±0.5%; ——其它绕组对：匝数比设计值的±0.5％。',265,'25aefcfe-cdf0-4bbc-8f84-78d0f2866263',187,NULL,'["4  干式电力变压器试验", "4.5  电压比测量和联结组标号检定", "4.5.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27425,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.1  试验一般要求\n\n变压器的温度接近试验时的环境温度。\n一对绕组的短路阻抗和负载损耗测量，通常由被试品的较高电压绕组施加额定频率近似正弦波的电  压，另一绕组短路，其余绕组开路。应施加相应的额定电流（或分接电流）。在受到试验设备的限制时， 可以施加不小于相应额定电流（或分接电流）的 50%，测得的负载损耗值乘以额定电流（或分接电流） 与试验电流之比的平方。\n对于分接范围不超过±5%的变压器，一般在主分接进行短路阻抗和负载损耗测量。\n对于分接范围超过±5%的变压器，应对主分接、两个极限分接进行短路阻抗和负载损耗测量。试 验报告中，除了提供主分接的短路阻抗和负载损耗外，还应提供两个极限分接的短路阻抗。\n对于分接范围不超过±5%，但额定容量超过 2500kVA 的变压器，如果产品进行温升试验，为了温 升试验的目的，应对主分接、两个极限分接进行短路阻抗和负载损耗测量。如果不进行温升试验，则对 主分接进行短路阻抗和负载损耗测量。对于此类变压器在短路后的复试中也仅在主分接进行短路阻抗和 负载损耗测量。\n负载试验以三相负载电流的算术平均值为准。\nJB/T 501—2021',266,'dab2c080-8eba-4c10-b72f-f73f3e26f8e1',516,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27426,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.2  测量仪器和精度\n\n互感器的精度不低于 0.2 级，所用仪表精度应不低于 0.5 级。',267,'3fa3782e-2cd5-45e9-bf0e-509e175b0d88',75,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.2  测量仪器和精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27427,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.3.1  试验接线\n\n单相变压器负载试验接线示意图见图 27。 三相变压器负载试验接线示意图见图 28。\n图 27  单相变压器负载试验接线示意图\n图 28  三相变压器负载试验接线示意图',268,'18793c2b-c3f8-4165-8206-2ae862ca2b0b',122,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.3.1  试验接线"]','TEXT',NULL,'2026-03-11 11:17:43'),(27428,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.3.2.1  参考温度\n\n短路阻抗和负载损耗的参考温度应等于绕组平均温升限值加上 20℃。\n当一台变压器的绕组具有多个不同的绝缘系统温度时，其参考温度应采用与较高绝缘系统温度相对 应的绕组的数值。\nJB/T 501—2021',269,'c7ca5fff-fb89-4827-bc32-0634ff236099',142,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.3.2.1  参考温度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27429,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.3.2.2  环境温度下损耗和短路阻抗换算到参考温度\n<table><tr><td>损耗按式（27）折算：</td><td>...............................................................</td></tr><tr><td>式中：</td><td> </td></tr></table>',270,'ad12e664-d3ed-47e5-a20b-564736850f21',146,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.3.2.2  环境温度下损耗和短路阻抗换算到参考温度"]','TABLE',NULL,'2026-03-11 11:17:43'),(27430,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.3.2.2  环境温度下损耗和短路阻抗换算到参考温度\n\nPk ——参考温度下的负载损耗，kW； Pkt ——t ℃时的负载损耗，kW；\nΣ I 2R ——试验温度下一对绕组的电阻损耗，kW；\nKt ——电阻温度换算系数。  短路阻抗按式（28） ）折算：\n......................................................................\n式中：\nZkt ——绕组温度为 t ℃时的短路阻抗，%；\nUkt ——绕组 t ℃时通过试验电流 Ik 的阻抗电压，kV； Ik    ——试验施加电流，A；\nUr ——施加电压侧的额定电压，kV； Ir ——施加电压侧的额定电流，A；  Zk ——参考温度时的短路阻抗，%； Pkt ——t ℃时的负载损耗，kW；\nPk ——参考温度下的负载损耗，kW； Sr ——额定容量，MVA；',271,'a72f0645-9aa0-4510-960b-3589b83d9e27',417,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.3.2.2  环境温度下损耗和短路阻抗换算到参考温度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27431,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.3.2.3  电阻损耗计算\n\n典型三相变压器一对绕组的电阻损耗应为两绕组电阻损耗之和，计算方法见式（29）和式（30）：\n(\nP\n=\n1.5\nI\n2\nR\n=\n3\nI\n2\nR\n（Y或\nYN\n联结\n的绕组）\n(\n29)\n)\n式中：\nPr ——电阻损耗， kW； I r ——额定电流， A；  Rxn ——线电阻， Ω;\nRxg ——相电阻， Ω。\nJB/T 501—2021',272,'b928df71-8ffd-48d0-a73e-9cf7657e8ae3',215,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.3.2.3  电阻损耗计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27432,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.4  结果判定\n\n按技术协议，但不得低于表 20 的规定。',273,'1534dec2-7052-49a6-bd2d-c8a3d4f1d0a4',59,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27433,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.4  结果判定\n表 20  干式电力变压器负载损耗和短路阻抗的允许偏差\n<table><tr><td colspan=\'2\'>项目</td><td colspan=\'2\'>允许偏差</td></tr><tr><td colspan=\'2\'>负载损耗</td><td colspan=\'2\'>+15%<br/>但总损耗不得超过+10%</td></tr><tr><td rowspan=\'5\'>短路阻抗</td><td rowspan=\'2\'>a)有两个独立绕组的变压器，或<br/>b)多绕组变压器中规定的第一对独立绕组</td><td>主分接</td><td>当阻抗值≥10 ％时，±7.5%当阻抗值&lt;10 ％时，±10%</td></tr><tr><td>其它分接</td><td>当阻抗值≥10 ％时，±10%当阻抗值 &lt;10 ％时，±15%</td></tr><tr><td rowspan=\'2\'>a)自耦联结的一对绕组，或<br/>b)多绕组变压器中规定的第二对绕组</td><td>主分接</td><td>规定值的±10%</td></tr><tr><td>其它分接</td><td>设计值的±10%</td></tr><tr><td>其它绕组对</td><td colspan=\'2\'>按协议，但绝对值不小于15%</td></tr></table>',274,'cae11812-ddee-4513-b70d-488f2dc30629',324,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.4  结果判定"]','TABLE',NULL,'2026-03-11 11:17:43'),(27434,508,'## 4  干式电力变压器试验\n### 4.6  短路阻抗和负载损耗测量\n#### 4.6.5  注意事项\n\n对于低电压、大电流的试品， 电压互感器一次线应连接到试品线端， 以免线路损耗影响测量结果。',275,'720121dc-5ddf-4b3c-921d-6021bc585b2d',84,NULL,'["4  干式电力变压器试验", "4.6  短路阻抗和负载损耗测量", "4.6.5  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27435,508,'## 4  干式电力变压器试验\n### 4.7  空载损耗和空载电流测量\n#### 4.7.1  试验一般要求\n\n变压器的温度接近试验时的环境温度。\n通常由被试品的低压侧施加额定频率的额定电压（应尽可能为对称的正弦波电压），其余绕组开路； 如果施加电压的绕组是带有分接的，则应使分接开关处于主分接的位置。运行中的地电位处宜可靠接地。\n对于三相变压器，选择接到试验电源的绕组和联结方式时，应尽可能使三个心柱上出现对称的正弦 电压。\n如果无其它规定，则对于有不同容量的多绕组变压器，空载电流百分数应换算到最大容量。',276,'c2035a38-2273-4d38-98ef-6339c20dcaba',239,NULL,'["4  干式电力变压器试验", "4.7  空载损耗和空载电流测量", "4.7.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27436,508,'## 4  干式电力变压器试验\n### 4.7  空载损耗和空载电流测量\n#### 4.7.2  测量仪器和精度\n\n空载损耗和空载电流测量对于测量系统的要求低于负载损耗的测量，因此能够满足负载损耗测量的 测量系统适用于空载损耗和空载电流测量。',277,'72ad8374-18fb-4af9-b758-9409b6e66766',105,NULL,'["4  干式电力变压器试验", "4.7  空载损耗和空载电流测量", "4.7.2  测量仪器和精度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27437,508,'## 4  干式电力变压器试验\n### 4.7  空载损耗和空载电流测量\n#### 4.7.3.1  试验接线\n\n单相变压器空试验接线示意图见图29。 三相变压器空试验接线示意图见图30。\nJB/T 501—2021\n图 29  单相变压器空试验接线示意图\n图 30  三相变压器空试验接线示意图',278,'0b52de07-ae89-44c5-ad7c-84454eeb4616',130,NULL,'["4  干式电力变压器试验", "4.7  空载损耗和空载电流测量", "4.7.3.1  试验接线"]','TEXT',NULL,'2026-03-11 11:17:43'),(27438,508,'## 4  干式电力变压器试验\n### 4.7  空载损耗和空载电流测量\n#### 4.7.3.2  试验电压的施加\n\n试验电压的施加应从零开始升压，在升压过程中应连续观察所有测量仪表的指示状况，尤其在测量 过程中，注意剩磁对测量结果的影响，在测量仪器和试验设备不过载的情况下，先对被试品进行 110% 额定电压励磁，降压时尽可能降到零电压，然后进行额定电压励磁，保持几分钟，待损耗和电流没有下 降的趋势，进行测量记录。\n励磁电压应以平均值电压表的读数U 9 为准，该读数与方均根值电压表的读数U具有同一刻度。',279,'57cc4e59-c3a2-437f-8f9d-70f3e3f255cd',239,NULL,'["4  干式电力变压器试验", "4.7  空载损耗和空载电流测量", "4.7.3.2  试验电压的施加"]','TEXT',NULL,'2026-03-11 11:17:43'),(27439,508,'## 4  干式电力变压器试验\n### 4.7  空载损耗和空载电流测量\n#### 4.7.3.3  空载损耗的波形校正\n\n如果U 9 与 U 相差 3%以内，则按照 Po=Pm(1+d)校正，其中 Po 为校正后的空载损耗，Pm 为测量的空 载损耗，d=（ U 9 - U）/U 9 。\n如果U 9 与 U 相差大于 3%，则应按照协议确认试验的有效性。在高于额定电压时，可以接受超过 3%的读数差，但测量值属于保证值的情况除外。',280,'8bb09e57-b12e-498c-b112-d65c74b29521',200,NULL,'["4  干式电力变压器试验", "4.7  空载损耗和空载电流测量", "4.7.3.3  空载损耗的波形校正"]','TEXT',NULL,'2026-03-11 11:17:43'),(27440,508,'## 4  干式电力变压器试验\n### 4.7  空载损耗和空载电流测量\n#### 4.7.4  结果判定\n\n按技术协议的规定。如果技术协议没有规定，则空载电流的允许偏差为+30%，空载损耗的允许偏\nJB/T 501—2021\n差为+15%。',281,'4e82ea17-6d24-4522-b833-8e78e854f911',105,NULL,'["4  干式电力变压器试验", "4.7  空载损耗和空载电流测量", "4.7.4  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27441,508,'## 4  干式电力变压器试验\n### 4.7  空载损耗和空载电流测量\n#### 4.7.5  注意事项\n\n应注意剩磁对空载损耗和空载电流测量的影响。',282,'8855e903-da28-46e8-86ea-c8137e43f45c',60,NULL,'["4  干式电力变压器试验", "4.7  空载损耗和空载电流测量", "4.7.5  注意事项"]','TEXT',NULL,'2026-03-11 11:17:43'),(27442,508,'## 4  干式电力变压器试验\n### 4.8  绝缘电阻测量\n#### 4.8.1  测量仪器和准确度\n\n测量仪器采用数字兆欧表，准确度不低于5%。',283,'6227223b-a0f1-421b-9176-fa6db99a8dd6',59,NULL,'["4  干式电力变压器试验", "4.8  绝缘电阻测量", "4.8.1  测量仪器和准确度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27443,508,'## 4  干式电力变压器试验\n### 4.8  绝缘电阻测量\n#### 4.8.2  测量参数\n\n测量R60（60s时)的绝缘电阻值。',284,'b1ef5ba6-1cd9-46e3-800c-8b33eaeb83ca',52,NULL,'["4  干式电力变压器试验", "4.8  绝缘电阻测量", "4.8.2  测量参数"]','TEXT',NULL,'2026-03-11 11:17:43'),(27444,508,'## 4  干式电力变压器试验\n### 4.8  绝缘电阻测量\n#### 4.8.3  测量组合方式\n\n绝缘电阻测量组合方式见表21。',285,'612b809d-3209-4476-bcbc-510b5ea900c2',51,NULL,'["4  干式电力变压器试验", "4.8  绝缘电阻测量", "4.8.3  测量组合方式"]','TEXT',NULL,'2026-03-11 11:17:43'),(27445,508,'## 4  干式电力变压器试验\n### 4.8  绝缘电阻测量\n#### 4.8.3  测量组合方式\n表 21  绝缘电阻测量组合方式\n<table><tr><td rowspan=\'2\'>顺序号</td><td colspan=\'2\'>双绕组变压器</td><td colspan=\'2\'>三绕组变压器</td></tr><tr><td>被试绕组</td><td>接地部位</td><td>被试绕组</td><td>接地部位</td></tr><tr><td>1</td><td>低压</td><td>铁心、夹件及高压</td><td>低压</td><td>铁心、夹件、高压及中压</td></tr><tr><td>2</td><td>高压</td><td>铁心、夹件及低压</td><td>中压</td><td>铁心、夹件、高压及低压</td></tr><tr><td>3</td><td>——</td><td>——</td><td>高压</td><td>铁心、夹件、中压及低压</td></tr><tr><td>4</td><td>高压及低压</td><td>铁心、夹件</td><td>高压及中压</td><td>铁心、夹件及低压</td></tr><tr><td>5</td><td>——</td><td>——</td><td>高压、中压及低压</td><td>铁心、夹件</td></tr></table>',286,'90240dd5-4d04-48c7-a829-2b814860ebb7',286,NULL,'["4  干式电力变压器试验", "4.8  绝缘电阻测量", "4.8.3  测量组合方式"]','TABLE',NULL,'2026-03-11 11:17:43'),(27446,508,'## 4  干式电力变压器试验\n### 4.9  外施耐压试验\n#### 4.9.1  试验前准备\n\n试品接地点应可靠接地。\n被试绕组端子短接并连接试验变压器，非被试绕组端子短接并可靠接地。',287,'8f738a80-b478-4af4-be6b-43bb0cacbd42',79,NULL,'["4  干式电力变压器试验", "4.9  外施耐压试验", "4.9.1  试验前准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27447,508,'## 4  干式电力变压器试验\n### 4.9  外施耐压试验\n#### 4.9.2.1  一般要求\n\n外施耐压试验的频率应不低于80%额定频率的任意一合适频率。\n试验峰值电压除以  2 作为试验电压。电压的波形应接近正弦波。\n试验电压的允许偏差为±1%。\n用于一般公共配电网或工业电网中的变压器，其绝缘水平应符合表 22 的规定。\nJB/T 501—2021',288,'5692617a-95b6-447e-a496-cd13ca8641fc',163,NULL,'["4  干式电力变压器试验", "4.9  外施耐压试验", "4.9.2.1  一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27448,508,'## 4  干式电力变压器试验\n### 4.9  外施耐压试验\n#### 4.9.2.1  一般要求\n表 22  干式电力变压器绝缘水平单位为千伏\n<table><tr><td rowspan=\'2\'>标称系统电压（方均根值）</td><td rowspan=\'2\'>设备最高电压Um（方均根值）</td><td rowspan=\'2\'>额定短时外施耐受电压<br/>（方均根值）</td><td colspan=\'2\'>额定雷电冲击耐受电压（峰值）</td></tr><tr><td>组Ⅰ</td><td>组Ⅱ</td></tr><tr><td>≤1</td><td>≤1.1</td><td>3</td><td> </td><td> </td></tr><tr><td>3</td><td>3.6</td><td>10</td><td>20</td><td>40</td></tr><tr><td>6</td><td>7.2</td><td>20</td><td>40</td><td>60</td></tr><tr><td>10</td><td>12</td><td>35</td><td>60</td><td>75</td></tr><tr><td>15</td><td>17.5</td><td>38</td><td>75</td><td>95</td></tr><tr><td>20</td><td>24</td><td>50</td><td>95</td><td>125</td></tr><tr><td>35</td><td>40.5</td><td>70</td><td>145</td><td>170</td></tr></table>',289,'89b36c96-b060-4749-b2bf-e1c2497b777b',315,NULL,'["4  干式电力变压器试验", "4.9  外施耐压试验", "4.9.2.1  一般要求"]','TABLE',NULL,'2026-03-11 11:17:43'),(27449,508,'## 4  干式电力变压器试验\n### 4.9  外施耐压试验\n#### 4.9.2.2  用于高海拔处的变压器\n\n当变压器运行地点在海拔 1000m~3000m 之间，而其试验却是在正常海拔处进行时，其额定短时外 施耐受电压值，应根据安装地点的海拔超过 1000m 的部分，以每 100m 增加 1%的方式来提高。至于在 海拔超过 3000m 处运行时，其绝缘水平应由供、需双方协商确定。\n4.9.3  测量系统的不确定度.\n工频测量系统的不确定度为±3%。',290,'d311ed42-bfb0-41ed-aabc-dcf9b7bba411',213,NULL,'["4  干式电力变压器试验", "4.9  外施耐压试验", "4.9.2.2  用于高海拔处的变压器"]','TEXT',NULL,'2026-03-11 11:17:43'),(27450,508,'## 4  干式电力变压器试验\n### 4.9  外施耐压试验\n#### 4.9.4.1  试验接线\n\n外施耐压试验接线示意图见图31。\n图 31  外施耐压试验接线示意图',291,'a39abe78-6dbd-4982-8161-cdd80b9db399',69,NULL,'["4  干式电力变压器试验", "4.9  外施耐压试验", "4.9.4.1  试验接线"]','TEXT',NULL,'2026-03-11 11:17:43'),(27451,508,'## 4  干式电力变压器试验\n### 4.9  外施耐压试验\n#### 4.9.4.2  施加电压程序和方法\n\n试验应从不大于规定试验电压值的1/3电压开始，并与测量相配合尽快地增加到试验电压值，在规 定试验电压下持续1min时间，试验完毕，应将电压迅速地降到1/3规定试验电压以下，并切断电源。',292,'1277c339-2cf4-44eb-b220-0922f36b1e84',133,NULL,'["4  干式电力变压器试验", "4.9  外施耐压试验", "4.9.4.2  施加电压程序和方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27452,508,'## 4  干式电力变压器试验\n### 4.9  外施耐压试验\n#### 4.9.5  结果判定\n\nJB/T 501—2021\n试验过程中，如果电压不突然下降，则试验合格；',293,'44a7d681-62b8-476f-afc2-61e9f9deeb6d',70,NULL,'["4  干式电力变压器试验", "4.9  外施耐压试验", "4.9.5  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27453,508,'## 4  干式电力变压器试验\n### 4.10  感应耐压试验\n#### 4.10.1  试验前准备\n\n试品接地点应可靠接地。\n任何不与试验电源相连的线路端子应开路。',294,'61ee4e65-b492-4a57-bd0c-c447b4f75fbc',68,NULL,'["4  干式电力变压器试验", "4.10  感应耐压试验", "4.10.1  试验前准备"]','TEXT',NULL,'2026-03-11 11:17:43'),(27454,508,'## 4  干式电力变压器试验\n### 4.10  感应耐压试验\n#### 4.10.2  试验一般要求\n\n三相变压器应使用三相对称电源加压。\n带分接的绕组，除非特别指定或由用户同意，一般在主分接进行。 施加的试验电压为两倍额定电压(2×Ur)。\n电压的波形应接近正弦波，试验中电压的峰值与方均根值都应测量，取峰值除以  2 和方均根值两\n者间较小的值作为试验电压值；\n试验电压的允许偏差为±1%。',295,'6102aee7-a339-44a7-957d-be459b2287e1',182,NULL,'["4  干式电力变压器试验", "4.10  感应耐压试验", "4.10.2  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27455,508,'## 4  干式电力变压器试验\n### 4.10  感应耐压试验\n#### 4.10.3  测量系统的不确定度\n\n测量系统的不确定度为±3%。',296,'ca537fcc-1925-473a-9add-f76e32a5518f',55,NULL,'["4  干式电力变压器试验", "4.10  感应耐压试验", "4.10.3  测量系统的不确定度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27456,508,'## 4  干式电力变压器试验\n### 4.10  感应耐压试验\n#### 4.10.4.1  试验接线\n\n感应耐压试验接线示意图见图32。\n图 32  感应耐压试验接线示意图',297,'7dc01632-718c-4bde-b775-fcb8ad2439f8',71,NULL,'["4  干式电力变压器试验", "4.10  感应耐压试验", "4.10.4.1  试验接线"]','TEXT',NULL,'2026-03-11 11:17:43'),(27457,508,'## 4  干式电力变压器试验\n### 4.10  感应耐压试验\n#### 4.10.4.2  施加电压的程序和方法\n\n为了防止试验时励磁电流过大，试验电压频率应适当地比额定频率高。\n除非另有规定，当试验电压的频率等于或小于两倍额定频率时，其全电压下的试验时间应为60s。 当试验频率超过两倍额定频率时，试验时间为：\n120×额定频率/试验频率（s）\n但不少于15s。\nJB/T 501—2021\n试验应从不大于规定试验电压值的1/3电压开始，并与测量相配合尽快地增加到试验电压值，在规 定试验电压下持续到规定时间，试验完毕，应将电压迅速地降到1/3规定试验电压以下，并切断电源。',298,'bffd34f2-c7f2-4724-83d9-e7752ef2d05e',274,NULL,'["4  干式电力变压器试验", "4.10  感应耐压试验", "4.10.4.2  施加电压的程序和方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27458,508,'## 4  干式电力变压器试验\n### 4.10  感应耐压试验\n#### 4.10.5  结果判定\n\n试验过程中，如果电压不出现突然下降，则试验合格。',299,'a5ad9226-fc6e-4691-b912-7544cc8cd9a1',60,NULL,'["4  干式电力变压器试验", "4.10  感应耐压试验", "4.10.5  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27459,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 4.11.1  概述\n\n局部放电测量应在Um ≥3.6kV的绕组上进行。',300,'22a7da9e-96a7-44ba-8c96-e304139f4dc5',58,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "4.11.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27460,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 4.11.2  测量线路\n\n(\nC\n) (\n3\n) (\n2\n) (\nZ\nm\n)局部放电测量线路见图33和图34。',301,'f87d9c39-c4b6-4487-bde2-db4675183331',78,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "4.11.2  测量线路"]','TEXT',NULL,'2026-03-11 11:17:43'),(27461,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 4.11.2  测量线路\n<table><tr><td>1</td><td> </td><td> </td></tr></table>',302,'03b262df-2fe4-47f3-96b1-7f3bcd1f5a99',45,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "4.11.2  测量线路"]','TABLE',NULL,'2026-03-11 11:17:43'),(27462,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 说明：\n\n1——  低压绕组； 2——  高压绕组； 3——  测量仪器。\n图 33  单相变压器局部放电测量的接线示意图\n(\n1\n)2',303,'f53deb23-a888-4470-8532-6b8c5f63a0f0',87,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27463,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 说明：\n\n1——  低压绕组；\n2——  高压绕组，D或Y接； 3——  测量仪器；\nS——  开关。\nC     Zm\n(\nC\n) (\n3\n) (\nS\n) (\nC\n)',304,'3fc2eb7e-ab47-49b2-9117-cea27228272a',99,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27464,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 说明：\n<table><tr><td>Zm</td><td rowspan=\'2\'> </td></tr><tr><td>Zm</td></tr></table>',305,'2a556c83-ca5e-49e7-a4f4-1b61ce7a7ddb',40,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "说明："]','TABLE',NULL,'2026-03-11 11:17:43'),(27465,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 说明：\n\n图 34  三相变压器局部放电测量的接线示意图\nJB/T 501—2021\n图中C为无局部放电的高压耦合电容器（其电容值与校准发生器的电容C0相比应足够大），该电容 器与测量阻抗Zm 串联，且与每个被试高压绕组端子相连接。',306,'13d5910f-d57c-4248-9476-1b348593d8bd',138,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27466,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 4.11.3  测量线路的校准\n\n在绕组内部和测量线路中，均会出现放电脉冲的衰减现象。校准按GB/T 7354的规定进行，将一台 标准放电校准器所产生的模拟放电脉冲施加到变压器被测绕组端子上。为了方便，可使校准发生器的重 复频率与变压器试验时所用电源频率的每半周中有一个脉冲相当。',307,'8640427b-f0bf-4d25-88b2-397192b672e0',162,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "4.11.3  测量线路的校准"]','TEXT',NULL,'2026-03-11 11:17:43'),(27467,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 4.11.4.1  概述\n\n局部放电测量应在所有绝缘试验项目完成后进行。根据变压器是单相还是三相结构，来决定其低压 绕组是由单相电源还是三相电源供电。试验电压波形应尽可能是正弦波，且试验频率应适当地比额定频 率高些， 以免试验期间励磁电流过大。',308,'500fa61d-70bc-4f0a-9919-2695c40b631d',144,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "4.11.4.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27468,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 4.11.4.2.1  例行试验\n\n本试验应在所有的干式变压器上进行，施加电压方式见图35。\nU\n(\n30\ns\n)3 min',309,'088c4274-bdcd-4280-877a-4708ae647ea0',84,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "4.11.4.2.1  例行试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27469,508,'## 4  干式电力变压器试验\n### 4.11  局部放电测量\n#### 4.11.4.2.1  例行试验\n<table><tr><td> </td></tr></table>',310,'c95b3be5-09a4-4ee1-9f45-9ccb1c5b7b4f',41,NULL,'["4  干式电力变压器试验", "4.11  局部放电测量", "4.11.4.2.1  例行试验"]','TABLE',NULL,'2026-03-11 11:17:43'),(27470,508,'## 4  干式电力变压器试验\n### 1.3 Ur\n\nt',311,'a6d3e589-c395-40ff-92fd-7db2803d1e6a',20,NULL,'["4  干式电力变压器试验", "1.3 Ur"]','TEXT',NULL,'2026-03-11 11:17:43'),(27471,508,'## 4  干式电力变压器试验\n### 1.3 Ur\n<table><tr><td colspan=\'2\'> </td></tr><tr><td>U</td><td> </td></tr></table>',312,'f6afcf94-7c2c-4698-a820-299cafd467bb',27,NULL,'["4  干式电力变压器试验", "1.3 Ur"]','TABLE',NULL,'2026-03-11 11:17:43'),(27472,508,'## 4  干式电力变压器试验\n### 1.3 Ur\n\n(\nU\n)\n图 35  局部放电例行试验的施加电压方式\n相间预加电压为1.8Ur（Ur为额定电压），加压时间为30s。然后不切断电源，将相间电压降至1.3Ur， 保持3min，在此期间应进行局部放电测量。',313,'79e6e4a6-3a7f-40b9-be6d-e99e1ef1aed4',120,NULL,'["4  干式电力变压器试验", "1.3 Ur"]','TEXT',NULL,'2026-03-11 11:17:43'),(27473,508,'## 4  干式电力变压器试验\n### 1.3 Ur\n#### 4.11.4.2.2  附加的试验程序（特殊试验）\n\n对于拟接到中性点绝缘的电力系统或接到中性点是通过高阻抗接地的电力系统的变压器，由于它能 在单相对地故障条件下继续运行，故可能要对变压器进行附加的试验。本试验只在用户有规定时才进行， 施加电压方式见图36。\nU',314,'bb34ad83-7b88-4c31-9353-2ad8e5f27383',148,NULL,'["4  干式电力变压器试验", "1.3 Ur", "4.11.4.2.2  附加的试验程序（特殊试验）"]','TEXT',NULL,'2026-03-11 11:17:43'),(27474,508,'## 30 s                      3 min\n\n(\n1.3\nU\nr\n)\nUr\nt\n(\nU\n)\n(\nU\n)\n图 36  局部放电特殊试验的施加电压方式\nJB/T 501—2021\n本试验是在一个线端接地时，先施加相间预加电压1.3Ur ，加压时间30s，然后不切断电源，将相间 电压降至Ur ，保持3min，在此期间应进行局部放电测量。此后，依次将另一个线端接地，重复进行本试 验。',315,'3ab5f6b5-6712-4bd4-939e-2553cb522c1e',176,NULL,'["30 s                      3 min"]','TEXT',NULL,'2026-03-11 11:17:43'),(27475,508,'## 30 s                      3 min\n### 4.11.4.3  单相变压器\n\n对于单相变压器，Ur应视实际情况，为相间电压或相对地电压。\n对于由三台单相变压器组成的三相变压器组，其试验要求应与三相变压器相同。',316,'5b3bce68-cc85-4e35-83dd-2a3eead8c7c8',91,NULL,'["30 s                      3 min", "4.11.4.3  单相变压器"]','TEXT',NULL,'2026-03-11 11:17:43'),(27476,508,'## 30 s                      3 min\n### 4.11.4.3  单相变压器\n#### 4.11.5  局部放电接受水平\n\n局部放电水平的最大值为10pC。\n可能要对装有某些附件（如：避雷器）的变压器进行特殊考虑。',317,'42f9b11f-ea4f-4c5a-977b-0c8319bfefae',87,NULL,'["30 s                      3 min", "4.11.4.3  单相变压器", "4.11.5  局部放电接受水平"]','TEXT',NULL,'2026-03-11 11:17:43'),(27477,508,'## 30 s                      3 min\n### 4.12  有载分接开关试验\n\n见 3.11.1。',318,'c5bfec70-b99b-4046-bbf1-3447c781606f',34,NULL,'["30 s                      3 min", "4.12  有载分接开关试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27478,508,'## 30 s                      3 min\n### 4.13  雷电冲击试验\n#### 4.13.1  一般要求\n\n冲击试验用的波形：1.2μs±30%/50μs±20%。 试验电压值的允许偏差： ±3%。\n测量系统不确定度： ±3%。\n如果分接范围不超过±5%且变压器的额定容量不大于2500kVA，则试验在变压器的主分接上进行。\n如果分接范围超过±5%或变压器的额定容量大于2500kVA，则除非经过同意，否则试验在变压器的 两个极限分接和主分接上进行，在三相变压器的每相或三相组变压器的每台单相变压器上各使用其中的 一个分接进行试验。',319,'f8121283-ad69-43a7-a164-5f798fa78329',247,NULL,'["30 s                      3 min", "4.13  雷电冲击试验", "4.13.1  一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27479,508,'## 30 s                      3 min\n### 4.13  雷电冲击试验\n#### 4.13.2  试验顺序\n\n试验电压应采用负极性。每个线端的试验顺序为：在 50%~70%额定耐受电压下进行一次全波冲击， 在 100%额定耐受电压下进行三次全波冲击。',320,'dc1006c0-562a-4ed1-9031-124f071a2b01',105,NULL,'["30 s                      3 min", "4.13  雷电冲击试验", "4.13.2  试验顺序"]','TEXT',NULL,'2026-03-11 11:17:43'),(27480,508,'## 30 s                      3 min\n### 4.13  雷电冲击试验\n#### 4.13.3  判断准则\n\n如果在降低电压下所记录的电压和电流瞬变波形与在额定耐受电压下所记录的相应的瞬变波形无 明显差异，则试验合格。',321,'90b7f3c9-d550-43da-bda6-495716bfb08b',89,NULL,'["30 s                      3 min", "4.13  雷电冲击试验", "4.13.3  判断准则"]','TEXT',NULL,'2026-03-11 11:17:43'),(27481,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.1  试验一般要求\n\n三相变压器的温升试验应使用三相电源进行。\n在试品周围 2m～3m 处不得有墙壁、热源、杂物堆积及外来辐射气流等干扰，室内可有自然的通 风，但不应引起显著的空气回流。\n对于分接范围不超过±5%，且额定容量不超过 2500kVA 的变压器，在主分接进行温升试验；\n对于分接范围超过±5%的变压器，或额定容量超过 2500kVA 的变压器，在最大电流分接进行温升 试验。\nJB/T 501—2021',322,'c7360a58-c45d-447b-9b82-370cf7e4a291',231,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27482,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.2.1  模拟负载法\n\n本方法适用于非封闭式、封闭式或全封闭式干式自冷或风冷变压器。\n温升值是通过短路试验（提供负载损耗）和空载试验（提供空载损耗）的组合来确定的。\n试验开始时，变压器的温度应与试验室的环境温度一致。应测量高、低压绕组各自的电阻值，这些 测量值将作为计算这两个绕组温升值的基准值。试验室的环境温度也应被测量并记录下来。\n对于三相变压器，其电阻测量应在中间相与一个边相绕组的线端之间进行。\n各温度测量点（即：测环境温度的温度计和变压器上的传感器（如果有））的位置，不论是参考测 量还是最终测量，均应相同。\n绕组短路试验是在一个绕组施加额定电流而另一个绕组短路下进行的，且持续到绕组和铁心温度都 达到稳态时为止。用电阻法或叠加法确定各绕组的温升 Δθc   。\n在额定频率和额定电压下的空载试验，应持续到绕组和铁心温度都达到稳态时为止，然后应测出各 自绕组的温升 Δθe   。\n模拟负载法应采用下述两种方法之一：\n——先进行绕组短路试验，直到铁心和绕组温度达到稳定为止，然后进行空载试验，直到铁心和绕 组温度达到稳定为止；\n——先进行空载试验，直到铁心和绕组温度达到稳定为止，然后进行绕组短路试验，直到铁心和绕 组温度达到稳定为止。\n在绕组通过额定电流和铁心为额定励磁下，每个绕组的总温升 Δθc \'用式（31）来计算：\nK1  ................................................................\n式中：\nΔθc \' ——绕组总温升；\nΔθc   ——短路试验下的绕组温升； Δθe   ——空载试验下的绕组温升；\nK1 ——对于自冷式为0.8；对于风冷式为0.9。',323,'524e74ef-08e6-471f-a019-7b89236e2dc0',736,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.2.1  模拟负载法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27483,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.2.2  相互负载法\n\n如果有两台同样的变压器，且试验室具有必需的试验设备时，采用本方法是合适的。它适用于封闭 式或非封闭式干式自冷或风冷变压器。\n试验开始时，变压器温度应与试验室的环境温度一致。应测量高、低压绕组各自的电阻值，这些测 量值将作为计算这两个绕组温升值的基准值。试验室的环境温度也应被测量并记录下来。\n各温度测量点的位置，不论是参考测量还是最终测量，均应相同。\n对于三相变压器，其电阻测量应在中间相与一个边相绕组的线端之间进行。 对于绕组为星形联结的三相变压器，最好是在中间心柱的绕组上进行测量。\n将两台变压器并联连接，其中一台为被试变压器，且最好是对这两台变压器的内部绕组以被试变压\nJB/T 501—2021\n(\nA\n) (\nB\n)器的额定电压进行励磁。利用两台变压器的电压比不同或另输入某一电压的方法，使被试变压器绕组中 通过额定电流，直到铁心和绕组温度达到稳定时为止。见图37和图38。',324,'31687642-6abe-41c6-99aa-7a275ca9fa31',428,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.2.2  相互负载法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27484,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.2.2  相互负载法\n<table><tr><td> </td><td> </td><td>C</td><td> </td></tr></table>',325,'1808cdbc-a7aa-45c3-aa45-2509e9c85d95',47,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.2.2  相互负载法"]','TABLE',NULL,'2026-03-11 11:17:43'),(27485,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 说明：\n\nA—— 供产生空载损耗的额定频率的电压源；\nB——  供产生负载损耗的额定频率下的额定电流源； C——  增压变压器。\n图 37  单相相互负载法接线示意图\nA\n(\nB\n)\nC',326,'f10cd4be-d961-4915-a62b-73b45c2ad6df',110,NULL,'["30 s                      3 min", "4.14  温升试验", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27486,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 说明：\n\nA——供产生空载损耗的额定频率电压源；\nB——供产生负载损耗的额定频率的额定电流源； C——增压变压器。\n图 38  三相相互负载法接线示意图',327,'f9b3f024-d845-403f-a06e-e3ed43ce23f0',95,NULL,'["30 s                      3 min", "4.14  温升试验", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27487,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.2.3  直接负载法\n\n本方法只适用于小型变压器。\n将变压器的一个绕组，最好是内部绕组在额定电压下励磁，另一个绕组连接适当的负载，以使两个 绕组都通过额定电流。',328,'11c18d03-6726-4ba5-8d7c-576cfa402709',104,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.2.3  直接负载法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27488,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.3  温度测量\n\nJB/T 501—2021',329,'1e4a161e-b957-4a31-a469-dc57fdd317d9',46,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.3  温度测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27489,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.3.1  冷却空气（环境温度）的测量\n\n温度传感器或温度计在试品周围不少于3个，距冷却表面1 m～2m，高度为冷却表面高度的一半。温 度传感器或温度计应插入油量不少于1000ml 的悬空金属油杯中，其时间常数应为2h。',330,'68b428b3-d2d8-4d3c-9840-bc9615dc351b',133,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.3.1  冷却空气（环境温度）的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27490,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.3.2  变压器温度的测量\n\n测量上铁轭的中心处和尽可能靠近最内部低压线圈顶部处的导体。',331,'2ea5ecb1-cca7-4fae-a984-1478700868f9',68,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.3.2  变压器温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27491,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.3.3  绕组温度的测量\n\n绕组温度是靠冷热电阻的变化率决定的；因此准确测量冷热电阻的阻值、冷电阻的绕组温度和热电 阻的冷却介质的温度是极为重要的；具体规定如下：\n——冷电阻和绕组温度测量按 4.4 的相关规定，为了使冷、热电阻的测量误差减小到最低，应记录 冷电阻测量时电源电流、电压、稳定时间等；\n——热电阻的测量要与冷电阻测量时的连线、仪器仪表、电源及电流、电压、稳定时间等完全相同； 切断试验电源时应尽量减少对冷却条件的干扰（保持风扇继续运行），并以最快的速度打开短 路工具，接通电源测量热电阻；要特别注意切断与被测绕组并联的供电回路和电压、功率测量\n回路，否则测量将会失败； ——绕组平均温度的测定；\n——电源切断瞬间的绕组温度的确定。\n绕组平均温度是通过绕组电阻确定的。三相变压器中，最好在中柱进行测量。温度θ2 下的电阻 R2 与θ1 下的电阻 R1 之间的比值见式（32）或式（33）：\n对于铜）     ....................................................... (32)\n对于铝）................................................................. (33)\n— 235          (对于铜)   ................................................ (34)\n— 225      （对于铝）..................................................... (35)\n绕组电阻是在切断电源并去掉短路接线后进行测量， 电源切断瞬间的电阻 R2 按下列规定确定。\n温升试验要求准确测定电源切断瞬间的绕组平均温度。在切断电源和打开短路接线后，立即将要测 的绕组接入直流测量电路， 由于绕组的电气时间常数（L/R）较大，因而只有经过一段时延后，才能测 得准确的电阻值。因绕组在切断电源后开始冷却，绕组电阻随冷却时间变化，故应至少测量10min， 以 便允许用外推法推算电源切断瞬间的绕组温度（见图39）。\nJB/T 501—2021\n图 39  确定切断电源瞬间热电阻温度的方法',332,'4c5329b5-60ae-4131-9916-b3cad0707ce3',952,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.3.3  绕组温度的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27492,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.4  变压器温升计算\n\n4.14.4.1  采用直接负载法、相互负载法、循环电流法或零序法使试品铁心达到额定励磁、绕组达到额\n定负载时，绕组温升按式（37）计算：\n.....................................\n式中：\nΔθ——绕组对空气的温升，K； R1 ——绕组的冷态电阻， Ω;\nR2 ——电源切断瞬间的电阻， Ω;\nθ1   ——绕组的冷态温度， ℃;\nθ2    ——试验最后 1h 内空气的平均温度， ℃; T——温度常数，铜为 235，铝为 225。\n4.14.4.2  当试品铁心达到额定励磁、绕组电流达到 90%及以上额定电流时，绕组温升按式（38）计算：\nΔθ= Δq ............................................\n式中：\nJB/T 501—2021\nΔθt ——负载电流为 It 时绕组对空气的温升，K；\nIr ——额定电流，A； It ——负载电流，A；\nq         空气自冷（AN）为 1.6、风冷（AF）为 1.8。',333,'3ba61261-3108-4e5b-8269-ce0528863745',471,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.4  变压器温升计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27493,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.5  结果判定\n\n按正常运行条件设计的变压器，当按上述规定进行试验时，其每个绕组的温升均不应超过表 23 所 列的相应限值。',334,'a39fc953-350c-4f04-9603-8313aee5dc29',86,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.5  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27494,508,'## 30 s                      3 min\n### 4.14  温升试验\n#### 4.14.5  结果判定\n表 23  绕组温升限值\n<table><tr><td>绝缘系统温度℃</td><td>额定电流下的绕组平均温升限值K</td></tr><tr><td>105（A）</td><td>60</td></tr><tr><td>120（E）</td><td>75</td></tr><tr><td>130（B）</td><td>80</td></tr><tr><td>155（F）</td><td>100</td></tr><tr><td>180（H）</td><td>125</td></tr><tr><td>200</td><td>135</td></tr><tr><td>220</td><td>150</td></tr></table>',335,'11015cd5-0ce5-488a-8c2b-d2ed25d90509',168,NULL,'["30 s                      3 min", "4.14  温升试验", "4.14.5  结果判定"]','TABLE',NULL,'2026-03-11 11:17:43'),(27495,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.1  试验一般要求\n\n声级测定通常采用声压法，也可采用声强法。\n反射物体应尽可能远离被试品，地面的反射面应大于被试品表面积在其上的投影。 如果无其它规定，则是否进行负载电流下的声级测量可按照式（39）估算：\nLWA,IN≈39+18lg(Sr/SP).........................................................................(39)\n式中：\nLWA,IN——变压器在额定电流、额定频率及短路阻抗下的 A 计权声功率级，dB； Sr——额定容量；MVA；\nSP——基准容量，1MVA。\n如果 LWA,IN 值比保证的声功率级低 8dB 或更多时，则负载电流声级测量不必进行。\n如果进行负载电流声级测量，则除试验电流不得低于 70％额定电流外，其它要求与短路阻抗和负 载损耗测量的要求一致。\n应在测量即将开始前和测量刚结束后对测量仪器进行校准。如果标准偏差超过 0.3dB，则本次测量 结果无效，应重新进行测量。\n声压级测量采用 A 计权，应使用仪器的快速响应指示。\n空载声级测量时与空载电流和空载损耗测量的要求一致，负载声级测量时与短路阻抗和负载损耗测 量的要求一致。',336,'fea2a165-ddeb-4a57-8b54-21814f20b81e',543,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.1  试验一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27496,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.2  测量仪器的要求\n\nJB/T 501—2021\n测量用声级计应符合 GB/T 3785.1—2010 和 GB/T 3785.2—2010 中的 1 型声级计，声校准器的偏 差不大于 2dB。\n声级计在测量前和测量后的校准偏差应小于 0.3dB。',337,'cbb28622-ca5d-423a-9e4d-6de916eda9e1',149,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.2  测量仪器的要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27497,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.3  试验接线\n\n空载声级测量时的试验接线与空载电流和空载损耗测量一致，负载声级测量时的试验接线与短路阻 抗和负载损耗测量一致。',338,'39df2117-231f-4410-87c8-66e3b8a67b70',88,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.3  试验接线"]','TEXT',NULL,'2026-03-11 11:17:43'),(27498,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.1.1  带保护外壳的变压器及保护外壳内装有冷却设备的变压器\n\n基准发射面是指由一条围绕变压器的弦线轮廓线，从箱盖顶部垂直移动到箱底所形成的表面。',339,'9843ef0a-33fa-4c6a-bec5-5a62ba7105fa',99,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.1.1  带保护外壳的变压器及保护外壳内装有冷却设备的变压器"]','TEXT',NULL,'2026-03-11 11:17:43'),(27499,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.1.2  无保护外壳的变压器基准发射面确定\n\n基准发射面是指由一条围绕变压器的弦线轮廓线，从变压器顶部垂直移动到其有效部分底面所形成 的表面，但基准发射面不包括框架、外部连线和接线装置以及不影响发射的附件（见图 40）。',340,'7b8e675f-e6ba-453c-9f25-1c1cd1491a35',136,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.1.2  无保护外壳的变压器基准发射面确定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27500,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.1.3  规定轮廓线的确定\n\n对于带保护外壳的变压器及保护外壳内装有冷却设备的变压器，规定的轮廓线应距基准发射面 0.3m。\n对于无保护外壳变压器，规定的轮廓线应距基准发射面 1m。',341,'5197ae88-8184-43db-9230-d7fb16f8b449',117,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.1.3  规定轮廓线的确定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27501,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.1.4  传声器位置的确定\n\n传声器应位于规定轮廓线上，彼此间距大致相等，间距不得大于 1m（见图 40 的尺寸 D）。至少应 设 6 个传声器位置。\nJB/T 501—2021',342,'715cdbc0-9f16-4388-9646-f38e38bb125d',115,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.1.4  传声器位置的确定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27502,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 说明：\n\n1——准发射面；\n2——规定轮廓线；\nh——带框架的铁心高度； D——传声器间距；\nX——测量距离。\n图 40  无保护外壳变压器声级测量的测点示意图',343,'13b81916-2a25-4a63-94cc-6a17d79f5022',99,NULL,'["30 s                      3 min", "4.15  声级测定", "说明："]','TEXT',NULL,'2026-03-11 11:17:43'),(27503,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.2  背景噪声的测量\n\n测量应在背景噪声值近似恒定时进行。\n在即将对试品噪声测量前，应先测出背景噪声的 A 计权声压级。测量背景噪声时，传声器所处的高 度应与测量试品噪声时其所处的高度相同，背景噪声的测量点应在规定的轮廓线上。\n当测量点总数超过 10 个时，允许只在试品周围呈均匀分布的 10 个测量点上测量背景噪声。\n如果背景噪声的声级明显低于试品和背景噪声的合成声级（即差值大于 10dB）,则可仅在一个测量 点上进行背景噪声测量，且不需对所测出的试品的声级进行修正。\n如果试验前、后背景的平均声压级之差大于 3dB，且较高者与未修正的 A 计权声压级之差小于 8dB， 则本次测量无效，应重新进行试验。但是，当未修正的平均 A 计权声压级小于保证值时除外。此时，应 认为试品符合声级保证值的要求。这种情况应在试验报告中予以记录。\n如果两个背景的平均 A 计权声压级中的较高者，与未修正的 A 计权声压级之差小于 3dB，则本次测 量无效，应重新进行试验。但是，当未修正的平均 A 计权声压级小于保证值时除外。此时，应认为试品 符合声级保证值的要求。这种情况应在试验报告中予以记录。\n试验接受准则见表 24。\nJB/T 501—2021',344,'ee3bd689-ad06-4cf3-8e6d-7b62562022fa',546,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.2  背景噪声的测量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27504,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.2  背景噪声的测量\n表 24  试验接受准则\n<table><tr><td>LpA0与较高的LbgA之差</td><td>试验前的LbgA与试验后的LbgA之差</td><td>结论</td></tr><tr><td>≥8dB</td><td>—</td><td>接受</td></tr><tr><td>＜8dB</td><td>＜3dB</td><td>接受</td></tr><tr><td>＜8dB</td><td>&gt;3dB</td><td>重新试验（见注）</td></tr><tr><td>＜3dB</td><td> </td><td>重新试验（见注）</td></tr><tr><td colspan=\'3\'>注：如果LpA0小于保证值，则认为试品符合声级保证值的要求。这种情况宜在试验报告中予以记录。</td></tr></table>',345,'c7b757e0-a0d2-4011-9c0f-be16510320d3',223,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.2  背景噪声的测量"]','TABLE',NULL,'2026-03-11 11:17:43'),(27505,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.3  测量表面积的计算\n\n式中：\nS——测量表面积，m2； h——试品高度，m；\nlm——轮廓线周长，m。',346,'cb06bd07-1242-4daf-8083-75f9e49b1062',79,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.3  测量表面积的计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27506,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.4  环境修正值 K 的计算\n\n环境修正值K按式（42）计算：\nA = αSV     ............................................................................... (42)\n式中：\nK  ——环境修正值。\nS  ——测量表面积，m2。\nSV ——试验室（墙壁、天棚和地面）的总表面积，m2。\nα ——平均吸声系数，工业厂房取 0.15。',347,'c434dbab-945c-4c9d-90eb-6fd964528337',230,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.4  环境修正值 K 的计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27507,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.5  平均声压级计算\n\n未修正的平均声压级由在试品供电时各测点上测得的 A 计权声压级按式（43）计算：\n= 10 lg .................................................................\n式中：\nLpA0  ——未修正的平均声压级，dB；\nLpAi  ——试品供电时各测点上测得的A计权声压级，dB； N——测点总数。\nJB/T 501—2021\n注：当各 LpAi  差别不大于5dB时，可用简单的算术平均值来计算。\n背景噪声的平均 A 计权声压级应根据试验前、后的各测量值分别按式（44）计算：\n= 10 lg .................................................................\n式中：\nLbgA  ——背景噪声的平均A计权声压级，dB； M——测点总数；\nLbgAi  ——各测点上测得的背景噪声 A 计权声压级，dB。 修正的平均 A 计权声压级按式（45）计算：\n= 10 lg - K ..........................................................\n式中：\nLpA  ——修正的平均 A 计权声压级，dB；\nLbgA   —两个计算出的背景噪声平均 A 计权声压级较小者。',348,'84b718af-cb79-46be-8a3f-2b89c098ff1b',602,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.5  平均声压级计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27508,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.6  声功率级计算\n\n试品的 A 计权声功率级LWA 应根据修正的平均 A 计权声压级LpA  按式（46）计算：\nLWA  =  .........................................................................\n式中：\nS—测量表面积， m2。\nSo—基准参考面积，1m2。',349,'09d210e6-8208-4144-9eba-f60f43af5441',194,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.6  声功率级计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27509,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.7  降低的负载电流声功率级计算\n\n如果只能在降低的电流下进行声级测量时，则在额定电流下的声功率级应按式（47）计算：\nLWA,IN  = LWA,IT + 40 lg  ..................................................................\n式中：\nLWA,IN    ——额定电流下的 A 计权声功率级，dB； LWA,IT ——降低电流下的 A 计权声功率级，dB；\nIN ——额定电流，A； IT ——降低电流，A。\nJB/T 501—2021\n该公式只在降低的电流为额定电流的 70%及以上时适用。',350,'0c5eb0cb-356a-4541-bf2f-22ee04915fd6',306,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.7  降低的负载电流声功率级计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27510,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.4.8  空载声功率级和负载电流声功率级合成的计算\n\n对于在额定电压和额定电流下运行的变压器，其 A 计权声功率级LWA,SN  可由 A 计权空载声功率级 LWA,UN  和 A 计权额定电流声功率级LWA,IN 按式（48）来计算：\nLWA,SN  = 10 lg(100.1LWA ,UN    + 100.1LWA ,IN  ) ......................................................... (48)',351,'51b2eed4-b88b-4d3b-a86e-5ba59b3be897',248,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.4.8  空载声功率级和负载电流声功率级合成的计算"]','TEXT',NULL,'2026-03-11 11:17:43'),(27511,508,'## 30 s                      3 min\n### 4.15  声级测定\n#### 4.15.5  结果判定\n\n按 GB/T 22072 、JB/T 10088 要求或技术协议规定。',352,'b77104c8-002b-464a-a53f-88775a032bca',68,NULL,'["30 s                      3 min", "4.15  声级测定", "4.15.5  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27512,508,'## 30 s                      3 min\n### 4.16  短路承受能力试验\n\n见 3.22。',353,'949d87d0-3202-43bb-a03e-52aba758f7b5',32,NULL,'["30 s                      3 min", "4.16  短路承受能力试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27513,508,'## 30 s                      3 min\n### 4.17  环境试验\n#### 4.17.1  概述\n\n本试验用于确定变压器是否符合 4.17.2 所规定的环境等级。\n如果无其它规定，则本试验应在一台包括附件（与试验有关的）在内的装配完整的变压器上进行。 变压器及其附件应该是新的、清洁的，且绝缘件表面应无任何附加处理。',354,'a4c6a4fb-3cf2-4a67-a815-d0b18836e0db',139,NULL,'["30 s                      3 min", "4.17  环境试验", "4.17.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27514,508,'## 30 s                      3 min\n### 4.17  环境试验\n#### 4.17.2  环境等级\n\n干式变压器的环境条件是指湿度、凝露、污秽和环境温度。\n注：上述环境条件不仅对干式变压器的运行是重要的，而且对其在安装前的贮存也是重要的。 根据湿度、冷凝和污秽的程度，规定以下三种不同的环境等级：\n——E0 级：变压器上没有凝露，且污秽可以被忽略。对于清洁、干燥的户内式安装，通常可以达 到这一等级。\n——E1 级：变压器上偶尔有凝露（如：当变压器无励磁时）。可能会出现有限的污秽。 ——E2 级：变压器上经常有凝露或严重的污秽，或两者同时都有。',355,'79d9bd28-f5e3-4f67-ba9e-ccf2d309b134',255,NULL,'["30 s                      3 min", "4.17  环境试验", "4.17.2  环境等级"]','TEXT',NULL,'2026-03-11 11:17:43'),(27515,508,'## 30 s                      3 min\n### 4.17  环境试验\n#### 4.17.3  试验的有效性\n\n在一台变压器上得到的环境试验结果，对基于同一设计准则的其它变压器也有效。这些设计准则为： ——设计概念相同（如：绕组是否被固体绝缘封闭、绕组类型、防护等级等）；\n——主要的绝缘材料相同。',356,'6324de32-ee63-4733-8fcf-9c3e7f463a5d',128,NULL,'["30 s                      3 min", "4.17  环境试验", "4.17.3  试验的有效性"]','TEXT',NULL,'2026-03-11 11:17:43'),(27516,508,'## 30 s                      3 min\n### 4.17  环境试验\n#### 4.17.4.1  试验要求\n\n本试验为凝露试验。\n变压器应放在温度和湿度可以控制的试验箱内。\n试验箱的容积至少为沿变压器外围划线所构成的长方体体积的五倍，变压器任一部位到箱壁、箱顶\nJB/T 501—2021\n和喷嘴之间的距离应不小于变压器带电部件之间的最小相间距离，且不小于 150mm。\n试验箱内的空气温度应能确保在变压器上出现凝露。 试验箱内的湿度应保持在 93%以上。\n水的电导率应在 0.1S/ m～0.3 S/ m 范围内。\n变压器在无励磁状态下，至少在空气相对湿度大于 93%的环境中放置 6h.。 此后，应在 5 min 内对变压器进行如下的感应电压试验：\n——对于拟接到中性点直接接地或经低阻抗接地的电力系统中的变压器，应在 1.1 倍额定电压下励 磁 15 min；\n——对于拟接到中性点绝缘或经高阻抗接地的电力系统中的变压器，应连续承受 3 次且每次为 5min 的感应电压试验。试验时每个高压端子应依次接地，在其它端子与地之间施加 1.1 倍额定电压。\n三相试验也可用单相试验来代替，此时，应将两个不接地相的端子连接在一起。 上述试验最好在试验箱内进行。',357,'f0f5967b-4b0b-4eb6-95cc-5ee58a08e423',509,NULL,'["30 s                      3 min", "4.17  环境试验", "4.17.4.1  试验要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27517,508,'## 30 s                      3 min\n### 4.17  环境试验\n#### 4.17.4.2  结果判定\n\n在施加电压过程中，应无闪络现象发生，且外观检查应无严重的放电痕迹。',358,'a854493d-cf56-42e8-bd95-fa4fa5348f2d',68,NULL,'["30 s                      3 min", "4.17  环境试验", "4.17.4.2  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27518,508,'## 30 s                      3 min\n### 4.17  环境试验\n#### 4.17.5.1  凝露试验\n\n凝露试验与 4.17.4 的规定相同，但水的电导率应在 0.5S/ m～1.5 S/ m 范围内。',359,'7882355e-3e95-41fa-b72b-0de722175fcd',84,NULL,'["30 s                      3 min", "4.17  环境试验", "4.17.5.1  凝露试验"]','TEXT',NULL,'2026-03-11 11:17:43'),(27519,508,'## 30 s                      3 min\n### 4.17  环境试验\n#### 4.17.5.2.1  试验要求\n\n在湿渗透试验开始时，变压器应为干燥状态。试验中，变压器在无励磁状态下，置于试验箱内 144h。 试验箱内的温度为（50±3） ℃, 相对湿度为（90±5）%，在该试验终了时，将变压器置于正常环境条 件中，最迟经过 3h，应对变压器进行外施交流耐压试验和感应交流耐压试验，但施加的试验电压值应 降到标准规定值的 80%。',360,'f3c1bf45-b4d4-426c-a3d4-0fc494731e26',196,NULL,'["30 s                      3 min", "4.17  环境试验", "4.17.5.2.1  试验要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27520,508,'## 30 s                      3 min\n### 4.17  环境试验\n#### 4.17.5.2.2  结果判定\n\n在绝缘试验中应无闪络或击穿现象发生，且外观检查应无严重的放电痕迹。',361,'fcac552d-e304-4e38-9b88-cd66b1b6372f',70,NULL,'["30 s                      3 min", "4.17  环境试验", "4.17.5.2.2  结果判定"]','TEXT',NULL,'2026-03-11 11:17:43'),(27521,508,'## 30 s                      3 min\n### 4.18  气候试验\n#### 4.18.1  概述\n\n本试验（又称为热冲击试验）用于确定变压器是否符合 4.18.2 中规定的气候等级。',362,'1c1919c4-0879-4076-8b25-67376e079798',72,NULL,'["30 s                      3 min", "4.18  气候试验", "4.18.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27522,508,'## 30 s                      3 min\n### 4.18  气候试验\n#### 4.18.2  气候等级\n\n规定以下两种气候等级：\n——C1 级：变压器适合于在不低于-5℃的环境温度下运行，但其运输和贮存时的环境温度可低至 -25℃。\n——C2 级：变压器适合于在低至-25℃的环境温度下运行、运输和贮存。',363,'719c9da8-96df-4927-9cf3-05ad07897cff',132,NULL,'["30 s                      3 min", "4.18  气候试验", "4.18.2  气候等级"]','TEXT',NULL,'2026-03-11 11:17:43'),(27523,508,'## 30 s                      3 min\n### 4.18  气候试验\n#### 4.18.3  试验的有效性\n\nJB/T 501—2021\n在一台变压器上得到的气候试验结果，对基于同一设计准则的其它变压器也有效。这些设计准则为： ——设计概念相同（如：绕组是否被固体绝缘封闭、绕组类型、防护等级等）；\n——绕组平均温升相同； ——导电材料相同；\n——主要的绝缘材料相同。',364,'68699c13-bcd0-4335-be9e-f4dd606f6675',164,NULL,'["30 s                      3 min", "4.18  气候试验", "4.18.3  试验的有效性"]','TEXT',NULL,'2026-03-11 11:17:43'),(27524,508,'## 30 s                      3 min\n### 4.18  气候试验\n#### 4.18.4.1  试验要求\n\n试验应在一台不带外壳（如果有）的完整变压器上进行，被试变压器应置于试验箱内。\n注：按供、需双方协议， 可以对由铁心上取出的所有线圈进行本试验，但最终的绝缘检查宜在这些试验过的线圈重 新套装到变压器铁心后进行。\n试验箱内的环境温度至少应由三个测量点来确定，测量点应距试品外表面 0.1m 处，高度在试品的 1/2 位置处，取各测量点读数的平均值作为环境温度参考值。',365,'f3721ca7-27cb-4841-96cc-1860b2c950c3',216,NULL,'["30 s                      3 min", "4.18  气候试验", "4.18.4.1  试验要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27525,508,'## 30 s                      3 min\n### 4.18  气候试验\n#### 4.18.4.2  试验程序\n\n试验程序如下：\na） 将试验箱内的环境温度在 8h 内逐渐降到（-25±3） ℃, 然后至少保持 12h，直到达到稳定状 态为止；\nb） 此后将试验箱内的环境温度在 4h 内逐渐上升到（-5±3） ℃, 并至少保持 12h，直到达到稳定 状态为止；\nc） 然后对被试绕组（封闭于固体绝缘内）施加两倍额定电流以进行热冲击试验。应将此电流维持 到被试绕组的实测平均温度等于表 23 中给出的绕组平均温升限值加上 40℃（正常使用条件下 的最高环境温度）为止。绕组的平均温度是根据电阻值的变化来确定的。可选择下述方法之一 来进行热冲击试验：\n1)  直流电源试验法：热冲击试验是在将规定的直流电流施加在被试绕组上进行的。对于多相 变压器，此试验电流可施加在串联在一起的所有各相绕组上。\n注：为使各相绕组串联在一起，可能需要拆开绕组的原有连接。\n在试验过程中，绕组平均温度的监测，可直接用测量试验电流和相应电压降的伏安法来进 行。\n2)  交流电源试验法：热冲击试验是在将规定的交流电流施加在被试绕组上进行的，此时，其 余绕组短路。对于多相变压器，宜采用对称电流来进行本试验。在试验过程中，绕组平均 温度的监测，宜采用将直流测量电流叠加到交流试验电流上的方法或其它等效的方法来进 行。\n3)  另一种交流电源试验法：在一个绕组短路的情况下，对变压器施加两倍额定电流，通过固 定在绕组顶部和底部表面处的温度传感器的读数，来监测每个绕组的温度。温度传感器要 通过一种校准试验来进行校准。此校准试验是在实际热冲击试验前的正常环境温度下，通 过施加两倍额定电流来进行的。\n传感器的校准是通过将传感器的读数，与根据绕组电阻值的变化所测定的绕组温升进行 比较来实现的。这样，传感器的读数便被确定为与绕组平均温升限值加上 40℃的值相对 应。应在从低环境温度下开始的试验中，读取同一传感器的读数。\n注：由于变压器各部分的热暂态特性不同，故要注意防止某些绕组出现过热现象。\nd） 热冲击试验后，应将变压器温度恢复到（25±10） ℃。\nJB/T 501—2021',366,'c82599ae-cf34-4e54-9db4-dbb620091672',901,NULL,'["30 s                      3 min", "4.18  气候试验", "4.18.4.2  试验程序"]','TEXT',NULL,'2026-03-11 11:17:43'),(27526,508,'## 30 s                      3 min\n### 4.18  气候试验\n#### 4.18.4.3  评价准则\n\n热冲击试验结束，并至少再经过12h后，应对变压器进行绝缘例行试验（外施耐压试验和感应耐压 试验），但应根据绕组的绝缘水平，将施加的试验电压值降为标准规定值的80％。\n此外，对于绕组被固体绝缘封闭的变压器，应按4.11进行局部放电测量试验，但施加的预加试验电 压值应不大于降低的感应耐压试验的试验电压值（160％额定电压值），所测得的局部放电量应不大于 例行试验中的规定值。\n经外观检查，绕组应无可见的异常现象，如：裂缝或开裂。',367,'e52e0766-c31a-413d-8a5c-78a00731fd9e',248,NULL,'["30 s                      3 min", "4.18  气候试验", "4.18.4.3  评价准则"]','TEXT',NULL,'2026-03-11 11:17:43'),(27527,508,'## 30 s                      3 min\n### 4.18  气候试验\n#### 4.18.5.1  试验要求、试验程序\n\n除下述修改外，试验要求、试验程序与4.18.4.1 、4.18.4.2 的规定相同： 取消4.18.4.2 的b）项， 以便在-25℃下进行热冲击试验。',368,'886092d3-6d57-4933-907a-ba76a44d42f0',116,NULL,'["30 s                      3 min", "4.18  气候试验", "4.18.5.1  试验要求、试验程序"]','TEXT',NULL,'2026-03-11 11:17:43'),(27528,508,'## 30 s                      3 min\n### 4.18  气候试验\n#### 4.18.5.2  评价准则\n\n试验准则与 4.18.4.3 的规定相同。',369,'a7976b4f-6498-4c1d-b8e6-21bda6575975',56,NULL,'["30 s                      3 min", "4.18  气候试验", "4.18.5.2  评价准则"]','TEXT',NULL,'2026-03-11 11:17:43'),(27529,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.1  概述\n\n为使变压器的性能最佳，应使其在燃烧时所逸出的有毒物质和不透明烟雾降至最低程度。因此，要 避免使用含有卤化物的材料。应按4.19.3检测所逸出的腐蚀性及有害性气体。此外，变压器在外部发生 火灾时不应明显助燃。燃烧性能应按4.19.4的试验程序进行评估。',370,'d2f9ccf8-d6e8-4c3f-b728-57ea63c087e9',158,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.1  概述"]','TEXT',NULL,'2026-03-11 11:17:43'),(27530,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.2  燃烧性能等级\n\n规定以下两种燃烧性能等级：\n——F0 级：无须特别考虑火灾危险。除变压器设计中所固有的特性外，不采取特殊的措施来限制 其可燃性。不过，应使其在燃烧时所逸出的有毒物质和不透明烟雾降至最低程度。\n——F1 级：变压器易遭受火灾危险，要求限制其可燃性。应使其在燃烧时所逸出的有毒物质和不 透明烟雾降至最低程度。\n变压器在经过按4.19.4所述程序进行的特殊试验后，应表明其能否符合F1级的要求。',371,'e0e6a56e-4c89-445b-a753-ea4a6c8199a3',231,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.2  燃烧性能等级"]','TEXT',NULL,'2026-03-11 11:17:43'),(27531,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.3  腐蚀性及有害性气体逸出的检测\n\n应从变压器上提取少量可燃性材料，用以检测其在燃烧时所逸出的腐蚀性和有害性气体。\n原则上，该试验将能检测出下述这些成分，即：氯化氢（HCl）、氰化氢（HCN）、溴化氢（HBr）、 氟化氢（HF）、二氧化硫（SO2 ）和甲醛（HCHO）。\n至于试验程序的细节及可接受的限值，可由供、需双方协商确定。',372,'b08c274f-cdf9-4216-8f81-d5f599eb2d9b',192,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.3  腐蚀性及有害性气体逸出的检测"]','TEXT',NULL,'2026-03-11 11:17:43'),(27532,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.4.1  一般要求\n\n本试验应在变压器一个完整的相上进行，完整的相应包括高压（HV）线圈、低压（LV）线圈、铁 心柱和绝缘件，但不包括外壳（如果有）。供试验用的铁心柱也可以用与原铁心柱尺寸及热特性类似的 材料来代替。不应考虑铁轭，将低压引线在该线圈上、下两端面处切去。\nJB/T 501—2021\n被试变压器的圆形线圈外径或非圆形线圈的最大横向尺寸应介于400mm～500mm之间。 注：经过协商，可用尺寸较大或较小的线圈进行本试验。',373,'4e7eaee2-eec6-477d-8126-b6779d9c55b2',243,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.4.1  一般要求"]','TEXT',NULL,'2026-03-11 11:17:43'),(27533,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.4.2  试验的有效性\n\n在一台变压器上得到的燃烧试验结果，对基于同一设计准则的其它变压器也有效。这些设计准则为： ——设计概念相同（如：绕组是否被固体绝缘封闭、绕组类型、防护等级等）；\n——绕组平均温升相同（按表 23）； ——主要的绝缘材料相同。',374,'a3b05d1a-a96a-48d5-bf74-c2b7d344de9c',151,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.4.2  试验的有效性"]','TEXT',NULL,'2026-03-11 11:17:43'),(27534,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.4.3  试验设施\n\n试验箱、火源应符合 GB/T 1094.11  中相应的规定。',375,'32b5eb35-b7a5-4666-8af6-71fc1777f571',67,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.4.3  试验设施"]','TEXT',NULL,'2026-03-11 11:17:43'),(27535,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.5.1  温度\n\n应使用热电偶或等效装置来测量下列各部位的温度： ——进气口；\n——出气口；\n——低压线圈顶部表面（任选）； ——高压线圈顶部表面（任选）；\n——铁心柱或其模拟件的底部和顶部（任选）； ——铁心和低压线圈间的气道中部（任选）；\n——高、低压线圈间的气道中部（任选）。\n注：测量传感器在试品上的置放位置依据GB/T 1094.11中的相应规定。',376,'1a647181-21ae-4113-9c50-f4cde5b740ce',205,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.5.1  温度"]','TEXT',NULL,'2026-03-11 11:17:43'),(27536,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.5.2  其它待测参量\n\n——测量段内可见光的传输，该测量应沿着穿过烟雾的光学通路进行，其长度至少应为 500mm。 注：设透光率为X，实际的光学路径长度为p（单位为m），则换算到1m长光学路径的透光率为：τ=X1/p。\n——进气口的气体流量；\n——烟囱内的气体流量（任选）。',377,'b04cd499-dc2c-428b-a91b-025b192fa420',164,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.5.2  其它待测参量"]','TEXT',NULL,'2026-03-11 11:17:43'),(27537,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.6  不带试品时试验箱的校准\n\n应在24kW的辐射板通电加热至少40min后，对试验箱进行校准。\n应在稳定状态下，将进气段内测得的空气流量调节到在20℃时为0.21×（1±15%）m3/s。当试验装 置以自然气流为基础时，其流量可通过调节阀或等效的装置来调节。而当试验装置采用强迫气流时，其 流量可通过风扇系统来调节。\n注：为了得到稳定条件下的空气流量，可能需要多次调节。',378,'c07fc875-a7cd-426b-8339-54d39008687d',212,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.6  不带试品时试验箱的校准"]','TEXT',NULL,'2026-03-11 11:17:43'),(27538,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.7  试验方法\n\n试品应按下列条件置于试验箱中：\n——外线圈表面与辐射板间的距离约为 175mm；\n——容器内酒精的起始液面与变压器线圈底面间的距离约为 40mm。 注：在某些情况下，供、需双方需根据试品的设计进行协商。\nJB/T 501—2021\n——半圆筒形金属屏应置于辐射板的对面，且应与试品同心；\n——试验开始时，试验箱内部、入口处空气及试品的温度，均应在 15℃~30℃之间； ——应在试验开始前的 5min 内，对容器注入酒精。\n当酒精刚点燃且辐射板（24kW）同时通电时，试验开始。40min后，将辐射板电源切断。应对4.19.5.1 和4.19.5.2所列参量进行记录，记录时间应为从试验开始时至少60min，或为整个试验期间。\n试验前及试验后，均应称出试品的质量，称量的准确度为±0.5％或更高。铁心柱和带绝缘部件的 线圈可以分别称重。',379,'7e1ffa62-ca0d-4405-b55f-7001d99fbf06',403,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.7  试验方法"]','TEXT',NULL,'2026-03-11 11:17:43'),(27539,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.8  试验报告\n\n试验报告应包含下列信息：\n——材料样品的试验结果（如果用户要求）；\n——可燃烧材料的计算质量、热能值（如果可能）及试品质量的测量值；\n——试验箱的校准结果（空气流量、测量段内的温度、调节阀或抽气系统的调节量等）；\n——对试验方法的全面说明，包括酒精燃烧时间和通电加热时间；\n——试验时可燃烧材料的质量损失（准确度为±10％） 及释放热量（MJ）的计算值（如果可能）；\n——整个试验过程的温度记录值，从试验开始起（酒精点燃时开始），每隔 2min 或更短的时间记 录一次；\n——整个试验过程中，在测量段内传输的可见光的连续记录值(%) ;\n——在整个试验过程中，每隔 2min 或更短的时间测量的测量段内的空气流量（m3/s）； ——试品上可见的燃烧状态。',380,'13f9994c-ac63-4b0f-ad9e-255e6a3eecd8',362,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.8  试验报告"]','TEXT',NULL,'2026-03-11 11:17:43'),(27540,508,'## 30 s                      3 min\n### 4.19  燃烧性能试验\n#### 4.19.9  试验结果的评价准则\n\n如果试品满足下列要求，则试验合格：\n——在整个试验过程中，在烟囱内的测量段中的气体对周围环境温度的温升应不超过 420K；\n——辐射板断电后 5min（即试验开始后的 45min），在烟囱内的测量段中的气体对周围环境温度的 温升应不超过 140K，且在 10min 后的测量期间内，此温升值应呈下降趋势；\n——试验开始后 60min，在烟囱内的测量段中的气体温升应不超过 80K，该条件用以表明火焰已经 熄灭；\n——如果储存的热能阻止了自然气流的温度下降，则可允许有较高的温升。\n——在试验开始后的 20min～60min 期间，测量段中透光率（换算到 1m 长的穿过烟雾的光学路径） 的算术平均值应不低于 20％。\n___________________________________',381,'5db511fa-77d0-4093-b96a-2c5a27bf39e3',352,NULL,'["30 s                      3 min", "4.19  燃烧性能试验", "4.19.9  试验结果的评价准则"]','TEXT',NULL,'2026-03-11 11:17:43');
