INSERT INTO `imessages` (`id`,`session_id`,`query`,`question_type`,`params_json`,`answer`,`ordinal`,`document_list`,`file_list`,`consumes_time`,`error`,`status`,`final_query`,`create_user_id`,`updated_at`,`created_at`) VALUES (4,2,'你好','KNOWLEDGE_QA','{"kbId": 50, "topK": 8}','你好！\n\n根据当前提供的知识库内容，未包含与“你好”这一问候语直接相关的信息或上下文。如果你有关于知识库功能、RAG系统、前端交互、ES向量存储等方面的问题，我可以基于已有证据为你解答。\n\n例如，当前知识库中提到了以下几点可能相关的内容：\n\n- 创建知识库时需增加“知识库描述”字段；\n- 必填校验提示应显示在对应输入框附近；\n- 上传文件与否会影响按钮名称（“创建” vs “创建并导入”）及后续流程（是否进入分块预览）；\n- 分块预览中的分隔符缺少默认值，且对如“\\n”这类语义符的支持存在问题；\n- Elasticsearch（ES）仅用于向量存储，存在入库问题 [1][2]。\n\n如有具体问题，请进一步说明！',1,'[{"ref": 1, "docId": 503, "score": 0.0287391216352965, "chunkId": 27069, "indexId": "b05b83f2-a0b2-48aa-b646-47cea95a9808", "snippet": "我需要根据前端功能来调整，现在有如下问题：\\n1 创建知识库，需要加一个知识库描述的字段。\\n2 必填校验提示样式不对，要在对应的输入框提示。\\n3 不上传文件也可以创建。 上传了文件按钮名称是创建并导入。 没上传文件名称就是创建。 上传了文件就到分块预览。没上传文件就直接提示创建成功。\\n4 分块预览哪里分隔符没有默认值。然后输入/n这种语义符好像后台不太支持。\\n5 es向量入库也有问题。 Es只做向量的存储。。 我提供我之前做的。你来参考，", "fileName": "rag.txt"}, {"ref": 2, "docId": 506, "score": 0.02832415420928403, "chunkId": 27116, "indexId": "1797f9c8-7dc3-4802-a77d-3f8888b802ca", "snippet": "我需要根据前端功能来调整，现在有如下问题：\\n1 创建知识库，需要加一个知识库描述的字段。\\n2 必填校验提示样式不对，要在对应的输入框提示。\\n3 不上传文件也可以创建。 上传了文件按钮名称是创建并导入。 没上传文件名称就是创建。 上传了文件就到分块预览。没上传文件就直接提示创建成功。\\n4 分块预览哪里分隔符没有默认值。然后输入/n这种语义符好像后台不太支持。\\n5 es向量入库也有问题。 Es只做向量的存储。。 我提供我之前做的。你来参考，", "fileName": "rag.txt"}, {"ref": 3, "docId": 503, "score": 0.027637721755368813, "chunkId": 27084, "indexId": "6f6f3f4e-3478-43ed-baae-057961f0c854", "snippet": "try {\\n            // 修改后的 textQuery 部分\\n            List<String> decomposedKeywords = param.getKeywords(); // 假设你传进来的是个 List\\n            Query textQuery = Query.of(q -> q\\n                    .bool(b -> {\\n                        // 1. 原有的全文检索（保留语义完整性）\\n          ", "fileName": "rag.txt"}, {"ref": 4, "docId": 506, "score": 0.027252906976744182, "chunkId": 27131, "indexId": "b79da9bb-bfce-45c8-976b-5f5a1361d735", "snippet": "try {\\n            // 修改后的 textQuery 部分\\n            List<String> decomposedKeywords = param.getKeywords(); // 假设你传进来的是个 List\\n            Query textQuery = Query.of(q -> q\\n                    .bool(b -> {\\n                        // 1. 原有的全文检索（保留语义完整性）\\n          ", "fileName": "rag.txt"}, {"ref": 5, "docId": 503, "score": 0.01639344262295082, "chunkId": 27112, "indexId": "0fa5fcdf-e408-4dcc-b7b6-ffe3c5b7dcfc", "snippet": "}", "fileName": "rag.txt"}, {"ref": 6, "docId": 506, "score": 0.016129032258064516, "chunkId": 27159, "indexId": "701d5b31-0c2d-4dd1-b879-a4d6199b2768", "snippet": "}", "fileName": "rag.txt"}, {"ref": 7, "docId": 503, "score": 0.015873015873015872, "chunkId": 27068, "indexId": "997665c9-1846-4bb8-b454-40f6bc9dc087", "snippet": "Cccccccc", "fileName": "rag.txt"}, {"ref": 8, "docId": 506, "score": 0.015625, "chunkId": 27115, "indexId": "d0ea5a98-04ee-41b7-b61e-9dbb1fafaf24", "snippet": "Cccccccc", "fileName": "rag.txt"}]','[]','5944ms',NULL,'normal','你好',1,'2026-03-10 15:02:59','2026-03-10 15:02:53'),(5,3,'你是谁？','KNOWLEDGE_QA','{"kbId": 50, "topK": 8}','我是知识库问答助手，根据提供的知识库内容回答问题。当前知识库中没有关于“我是谁”的直接说明，但根据系统设定和上下文可知：我是一个基于给定证据进行回答的问答助手，仅依据用户提供的知识库内容作答，不编造信息。\n\n在当前提供的证据中，并无明确描述本助手身份的内容，因此该结论主要基于系统初始设定，而非所列证据。若严格限于证据本身，则：\n\n**未在当前知识库中找到充分依据**。',1,'[{"ref": 1, "docId": 503, "score": 0.03125763125763126, "chunkId": 27069, "indexId": "b05b83f2-a0b2-48aa-b646-47cea95a9808", "snippet": "我需要根据前端功能来调整，现在有如下问题：\\n1 创建知识库，需要加一个知识库描述的字段。\\n2 必填校验提示样式不对，要在对应的输入框提示。\\n3 不上传文件也可以创建。 上传了文件按钮名称是创建并导入。 没上传文件名称就是创建。 上传了文件就到分块预览。没上传文件就直接提示创建成功。\\n4 分块预览哪里分隔符没有默认值。然后输入/n这种语义符好像后台不太支持。\\n5 es向量入库也有问题。 Es只做向量的存储。。 我提供我之前做的。你来参考，", "fileName": "rag.txt"}, {"ref": 2, "docId": 506, "score": 0.030776515151515152, "chunkId": 27116, "indexId": "1797f9c8-7dc3-4802-a77d-3f8888b802ca", "snippet": "我需要根据前端功能来调整，现在有如下问题：\\n1 创建知识库，需要加一个知识库描述的字段。\\n2 必填校验提示样式不对，要在对应的输入框提示。\\n3 不上传文件也可以创建。 上传了文件按钮名称是创建并导入。 没上传文件名称就是创建。 上传了文件就到分块预览。没上传文件就直接提示创建成功。\\n4 分块预览哪里分隔符没有默认值。然后输入/n这种语义符好像后台不太支持。\\n5 es向量入库也有问题。 Es只做向量的存储。。 我提供我之前做的。你来参考，", "fileName": "rag.txt"}, {"ref": 3, "docId": 503, "score": 0.029726775956284153, "chunkId": 27084, "indexId": "6f6f3f4e-3478-43ed-baae-057961f0c854", "snippet": "try {\\n            // 修改后的 textQuery 部分\\n            List<String> decomposedKeywords = param.getKeywords(); // 假设你传进来的是个 List\\n            Query textQuery = Query.of(q -> q\\n                    .bool(b -> {\\n                        // 1. 原有的全文检索（保留语义完整性）\\n          ", "fileName": "rag.txt"}, {"ref": 4, "docId": 506, "score": 0.02928692699490662, "chunkId": 27131, "indexId": "b79da9bb-bfce-45c8-976b-5f5a1361d735", "snippet": "try {\\n            // 修改后的 textQuery 部分\\n            List<String> decomposedKeywords = param.getKeywords(); // 假设你传进来的是个 List\\n            Query textQuery = Query.of(q -> q\\n                    .bool(b -> {\\n                        // 1. 原有的全文检索（保留语义完整性）\\n          ", "fileName": "rag.txt"}, {"ref": 5, "docId": 503, "score": 0.01639344262295082, "chunkId": 27068, "indexId": "997665c9-1846-4bb8-b454-40f6bc9dc087", "snippet": "Cccccccc", "fileName": "rag.txt"}, {"ref": 6, "docId": 506, "score": 0.016129032258064516, "chunkId": 27115, "indexId": "d0ea5a98-04ee-41b7-b61e-9dbb1fafaf24", "snippet": "Cccccccc", "fileName": "rag.txt"}, {"ref": 7, "docId": 503, "score": 0.015873015873015872, "chunkId": 27104, "indexId": "27ddbdc1-cdb2-40e2-93de-16665552823b", "snippet": "DeleteByQueryResponse response = esClient.deleteByQuery(d -> d\\n                .index(indexName)\\n                .query(q -> q\\n                        .term(t -> t\\n                                .field(\\"docId.keyword\\") // 注意：字段类型是 keyword\\n                    ", "fileName": "rag.txt"}, {"ref": 8, "docId": 506, "score": 0.015625, "chunkId": 27151, "indexId": "c098c5eb-7723-4b6b-abd4-49564a586bca", "snippet": "DeleteByQueryResponse response = esClient.deleteByQuery(d -> d\\n                .index(indexName)\\n                .query(q -> q\\n                        .term(t -> t\\n                                .field(\\"docId.keyword\\") // 注意：字段类型是 keyword\\n                    ", "fileName": "rag.txt"}]','[]','4996ms',NULL,'normal','你是谁？',1,'2026-03-10 15:20:59','2026-03-10 15:20:53'),(6,4,'你好','SMALL_TALK','{"kbId": 51, "topK": 8, "intent": "SMALL_TALK", "preferKb": false, "routeReason": "MODEL_SMALL_TALK"}','你好！有什么我可以帮你的吗？😊',1,'[]','[]','1013ms',NULL,'normal','你好',1,'2026-03-10 16:00:40','2026-03-10 16:00:39'),(7,4,'你能做什么？','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','以下回答基于通用模型能力，非知识库依据。\n\n我可以回答问题、提供信息、解释概念、协助学习、帮助写作、进行逻辑推理、编程支持等。如果你有任何具体问题或需要帮助，尽管告诉我！',2,'[]','[]','1998ms',NULL,'normal','你能做什么？',1,'2026-03-10 16:00:54','2026-03-10 16:00:51'),(8,4,'西红柿炒鸡蛋怎么做？','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','以下回答基于通用模型能力，非知识库依据。\n\n西红柿炒鸡蛋的做法如下：\n\n1. **准备食材**：鸡蛋2-3个，西红柿1-2个，盐、糖、油适量。\n2. **打蛋**：将鸡蛋打入碗中，加少许盐，搅打均匀。\n3. **切西红柿**：西红柿洗净切块（可去皮，口感更佳）。\n4. **炒鸡蛋**：热锅倒油，油热后倒入蛋液，炒至凝固成块后盛出备用。\n5. **炒西红柿**：锅中再加少许油，放入西红柿翻炒，加入少许盐和糖（糖可中和酸味），炒至出汁。\n6. **合炒**：将炒好的鸡蛋倒回锅中，与西红柿翻炒均匀，尝味调整即可出锅。\n\n小贴士：喜欢汤汁多的可以加一点水；喜欢酸甜口可多加一点糖。',3,'[]','[]','6515ms',NULL,'normal','西红柿炒鸡蛋怎么做？',1,'2026-03-10 16:01:39','2026-03-10 16:01:32'),(9,5,'击穿电压测量的试验目的是什么？','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','击穿电压测量的试验目的主要是：\n\n- **评估绝缘油被水和悬浮杂质污染的程度**。  \n- **判断变压器整体绝缘性能的好坏**：击穿电压越低，说明绝缘性能越差，可能影响变压器的安全运行。  \n- **通过严格测试，确保绝缘油的击穿电压控制在规定范围内**，以保障设备运行的可靠性与安全性 [1]。\n\n因此，该试验是油浸式电力变压器绝缘油试验中的关键项目之一。',1,'[{"ref": 1, "docId": 508, "score": 0.032018442622950824, "chunkId": 27173, "indexId": "0494d5da-3274-46f3-adbc-847dacaccd1c", "snippet": "3 油浸式电力变压器试验\\n3.4 绝缘油试验\\n3.4.2.1 试验目的\\n绝缘油的击穿电压是衡量绝缘油被水和悬浮杂质污染程度的重要指标。油的击穿电压越低，变压器 的整体绝缘性能越差，直接影响变压器的安全运行。因此应严格测试，以便将绝缘油击穿电压控制在不 同范围内。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 2, "docId": 508, "score": 0.031544957774465976, "chunkId": 27174, "indexId": "315582ec-1f16-4475-9e0c-1fec434a1ad4", "snippet": "3 油浸式电力变压器试验\\n3.4 绝缘油试验\\n3.4.2.2 试验方法\\n绝缘油击穿电压测量的试验方法按GB/T 507的规定进行。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 3, "docId": 508, "score": 0.02964254577157803, "chunkId": 27175, "indexId": "b8ef51dc-2104-48ad-9346-1830f1e8ed38", "snippet": "3 油浸式电力变压器试验\\n3.4 绝缘油试验\\n3.4.2.3 试验仪器\\n本导则推荐使用全自动击穿电压测试仪—油试验器，整套仪器应满足以下条件：\\n——油杯：由透明的绝缘材料制成，且对绝缘油和所有清洗剂具有化学惰性。有效容积在 350mL~ 600mL 之间，并带有封盖；\\n——电极：由黄铜或不锈钢磨制而成，形状可以是球形或球盖形（蘑菇形），几何尺寸应满足 GB/T\\n507 的规定， 电极距离为 2.5 mm ±0.05 mm；\\n——调压装置：采用自动升压系统，可采用自耦式调压器或电阻分压器；\\n——变压器：采用低压侧电源", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 4, "docId": 508, "score": 0.029418126757516764, "chunkId": 27180, "indexId": "20b4caf6-e46e-4b05-8d25-9fe68dceb58a", "snippet": "3 油浸式电力变压器试验\\n3.4 绝缘油试验\\n3.4.2.7 结果的判定\\n表 2 绝缘油耐压规定值\\n电压等级kV | 击穿电压kV |\\n≤35 | ≥40 |\\n66～220 | ≥45 |\\n330 | ≥55 |\\n500 | ≥65 |", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 5, "docId": 508, "score": 0.029030910609857977, "chunkId": 27272, "indexId": "995682ca-53fd-4c18-a420-684591604c89", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.4 辅助接线的绝缘试验（AuxW)\\n辅助电源和控制线路的接线应承受 2kV（方均根值）、1min 交流外施电压的对地耐压试验，如果电 压没有突然下降或没有其它击穿特征，则表明通过了试验。\\n电流互感器二次绕组接线应进行 2.5kV（方均根值）、1min 交流外施电压的对地耐压试验，如果互 感器的拐点电压超过交流 2kV，那么试验应在交流 4kV 进行。如果电压没有突然下降或没有其它击穿特 征，则表明通过了试验。\\n辅助设备用的电机和其它二次原件的绝缘要求应符合产品", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 6, "docId": 508, "score": 0.026984126984126985, "chunkId": 27177, "indexId": "8135bcd8-8bf1-4d6c-849d-7660362c57bb", "snippet": "3 油浸式电力变压器试验\\n3.4 绝缘油试验\\n3.4.2.5 试验过程\\n试验过程如下：\\na) 熟悉仪器使用说明书，按要求连接试验仪器并调试正常，且经计量部门检定合格；\\nb) 首次使用时应拆卸电极，用清洗剂彻底清洗电极和油杯，再用蒸馏水清洗几遍，用电吹风彻底 吹干；安装电极时要用标准规调整电极间隙到 2.5mm；正常使用情况下不必每次拆洗电极；\\nc) 将平衡到室温的试油(与环境温度之差小于 5℃)倒入油杯，并洗刷两次，最后倒入油杯的试油 油面至少超过电极 40mm；\\nd) 盖上安全防尘罩，选定标准值，按“开始”键，仪", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 7, "docId": 508, "score": 0.02674825174825175, "chunkId": 27480, "indexId": "90b7f3c9-d550-43da-bda6-495716bfb08b", "snippet": "30 s 3 min\\n4.13 雷电冲击试验\\n4.13.3 判断准则\\n如果在降低电压下所记录的电压和电流瞬变波形与在额定耐受电压下所记录的相应的瞬变波形无 明显差异，则试验合格。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 8, "docId": 508, "score": 0.026140526140526144, "chunkId": 27520, "indexId": "fcac552d-e304-4e38-9b88-cd66b1b6372f", "snippet": "30 s 3 min\\n4.17 环境试验\\n4.17.5.2.2 结果判定\\n在绝缘试验中应无闪络或击穿现象发生，且外观检查应无严重的放电痕迹。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}]','[]','5056ms',NULL,'normal','击穿电压测量的试验目的是什么？',1,'2026-03-11 11:26:02','2026-03-11 11:25:56'),(10,5,'变压器绕组温升限值是多少?','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','变压器绕组温升限值依据绝缘系统温度和冷却方式不同而有所差异，具体如下：\n\n1. **按绝缘系统温度分类的绕组平均温升限值（适用于一般情况）**：\n   - 绝缘系统温度 105℃（A级）：60 K  \n   - 120℃（E级）：75 K  \n   - 130℃（B级）：80 K  \n   - 155℃（F级）：100 K  \n   - 180℃（H级）：125 K  \n   - 200℃：135 K  \n   - 220℃：150 K  \n   [1]\n\n2. **对于油浸式变压器（绝缘系统温度为105℃，使用矿物油或燃点≤300℃的合成液体）**，在正常使用条件下，绕组温升限值规定如下：\n   - **绕组平均温升**：\n     - ON 及 OF 冷却方式：不超过 65 K  \n     - OD 冷却方式：不超过 70 K  \n   - **绕组热点温升**：不超过 78 K  \n   [3]\n\n3. **判定原则**：  \n   按正常运行条件设计的变压器，在温升试验中每个绕组的温升均不应超过上述对应限值 [2]。\n\n综上，绕组温升限值需根据绝缘等级、冷却方式及变压器类型（如油浸式）综合确定。',2,'[{"ref": 1, "docId": 508, "score": 0.03225806451612903, "chunkId": 27494, "indexId": "11015cd5-0ce5-488a-8c2b-d2ed25d90509", "snippet": "30 s 3 min\\n4.14 温升试验\\n4.14.5 结果判定\\n表 23 绕组温升限值\\n绝缘系统温度℃ | 额定电流下的绕组平均温升限值K |\\n105（A） | 60 |\\n120（E） | 75 |\\n130（B） | 80 |\\n155（F） | 100 |\\n180（H） | 125 |\\n200 | 135 |\\n220 | 150 |", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 2, "docId": 508, "score": 0.031099324975891997, "chunkId": 27493, "indexId": "a39fc953-350c-4f04-9603-8313aee5dc29", "snippet": "30 s 3 min\\n4.14 温升试验\\n4.14.5 结果判定\\n按正常运行条件设计的变压器，当按上述规定进行试验时，其每个绕组的温升均不应超过表 23 所 列的相应限值。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 3, "docId": 508, "score": 0.031024531024531024, "chunkId": 27339, "indexId": "65e62f75-5a80-4709-bec9-09f4018d4796", "snippet": "3 油浸式电力变压器试验\\n3.17 温升试验\\n3.17.7 试验结果判断\\n对于绝缘系统温度为 105℃的固体绝缘，绝缘液为矿物油或燃点不大于 300℃的合成液体，在正常 使用条件下温升限值按技术协议规定，但不得高于以下规定限值：\\n——顶层液体温升：60K；\\n——绕组平均温升：65K （ON 及 OF 冷却方式）、70K （OD 冷却方式）； ——绕组热点温升：78K。\\n对于特殊冷却条件下的温升限值，应按照 GB/T 1094.2 的规定进行修正。 油中的许可气体增长率应符合 GB/T 1094.2—2013 中附录", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 4, "docId": 508, "score": 0.031009615384615385, "chunkId": 27336, "indexId": "c2375a1c-a4af-4869-b3aa-585da670b209", "snippet": "3 油浸式电力变压器试验\\n3.17 温升试验\\n3.17.5.7 绕组热点温升确定\\n对于额定容量小于 20/3（MVA/相）的变压器绕组热点温升既不需要直接测量也不需要计算。通常 认为绕组平均温升足以满足热点温升的要求。\\n对于额定容量不小于 20/3（MVA/相）的变压器绕组热点温升应以试验结果为基础计算得出，也可 以通过直接测量得到。\\n根据温升试验结果按照式（9）计算绕组热点温升：\\nΔθh= Δθo+H × g ....................................................", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 5, "docId": 508, "score": 0.030886196246139225, "chunkId": 27323, "indexId": "55099ded-0577-4a71-a873-c42a648f488a", "snippet": "3 油浸式电力变压器试验\\n3.17 温升试验\\n3.17.2 试验一般要求\\n测定稳态温升的标准方法是采用短路接线的等效试验方法。 按照协议也可采用“直接负载法”和“相互负载法”。\\n试验温度应介于 5℃与变压器设计所依据的最高环境温度之间。\\n冷却水的温度应介于 5℃与变压器设计所依据的最高冷却水温度之间。\\n对于分接范围不超过±5%，且额定容量不超过 2500kVA（单相 833kVA）的变压器，在主分接下进行 温升试验。\\n对于分接范围超过±5%的变压器，或额定容量超过 2500kVA（单相 833kVA）的变压器，试验", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 6, "docId": 508, "score": 0.030798389007344232, "chunkId": 27491, "indexId": "4c5329b5-60ae-4131-9916-b3cad0707ce3", "snippet": "30 s 3 min\\n4.14 温升试验\\n4.14.3.3 绕组温度的测量\\n绕组温度是靠冷热电阻的变化率决定的；因此准确测量冷热电阻的阻值、冷电阻的绕组温度和热电 阻的冷却介质的温度是极为重要的；具体规定如下：\\n——冷电阻和绕组温度测量按 4.4 的相关规定，为了使冷、热电阻的测量误差减小到最低，应记录 冷电阻测量时电源电流、电压、稳定时间等；\\n——热电阻的测量要与冷电阻测量时的连线、仪器仪表、电源及电流、电压、稳定时间等完全相同； 切断试验电源时应尽量减少对冷却条件的干扰（保持风扇继续运行），并以最快的速度打开短", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 7, "docId": 508, "score": 0.030536130536130537, "chunkId": 27428, "indexId": "c7ca5fff-fb89-4827-bc32-0634ff236099", "snippet": "4 干式电力变压器试验\\n4.6 短路阻抗和负载损耗测量\\n4.6.3.2.1 参考温度\\n短路阻抗和负载损耗的参考温度应等于绕组平均温升限值加上 20℃。\\n当一台变压器的绕组具有多个不同的绝缘系统温度时，其参考温度应采用与较高绝缘系统温度相对 应的绕组的数值。\\nJB/T 501—2021", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 8, "docId": 508, "score": 0.029631255487269532, "chunkId": 27333, "indexId": "65913cff-0abd-4e8e-a11c-7b84ee2e9587", "snippet": "3 油浸式电力变压器试验\\n3.17 温升试验\\n3.17.5.4.2 绕组平均温度的计算\\n根据测量绕组的电阻值，可按式（7）或式（8）计算绕组平均温度：\\n- 235 （对于铜）......................................................... (7)\\n- 225 （对于铝）......................................................... (8)\\n式中：\\nθ1 ——稳定的环境温度下的绕组温度；\\nθ2 ——电源断开瞬间的绕组", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}]','[]','10609ms',NULL,'normal','变压器绕组温升限值是多少?',1,'2026-03-11 11:26:32','2026-03-11 11:26:21'),(11,5,'感应耐压的试验具体操作步骤','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','感应耐压试验的具体操作步骤如下（基于干式电力变压器的试验要求）：\n\n1. **试验前准备**  \n   - 确保试品接地点可靠接地。  \n   - 所有不与试验电源相连的线路端子应保持开路 [2]。\n\n2. **试验接线**  \n   - 按照标准接线示意图进行连接（见图32）[1]。\n\n3. **试验电源与电压参数设置**  \n   - 三相变压器应使用三相对称电源加压。  \n   - 一般在主分接位置进行试验（除非另有规定或用户同意）。  \n   - 施加的试验电压为 **2倍额定电压（2×Ur）**。  \n   - 电压波形应接近正弦波；试验中需同时测量峰值和方均根值，取 **“峰值 ÷ √2”与方均根值中较小者** 作为试验电压值。  \n   - 试验电压允许偏差为 **±1%** [3]。\n\n4. **施加电压的程序和方法**  \n   - 为防止励磁电流过大，**试验频率应适当高于额定频率**。  \n   - **试验时间根据频率确定**：  \n     - 若试验频率 ≤ 2倍额定频率，全电压下持续 **60秒**；  \n     - 若试验频率 > 2倍额定频率，试验时间为 **120 × 额定频率 / 试验频率（秒）**，但 **不少于15秒** [4]。  \n   - 升压过程：从 **不超过规定试验电压的1/3** 开始，尽快升至规定试验电压，并维持规定时间。  \n   - 试验结束后，**迅速将电压降至1/3规定值以下**，再切断电源 [4]。\n\n5. **结果判定**  \n   - 若试验过程中 **电压未出现突然下降**，则判定为合格 [5]。\n\n> 注：以上步骤主要适用于干式电力变压器。对于油浸式变压器，感应耐压试验（IVW）属于绝缘试验序列中的一项，但具体操作步骤未在所提供证据中详细说明 [7]。',3,'[{"ref": 1, "docId": 508, "score": 0.032266458495966696, "chunkId": 27456, "indexId": "7dc01632-718c-4bde-b775-fcb8ad2439f8", "snippet": "4 干式电力变压器试验\\n4.10 感应耐压试验\\n4.10.4.1 试验接线\\n感应耐压试验接线示意图见图32。\\n图 32 感应耐压试验接线示意图", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 2, "docId": 508, "score": 0.03128054740957967, "chunkId": 27453, "indexId": "61ee4e65-b492-4a57-bd0c-c447b4f75fbc", "snippet": "4 干式电力变压器试验\\n4.10 感应耐压试验\\n4.10.1 试验前准备\\n试品接地点应可靠接地。\\n任何不与试验电源相连的线路端子应开路。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 3, "docId": 508, "score": 0.031009615384615385, "chunkId": 27454, "indexId": "6102aee7-a339-44a7-957d-be459b2287e1", "snippet": "4 干式电力变压器试验\\n4.10 感应耐压试验\\n4.10.2 试验一般要求\\n三相变压器应使用三相对称电源加压。\\n带分接的绕组，除非特别指定或由用户同意，一般在主分接进行。 施加的试验电压为两倍额定电压(2×Ur)。\\n电压的波形应接近正弦波，试验中电压的峰值与方均根值都应测量，取峰值除以 2 和方均根值两\\n者间较小的值作为试验电压值；\\n试验电压的允许偏差为±1%。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 4, "docId": 508, "score": 0.030886196246139225, "chunkId": 27457, "indexId": "bffd34f2-c7f2-4724-83d9-e7752ef2d05e", "snippet": "4 干式电力变压器试验\\n4.10 感应耐压试验\\n4.10.4.2 施加电压的程序和方法\\n为了防止试验时励磁电流过大，试验电压频率应适当地比额定频率高。\\n除非另有规定，当试验电压的频率等于或小于两倍额定频率时，其全电压下的试验时间应为60s。 当试验频率超过两倍额定频率时，试验时间为：\\n120×额定频率/试验频率（s）\\n但不少于15s。\\nJB/T 501—2021\\n试验应从不大于规定试验电压值的1/3电压开始，并与测量相配合尽快地增加到试验电压值，在规 定试验电压下持续到规定时间，试验完毕，应将电压迅速地降到1/3规", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 5, "docId": 508, "score": 0.029418126757516764, "chunkId": 27458, "indexId": "a5ad9226-fc6e-4691-b912-7544cc8cd9a1", "snippet": "4 干式电力变压器试验\\n4.10 感应耐压试验\\n4.10.5 结果判定\\n试验过程中，如果电压不出现突然下降，则试验合格。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 6, "docId": 508, "score": 0.02913851351351351, "chunkId": 27455, "indexId": "ca537fcc-1925-473a-9add-f76e32a5518f", "snippet": "4 干式电力变压器试验\\n4.10 感应耐压试验\\n4.10.3 测量系统的不确定度\\n测量系统的不确定度为±3%。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 7, "docId": 508, "score": 0.028991596638655463, "chunkId": 27170, "indexId": "3b47b27b-c7cb-4d74-95eb-a0400633575f", "snippet": "3 油浸式电力变压器试验\\n3.2 绝缘试验顺序\\n绝缘试验前至少应完成以下试验项目：试验前的绝缘油试验、绕组电阻测量、电压比测量和联结组 标号检定、绕组对地及绕组间直流绝缘电阻测量及铁心和夹件绝缘检查。对于设备最高电压Um>72.5kV 的变压器还应完成绕组对地和绕组间电容测量、绝缘系统电容的介质损耗因数（tanδ) 测量及额定电 压下的空载损耗和空载电流测量。\\n绝缘试验顺序一般应按照GB/T 1094.3的规定进行。试验顺序如下： ——雷电冲击试验（LI、LIC、LIN、LIMT，如果规定)；\\n——操作冲击试验（S", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 8, "docId": 508, "score": 0.028083267871170464, "chunkId": 27526, "indexId": "e52e0766-c31a-413d-8a5c-78a00731fd9e", "snippet": "30 s 3 min\\n4.18 气候试验\\n4.18.4.3 评价准则\\n热冲击试验结束，并至少再经过12h后，应对变压器进行绝缘例行试验（外施耐压试验和感应耐压 试验），但应根据绕组的绝缘水平，将施加的试验电压值降为标准规定值的80％。\\n此外，对于绕组被固体绝缘封闭的变压器，应按4.11进行局部放电测量试验，但施加的预加试验电 压值应不大于降低的感应耐压试验的试验电压值（160％额定电压值），所测得的局部放电量应不大于 例行试验中的规定值。\\n经外观检查，绕组应无可见的异常现象，如：裂缝或开裂。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}]','[]','15076ms',NULL,'normal','感应耐压的试验具体操作步骤',1,'2026-03-11 11:27:14','2026-03-11 11:26:58'),(12,5,'绝缘试验顺序是什么？','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','根据提供的证据，绝缘试验的顺序如下：\n\n在进行绝缘试验前，需先完成以下基础试验项目：  \n- 试验前的绝缘油试验  \n- 绕组电阻测量  \n- 电压比测量和联结组标号检定  \n- 绕组对地及绕组间直流绝缘电阻测量  \n- 铁心和夹件绝缘检查  \n\n对于设备最高电压 Um > 72.5kV 的变压器，还需额外完成：  \n- 绕组对地和绕组间电容测量  \n- 绝缘系统电容的介质损耗因数（tanδ）测量  \n- 额定电压下的空载损耗和空载电流测量 [1]\n\n**正式的绝缘试验顺序一般应按照 GB/T 1094.3 的规定执行，具体为**：  \n1. 雷电冲击试验（LI、LIC、LIN、LIMT，如规定）  \n2. 操作冲击试验（SI，如规定）  \n3. 外施耐压试验（AV）  \n4. 线端交流耐压试验（LTAC，如规定）  \n5. 感应耐压试验（IVW，如规定）  \n6. 带有局部放电测量的感应电压试验（IVPD，如规定）[1]\n\n**特殊说明**：  \n- 若要求进行带有局部放电测量的感应电压试验（IVPD），则该试验应作为**最后一项**绝缘试验。  \n- 经制造方与用户协商同意，可对上述顺序进行少量调整，例如将操作冲击试验安排在雷电冲击试验之前，或在绝缘试验前增加 IVPD 试验 [1]。\n\n综上，绝缘试验的标准顺序以 [1] 所述为准。',4,'[{"ref": 1, "docId": 508, "score": 0.03278688524590164, "chunkId": 27170, "indexId": "3b47b27b-c7cb-4d74-95eb-a0400633575f", "snippet": "3 油浸式电力变压器试验\\n3.2 绝缘试验顺序\\n绝缘试验前至少应完成以下试验项目：试验前的绝缘油试验、绕组电阻测量、电压比测量和联结组 标号检定、绕组对地及绕组间直流绝缘电阻测量及铁心和夹件绝缘检查。对于设备最高电压Um>72.5kV 的变压器还应完成绕组对地和绕组间电容测量、绝缘系统电容的介质损耗因数（tanδ) 测量及额定电 压下的空载损耗和空载电流测量。\\n绝缘试验顺序一般应按照GB/T 1094.3的规定进行。试验顺序如下： ——雷电冲击试验（LI、LIC、LIN、LIMT，如果规定)；\\n——操作冲击试验（S", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 2, "docId": 508, "score": 0.031054405392392875, "chunkId": 27277, "indexId": "224b9873-31b3-47ae-8d4b-556cd58260ae", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.5.4.2 施加电压程序和方法\\n试验应从不大于规定试验电压值的 1/3 电压开始，并与测量相配合尽快地增加到试验电压值，在规 定试验电压下持续 1min 时间，试验完毕，应将电压迅速地降到 1/3 规定试验电压值以下，并切断电源。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 3, "docId": 508, "score": 0.030158730158730156, "chunkId": 27272, "indexId": "995682ca-53fd-4c18-a420-684591604c89", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.4 辅助接线的绝缘试验（AuxW)\\n辅助电源和控制线路的接线应承受 2kV（方均根值）、1min 交流外施电压的对地耐压试验，如果电 压没有突然下降或没有其它击穿特征，则表明通过了试验。\\n电流互感器二次绕组接线应进行 2.5kV（方均根值）、1min 交流外施电压的对地耐压试验，如果互 感器的拐点电压超过交流 2kV，那么试验应在交流 4kV 进行。如果电压没有突然下降或没有其它击穿特 征，则表明通过了试验。\\n辅助设备用的电机和其它二次原件的绝缘要求应符合产品", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 4, "docId": 508, "score": 0.028949545078577336, "chunkId": 27479, "indexId": "dc1006c0-562a-4ed1-9031-124f071a2b01", "snippet": "30 s 3 min\\n4.13 雷电冲击试验\\n4.13.2 试验顺序\\n试验电压应采用负极性。每个线端的试验顺序为：在 50%~70%额定耐受电压下进行一次全波冲击， 在 100%额定耐受电压下进行三次全波冲击。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 5, "docId": 508, "score": 0.0288981288981289, "chunkId": 27445, "indexId": "90240dd5-4d04-48c7-a829-2b814860ebb7", "snippet": "4 干式电力变压器试验\\n4.8 绝缘电阻测量\\n4.8.3 测量组合方式\\n表 21 绝缘电阻测量组合方式\\n顺序号 | 双绕组变压器 | 三绕组变压器 |\\n被试绕组 | 接地部位 | 被试绕组 | 接地部位 |\\n1 | 低压 | 铁心、夹件及高压 | 低压 | 铁心、夹件、高压及中压 |\\n2 | 高压 | 铁心、夹件及低压 | 中压 | 铁心、夹件、高压及低压 |\\n3 | —— | —— | 高压 | 铁心、夹件、中压及低压 |\\n4 | 高压及低压 | 铁心、夹件 | 高压及中压 | 铁心、夹件及低压 |\\n5 | ——", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 6, "docId": 508, "score": 0.02758751902587519, "chunkId": 27297, "indexId": "94112052-f53b-463c-86a0-13bd791bef9d", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.8.4.2 施加电压的程序和方法\\n除非另有规定，当试验电压的频率等于或小于 2 倍额定频率时，试验时间为：\\nJB/T 501—2021\\n120×额定频率/试验频率（s)，但不少于 15s\\n试验应在不大于规定电压的 1/3 电压下接通电源，并与测量相配合尽快升至试验电压值。施加电压 达到规定时间后，应将电压迅速降至试验电压 1/3 下，然后切断电源。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 7, "docId": 508, "score": 0.026973565905412698, "chunkId": 27283, "indexId": "790e6152-36b8-454a-aea1-3e77cd54c11c", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.6.4.2 施加电压的程序和方法\\n为了防止试验时励磁电流过大，试验电压频率应适当地比额定频率高。对于某些产品，励磁电流可 能呈现容性电流，为了防止发电机自励磁现象发生，可以在励磁线路中并联补偿电抗器。\\n除非另有规定，当试验电压的频率等于或小于两倍额定频率时，其全电压下的试验时间应为 60s。 当试验频率超过两倍额定频率时，试验时间为：120×额定频率/试验频率，但不少于 15s。\\n试验应从不大于规定试验电压值的 1/3 电压开始，并与测量相配合尽快地增加到试验", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 8, "docId": 508, "score": 0.02615131578947368, "chunkId": 27290, "indexId": "e7f6997b-b4a8-44a7-bbfb-369f8c0825a1", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.7.4.2 施加电压的程序和方法\\n除非另有规定，当试验电压的频率等于或小于2倍额定频率时，对于Um≤800kV的变压器，其增强电 压下的试验时间应为60s，对于Um>800kV的变压器，其增强电压下的试验时间应为300s，当试验频率超 过2倍额定频率时，试验时间为：\\n120×额定频率/试验频率（s)，但不少于 15s(Um≤800kV) 或\\n600×额定频率/试验频率（s)，但不少于 75s(Um>800kV) 试验顺序如下:\\n—— 在不大于（0.4×Ur ）", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}]','[]','15308ms',NULL,'normal','绝缘试验顺序是什么？',1,'2026-03-11 11:28:22','2026-03-11 11:28:06'),(13,5,'绝缘试验顺序是什么？','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','绝缘试验的顺序如下：\n\n**一、试验前需完成的基础项目**  \n在进行绝缘试验前，必须至少完成以下试验：  \n- 试验前的绝缘油试验  \n- 绕组电阻测量  \n- 电压比测量和联结组标号检定  \n- 绕组对地及绕组间直流绝缘电阻测量  \n- 铁心和夹件绝缘检查  \n\n对于设备最高电压 Um > 72.5kV 的变压器，还需额外完成：  \n- 绕组对地和绕组间电容测量  \n- 绝缘系统电容的介质损耗因数（tanδ）测量  \n- 额定电压下的空载损耗和空载电流测量 [1]\n\n**二、正式绝缘试验的标准顺序**  \n按照 GB/T 1094.3 的规定，绝缘试验的一般顺序为：  \n1. 雷电冲击试验（LI、LIC、LIN、LIMT，如规定）  \n2. 操作冲击试验（SI，如规定）  \n3. 外施耐压试验（AV）  \n4. 线端交流耐压试验（LTAC，如规定）  \n5. 感应耐压试验（IVW，如规定）  \n6. 带有局部放电测量的感应电压试验（IVPD，如规定）[1]\n\n**三、特殊规定与调整**  \n- 若规定需进行带有局部放电测量的感应电压试验（IVPD），则该试验**必须作为最后一项**绝缘试验 [1]。  \n- 经制造方与用户协商同意，可对上述顺序进行少量调整，例如：  \n  - 将操作冲击试验安排在雷电冲击试验之前；  \n  - 在绝缘试验前增加 IVPD 试验 [1]。\n\n综上，绝缘试验顺序以 [1] 所述为准。',5,'[{"ref": 1, "docId": 508, "score": 0.03278688524590164, "chunkId": 27170, "indexId": "3b47b27b-c7cb-4d74-95eb-a0400633575f", "snippet": "3 油浸式电力变压器试验\\n3.2 绝缘试验顺序\\n绝缘试验前至少应完成以下试验项目：试验前的绝缘油试验、绕组电阻测量、电压比测量和联结组 标号检定、绕组对地及绕组间直流绝缘电阻测量及铁心和夹件绝缘检查。对于设备最高电压Um>72.5kV 的变压器还应完成绕组对地和绕组间电容测量、绝缘系统电容的介质损耗因数（tanδ) 测量及额定电 压下的空载损耗和空载电流测量。\\n绝缘试验顺序一般应按照GB/T 1094.3的规定进行。试验顺序如下： ——雷电冲击试验（LI、LIC、LIN、LIMT，如果规定)；\\n——操作冲击试验（S", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 2, "docId": 508, "score": 0.031054405392392875, "chunkId": 27277, "indexId": "224b9873-31b3-47ae-8d4b-556cd58260ae", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.5.4.2 施加电压程序和方法\\n试验应从不大于规定试验电压值的 1/3 电压开始，并与测量相配合尽快地增加到试验电压值，在规 定试验电压下持续 1min 时间，试验完毕，应将电压迅速地降到 1/3 规定试验电压值以下，并切断电源。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 3, "docId": 508, "score": 0.030158730158730156, "chunkId": 27272, "indexId": "995682ca-53fd-4c18-a420-684591604c89", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.4 辅助接线的绝缘试验（AuxW)\\n辅助电源和控制线路的接线应承受 2kV（方均根值）、1min 交流外施电压的对地耐压试验，如果电 压没有突然下降或没有其它击穿特征，则表明通过了试验。\\n电流互感器二次绕组接线应进行 2.5kV（方均根值）、1min 交流外施电压的对地耐压试验，如果互 感器的拐点电压超过交流 2kV，那么试验应在交流 4kV 进行。如果电压没有突然下降或没有其它击穿特 征，则表明通过了试验。\\n辅助设备用的电机和其它二次原件的绝缘要求应符合产品", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 4, "docId": 508, "score": 0.028949545078577336, "chunkId": 27479, "indexId": "dc1006c0-562a-4ed1-9031-124f071a2b01", "snippet": "30 s 3 min\\n4.13 雷电冲击试验\\n4.13.2 试验顺序\\n试验电压应采用负极性。每个线端的试验顺序为：在 50%~70%额定耐受电压下进行一次全波冲击， 在 100%额定耐受电压下进行三次全波冲击。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 5, "docId": 508, "score": 0.0288981288981289, "chunkId": 27445, "indexId": "90240dd5-4d04-48c7-a829-2b814860ebb7", "snippet": "4 干式电力变压器试验\\n4.8 绝缘电阻测量\\n4.8.3 测量组合方式\\n表 21 绝缘电阻测量组合方式\\n顺序号 | 双绕组变压器 | 三绕组变压器 |\\n被试绕组 | 接地部位 | 被试绕组 | 接地部位 |\\n1 | 低压 | 铁心、夹件及高压 | 低压 | 铁心、夹件、高压及中压 |\\n2 | 高压 | 铁心、夹件及低压 | 中压 | 铁心、夹件、高压及低压 |\\n3 | —— | —— | 高压 | 铁心、夹件、中压及低压 |\\n4 | 高压及低压 | 铁心、夹件 | 高压及中压 | 铁心、夹件及低压 |\\n5 | ——", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 6, "docId": 508, "score": 0.02758751902587519, "chunkId": 27297, "indexId": "94112052-f53b-463c-86a0-13bd791bef9d", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.8.4.2 施加电压的程序和方法\\n除非另有规定，当试验电压的频率等于或小于 2 倍额定频率时，试验时间为：\\nJB/T 501—2021\\n120×额定频率/试验频率（s)，但不少于 15s\\n试验应在不大于规定电压的 1/3 电压下接通电源，并与测量相配合尽快升至试验电压值。施加电压 达到规定时间后，应将电压迅速降至试验电压 1/3 下，然后切断电源。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 7, "docId": 508, "score": 0.026973565905412698, "chunkId": 27283, "indexId": "790e6152-36b8-454a-aea1-3e77cd54c11c", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.6.4.2 施加电压的程序和方法\\n为了防止试验时励磁电流过大，试验电压频率应适当地比额定频率高。对于某些产品，励磁电流可 能呈现容性电流，为了防止发电机自励磁现象发生，可以在励磁线路中并联补偿电抗器。\\n除非另有规定，当试验电压的频率等于或小于两倍额定频率时，其全电压下的试验时间应为 60s。 当试验频率超过两倍额定频率时，试验时间为：120×额定频率/试验频率，但不少于 15s。\\n试验应从不大于规定试验电压值的 1/3 电压开始，并与测量相配合尽快地增加到试验", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 8, "docId": 508, "score": 0.02615131578947368, "chunkId": 27290, "indexId": "e7f6997b-b4a8-44a7-bbfb-369f8c0825a1", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.7.4.2 施加电压的程序和方法\\n除非另有规定，当试验电压的频率等于或小于2倍额定频率时，对于Um≤800kV的变压器，其增强电 压下的试验时间应为60s，对于Um>800kV的变压器，其增强电压下的试验时间应为300s，当试验频率超 过2倍额定频率时，试验时间为：\\n120×额定频率/试验频率（s)，但不少于 15s(Um≤800kV) 或\\n600×额定频率/试验频率（s)，但不少于 75s(Um>800kV) 试验顺序如下:\\n—— 在不大于（0.4×Ur ）", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}]','[]','15535ms',NULL,'normal','绝缘试验顺序是什么？',1,'2026-03-11 11:34:28','2026-03-11 11:34:06'),(14,5,'绝缘试验顺序是什么？','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','根据提供的证据，绝缘试验顺序如下：\n\n在进行绝缘试验前，应至少完成以下试验项目：\n- 试验前的绝缘油试验\n- 绕组电阻测量\n- 电压比测量和联结组标号检定\n- 绕组对地及绕组间直流绝缘电阻测量\n- 铁心和夹件绝缘检查\n\n对于设备最高电压Um>72.5kV的变压器，还需完成：\n- 绕组对地和绕组间电容测量\n- 绝缘系统电容的介质损耗因数（tanδ) 测量\n- 额定电压下的空载损耗和空载电流测量\n\n绝缘试验的一般顺序按照GB/T 1094.3的规定进行，具体如下[1]：\n1. 雷电冲击试验（LI、LIC、LIN、LIMT，如果规定）\n2. 操作冲击试验（SI，如果规定）\n3. 外施耐压试验（AV）\n4. 线端交流耐压试验（LTAC，如果规定）\n5. 感应耐压试验（IVW，如果规定）\n6. 带有局部放电测量的感应电压试验（IVPD，如果规定）\n\n特别注意：如果要求了带有局部放电测量的感应电压试验（IVPD），那么该试验应作为最后的绝缘试验。此外，经制造方与用户协商同意也可以进行少量的更改，例如操作冲击可以在雷电冲击试验前进行，或在绝缘试验前增加带有局部放电测量的感应电压试验（IVPD）[1]。',6,'[{"ref": 1, "docId": 508, "score": 0.8129753816923002, "chunkId": 27170, "indexId": "3b47b27b-c7cb-4d74-95eb-a0400633575f", "snippet": "3 油浸式电力变压器试验\\n3.2 绝缘试验顺序\\n绝缘试验前至少应完成以下试验项目：试验前的绝缘油试验、绕组电阻测量、电压比测量和联结组 标号检定、绕组对地及绕组间直流绝缘电阻测量及铁心和夹件绝缘检查。对于设备最高电压Um>72.5kV 的变压器还应完成绕组对地和绕组间电容测量、绝缘系统电容的介质损耗因数（tanδ) 测量及额定电 压下的空载损耗和空载电流测量。\\n绝缘试验顺序一般应按照GB/T 1094.3的规定进行。试验顺序如下： ——雷电冲击试验（LI、LIC、LIN、LIMT，如果规定)；\\n——操作冲击试验（S", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 2, "docId": 508, "score": 0.4212566051796735, "chunkId": 27290, "indexId": "e7f6997b-b4a8-44a7-bbfb-369f8c0825a1", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.7.4.2 施加电压的程序和方法\\n除非另有规定，当试验电压的频率等于或小于2倍额定频率时，对于Um≤800kV的变压器，其增强电 压下的试验时间应为60s，对于Um>800kV的变压器，其增强电压下的试验时间应为300s，当试验频率超 过2倍额定频率时，试验时间为：\\n120×额定频率/试验频率（s)，但不少于 15s(Um≤800kV) 或\\n600×额定频率/试验频率（s)，但不少于 75s(Um>800kV) 试验顺序如下:\\n—— 在不大于（0.4×Ur ）", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 3, "docId": 508, "score": 0.2947049456911233, "chunkId": 27445, "indexId": "90240dd5-4d04-48c7-a829-2b814860ebb7", "snippet": "4 干式电力变压器试验\\n4.8 绝缘电阻测量\\n4.8.3 测量组合方式\\n表 21 绝缘电阻测量组合方式\\n顺序号 | 双绕组变压器 | 三绕组变压器 |\\n被试绕组 | 接地部位 | 被试绕组 | 接地部位 |\\n1 | 低压 | 铁心、夹件及高压 | 低压 | 铁心、夹件、高压及中压 |\\n2 | 高压 | 铁心、夹件及低压 | 中压 | 铁心、夹件、高压及低压 |\\n3 | —— | —— | 高压 | 铁心、夹件、中压及低压 |\\n4 | 高压及低压 | 铁心、夹件 | 高压及中压 | 铁心、夹件及低压 |\\n5 | ——", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 4, "docId": 508, "score": 0.22264793071140587, "chunkId": 27272, "indexId": "995682ca-53fd-4c18-a420-684591604c89", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.4 辅助接线的绝缘试验（AuxW)\\n辅助电源和控制线路的接线应承受 2kV（方均根值）、1min 交流外施电压的对地耐压试验，如果电 压没有突然下降或没有其它击穿特征，则表明通过了试验。\\n电流互感器二次绕组接线应进行 2.5kV（方均根值）、1min 交流外施电压的对地耐压试验，如果互 感器的拐点电压超过交流 2kV，那么试验应在交流 4kV 进行。如果电压没有突然下降或没有其它击穿特 征，则表明通过了试验。\\n辅助设备用的电机和其它二次原件的绝缘要求应符合产品", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 5, "docId": 508, "score": 0.19894814401016764, "chunkId": 27263, "indexId": "e2e2f6c6-d6b5-4e44-abe0-04423e84e4ed", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.1 绝缘试验的一般要求\\n对于油浸式变压器绝缘试验仅适用于内绝缘。外绝缘补充要求或试验应由制造方与用户商定。\\n在进行绝缘试验时，如果有必要，则可以对套管端子采取屏蔽措施，但是与套管端子相邻的接地部 分的任何屏蔽应视为运行时变压器的一部分，局部放电试验期间所需要的屏蔽除外。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 6, "docId": 508, "score": 0.18903256661752385, "chunkId": 27277, "indexId": "224b9873-31b3-47ae-8d4b-556cd58260ae", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.5.4.2 施加电压程序和方法\\n试验应从不大于规定试验电压值的 1/3 电压开始，并与测量相配合尽快地增加到试验电压值，在规 定试验电压下持续 1min 时间，试验完毕，应将电压迅速地降到 1/3 规定试验电压值以下，并切断电源。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 7, "docId": 508, "score": 0.1884929057888906, "chunkId": 27264, "indexId": "42550085-0d35-4221-b524-d7564fc84105", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.2 不同类别变压器的绝缘试验项目\\n变压器的绝缘试验项目是按被试变压器中最高电压绕组 Um 值确定的，试验项目见表 10。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 8, "docId": 508, "score": 0.18413966084491967, "chunkId": 27294, "indexId": "d80e30b0-e594-477a-9cf7-2a3be854b0ff", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.8.2 试验一般要求\\n本试验的目的是考核分级绝缘绕组每个线端对地的耐压试验，而不以相间和匝间的电压试验为目 的。该项试验是对操作冲击试验的有效补充。\\n对于带分接绕组的变压器，应选择合适的分接使被试绕组产生所要求的电压，其它绕组端子出现的 电压尽可能接近于所要求的试验电压值。\\n受试验设备和产品结构限制时，较低电压绕组端子承受的试验电压不应比规定电压低 8%。 如果无其它规定，则分接位置和感应倍数由制造方确定。\\n电压的波形应接近正弦波，试验中电压的峰值与方均根值都", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}]','[]','12366ms',NULL,'normal','绝缘试验顺序是什么？',1,'2026-03-11 11:42:16','2026-03-11 11:41:42'),(15,5,'绝缘试验顺序是什么？','KB_QA','{"kbId": 51, "topK": 8, "intent": "KB_QA", "preferKb": false, "routeReason": "MODEL_KB_QA"}','根据当前知识库中的证据，绝缘试验顺序如下：\n\n一、试验前的必要准备工作  \n在进行绝缘试验前，至少应完成以下项目：  \n- 试验前的绝缘油试验  \n- 绕组电阻测量  \n- 电压比测量和联结组标号检定  \n- 绕组对地及绕组间直流绝缘电阻测量  \n- 铁心和夹件绝缘检查  \n\n对于设备最高电压 Um > 72.5 kV 的变压器，还应额外完成：  \n- 绕组对地和绕组间电容测量  \n- 绝缘系统电容的介质损耗因数（tanδ）测量  \n- 额定电压下的空载损耗和空载电流测量  \n[1]\n\n二、绝缘试验的标准顺序  \n绝缘试验一般应按照 GB/T 1094.3 的规定进行，具体顺序为：  \n1. 雷电冲击试验（LI、LIC、LIN、LIMT，如规定）  \n2. 操作冲击试验（SI，如规定）  \n3. 外施耐压试验（AV）  \n4. 线端交流耐压试验（LTAC，如规定）  \n5. 感应耐压试验（IVW，如规定）  \n6. 带有局部放电测量的感应电压试验（IVPD，如规定）  \n\n特别说明：  \n- 若要求进行 IVPD 试验，则该试验应作为**最后一项**绝缘试验执行。  \n- 经制造方与用户协商同意，可对上述顺序进行少量调整，例如将操作冲击试验安排在雷电冲击试验之前，或在绝缘试验前增加 IVPD 试验。  \n[1]\n\n注：以上内容仅适用于油浸式电力变压器，依据文件《JBT 501-2021 电力变压器试验导则》第3.2节。其他类型（如干式）变压器的绝缘试验顺序未在所提供证据中明确说明。',7,'[{"ref": 1, "docId": 508, "score": 0.8129753816923002, "chunkId": 27170, "indexId": "3b47b27b-c7cb-4d74-95eb-a0400633575f", "snippet": "3 油浸式电力变压器试验\\n3.2 绝缘试验顺序\\n绝缘试验前至少应完成以下试验项目：试验前的绝缘油试验、绕组电阻测量、电压比测量和联结组 标号检定、绕组对地及绕组间直流绝缘电阻测量及铁心和夹件绝缘检查。对于设备最高电压Um>72.5kV 的变压器还应完成绕组对地和绕组间电容测量、绝缘系统电容的介质损耗因数（tanδ) 测量及额定电 压下的空载损耗和空载电流测量。\\n绝缘试验顺序一般应按照GB/T 1094.3的规定进行。试验顺序如下： ——雷电冲击试验（LI、LIC、LIN、LIMT，如果规定)；\\n——操作冲击试验（S", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 2, "docId": 508, "score": 0.4214574006557065, "chunkId": 27290, "indexId": "e7f6997b-b4a8-44a7-bbfb-369f8c0825a1", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.7.4.2 施加电压的程序和方法\\n除非另有规定，当试验电压的频率等于或小于2倍额定频率时，对于Um≤800kV的变压器，其增强电 压下的试验时间应为60s，对于Um>800kV的变压器，其增强电压下的试验时间应为300s，当试验频率超 过2倍额定频率时，试验时间为：\\n120×额定频率/试验频率（s)，但不少于 15s(Um≤800kV) 或\\n600×额定频率/试验频率（s)，但不少于 75s(Um>800kV) 试验顺序如下:\\n—— 在不大于（0.4×Ur ）", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 3, "docId": 508, "score": 0.2947049456911233, "chunkId": 27445, "indexId": "90240dd5-4d04-48c7-a829-2b814860ebb7", "snippet": "4 干式电力变压器试验\\n4.8 绝缘电阻测量\\n4.8.3 测量组合方式\\n表 21 绝缘电阻测量组合方式\\n顺序号 | 双绕组变压器 | 三绕组变压器 |\\n被试绕组 | 接地部位 | 被试绕组 | 接地部位 |\\n1 | 低压 | 铁心、夹件及高压 | 低压 | 铁心、夹件、高压及中压 |\\n2 | 高压 | 铁心、夹件及低压 | 中压 | 铁心、夹件、高压及低压 |\\n3 | —— | —— | 高压 | 铁心、夹件、中压及低压 |\\n4 | 高压及低压 | 铁心、夹件 | 高压及中压 | 铁心、夹件及低压 |\\n5 | ——", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 4, "docId": 508, "score": 0.22264793071140587, "chunkId": 27272, "indexId": "995682ca-53fd-4c18-a420-684591604c89", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.4 辅助接线的绝缘试验（AuxW)\\n辅助电源和控制线路的接线应承受 2kV（方均根值）、1min 交流外施电压的对地耐压试验，如果电 压没有突然下降或没有其它击穿特征，则表明通过了试验。\\n电流互感器二次绕组接线应进行 2.5kV（方均根值）、1min 交流外施电压的对地耐压试验，如果互 感器的拐点电压超过交流 2kV，那么试验应在交流 4kV 进行。如果电压没有突然下降或没有其它击穿特 征，则表明通过了试验。\\n辅助设备用的电机和其它二次原件的绝缘要求应符合产品", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 5, "docId": 508, "score": 0.19894814401016764, "chunkId": 27263, "indexId": "e2e2f6c6-d6b5-4e44-abe0-04423e84e4ed", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.1 绝缘试验的一般要求\\n对于油浸式变压器绝缘试验仅适用于内绝缘。外绝缘补充要求或试验应由制造方与用户商定。\\n在进行绝缘试验时，如果有必要，则可以对套管端子采取屏蔽措施，但是与套管端子相邻的接地部 分的任何屏蔽应视为运行时变压器的一部分，局部放电试验期间所需要的屏蔽除外。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 6, "docId": 508, "score": 0.1889926079688915, "chunkId": 27277, "indexId": "224b9873-31b3-47ae-8d4b-556cd58260ae", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.5.4.2 施加电压程序和方法\\n试验应从不大于规定试验电压值的 1/3 电压开始，并与测量相配合尽快地增加到试验电压值，在规 定试验电压下持续 1min 时间，试验完毕，应将电压迅速地降到 1/3 规定试验电压值以下，并切断电源。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 7, "docId": 508, "score": 0.1884929057888906, "chunkId": 27264, "indexId": "42550085-0d35-4221-b524-d7564fc84105", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.2 不同类别变压器的绝缘试验项目\\n变压器的绝缘试验项目是按被试变压器中最高电压绕组 Um 值确定的，试验项目见表 10。", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}, {"ref": 8, "docId": 508, "score": 0.1841698424246613, "chunkId": 27294, "indexId": "d80e30b0-e594-477a-9cf7-2a3be854b0ff", "snippet": "3 油浸式电力变压器试验\\n3.10 绝缘试验\\n3.10.8.2 试验一般要求\\n本试验的目的是考核分级绝缘绕组每个线端对地的耐压试验，而不以相间和匝间的电压试验为目 的。该项试验是对操作冲击试验的有效补充。\\n对于带分接绕组的变压器，应选择合适的分接使被试绕组产生所要求的电压，其它绕组端子出现的 电压尽可能接近于所要求的试验电压值。\\n受试验设备和产品结构限制时，较低电压绕组端子承受的试验电压不应比规定电压低 8%。 如果无其它规定，则分接位置和感应倍数由制造方确定。\\n电压的波形应接近正弦波，试验中电压的峰值与方均根值都", "fileName": "JBT 501-2021 电力变压器试验导则.docx"}]','[]','15190ms',NULL,'normal','绝缘试验顺序是什么？',1,'2026-03-11 11:55:30','2026-03-11 11:55:14'),(16,6,'你好','contract-review-pro','{"fileIds": [], "skillId": 2, "runtimeSkillName": "contract-review-pro"}',NULL,1,NULL,'[]',NULL,NULL,'pending','你好',1,'2026-03-11 16:30:52','2026-03-11 16:30:52'),(18,6,'你好','contract-review-pro','{"fileIds": [], "skillId": 2, "runtimeSkillName": "contract-review-pro"}',NULL,2,NULL,'[]',NULL,NULL,'pending','你好',1,'2026-03-11 17:14:05','2026-03-11 17:14:05'),(19,6,'你好','contract-review-pro','{"fileIds": [], "skillId": 2, "runtimeSkillName": "contract-review-pro"}',NULL,3,NULL,'[]',NULL,NULL,'pending','你好',1,'2026-03-12 09:21:40','2026-03-12 09:21:40'),(20,6,'你好','contract-review-pro','{"fileIds": [], "skillId": 2, "runtimeSkillName": "contract-review-pro"}',NULL,4,NULL,'[]',NULL,NULL,'pending','你好',1,'2026-03-12 09:29:24','2026-03-12 09:29:24'),(21,6,'你好','contract-review-pro','{"fileIds": [], "skillId": 2, "runtimeSkillName": "contract-review-pro"}','',5,NULL,'[]','5356ms',NULL,'normal','你好',1,'2026-03-12 09:31:19','2026-03-12 09:31:14'),(22,6,'你好','contract-review-pro','{"fileIds": [], "skillId": 2, "runtimeSkillName": "contract-review-pro"}','你好！我是 Contract Review Pro，专业的合同审核助手。\n\n你可以：\n1. **查询某类合同的审核要点**（例如：“买卖合同的审核要点是什么？”）\n2. **上传具体合同文件**（.docx 或 .txt）让我帮你审核\n\n请问有什么可以帮您的吗？',6,NULL,'[]','2935ms',NULL,'normal','你好',1,'2026-03-12 09:52:07','2026-03-12 09:52:04'),(23,6,'帮我审查