INSERT INTO `tool_catalog` (`id`,`tool_name`,`display_name`,`description`,`tool_type`,`bindable`,`owner_skill_name`,`source`,`sort_order`,`created_at`,`updated_at`) VALUES (1,'writeFile','写入文件','将 UTF-8 文本写入本地文件，必要时自动创建目录。','GLOBAL',1,NULL,'runtime',1,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(2,'runPython','执行 Python','执行指定 Python 脚本并返回标准输出。','GLOBAL',1,NULL,'runtime',2,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(3,'readFile','读取文件','读取本地 UTF-8 文本文件内容。','GLOBAL',1,NULL,'runtime',0,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(4,'checkInventory','查询库存','查询指定品类或全部商品的库存、尺码和库存状态。','SKILL_NATIVE',0,'inventory','example',3,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(5,'getPricing','查询定价','查询商品售价、成本价、毛利率和建议价格区间。','SKILL_NATIVE',0,'pricing','example',4,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(6,'generatePurchaseStrategy','生成采购策略','根据预算和优先级生成补货与采购策略建议。','SKILL_NATIVE',0,'purchase','example',5,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(7,'optimizePurchaseOrder','优化采购单','优化采购单数量与成本结构，提升 ROI 和折扣收益。','SKILL_NATIVE',0,'purchase','example',6,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(8,'getSupplierCatalog','供应商目录','查询供应商可售商品、批发价、起订量和供货情况。','SKILL_NATIVE',0,'supplier','example',7,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(9,'getSupplierQuote','获取供应商报价','根据供应商 SKU 和数量生成明细报价与折扣信息。','SKILL_NATIVE',0,'supplier','example',8,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(10,'getPredictedDemand','需求预测','预测未来周期的需求量、建议备货量和风险等级。','SKILL_NATIVE',0,'trend','example',9,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(11,'getSalesTrends','销售趋势分析','查询指定周期内的热销商品、销售速度和市场趋势。','SKILL_NATIVE',0,'trend','example',10,'2026-03-11 16:28:15','2026-03-11 16:28:15'),(12,'getWeather','查询天气','查询指定城市的天气、温度、湿度和风速。','SKILL_NATIVE',0,'weather','example',11,'2026-03-11 16:28:16','2026-03-11 16:28:16');
